INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Bilimsel Düşünme ve Araştırma Metodolojisi' LIMIT 1), 'main_idea', $$Bu metnin ana fikri aşağıdakilerden hangisidir?$$, $json$["Bilimsel araştırma yalnızca laboratuvar ortamında yapılabilir","Bilimsel düşünme; sistematik gözlem, sorgulama ve doğrulamaya dayanan bir süreçtir","Araştırmacılar her zaman önceki bulgulara güvenmek zorundadır","Metodoloji yalnızca sosyal bilimlerde önem taşır"]$json$::jsonb, 1, $$Metin, bilimsel düşünmenin sistematik ve sorgulayıcı doğasını ana eksen olarak ele almaktadır.$$, 4, 1),
((SELECT id FROM text_library WHERE title = 'Bilimsel Düşünme ve Araştırma Metodolojisi' LIMIT 1), 'detail', $$Araştırma metodolojisinde "değişken kontrolü" neden önemlidir?$$, $json$["Deneyin maliyetini düşürmek için","Sonuçların yalnızca hedeflenen etkenden kaynaklandığını güvence altına almak için","Araştırmacının çalışma süresini kısaltmak için","Veri toplamayı kolaylaştırmak için"]$json$::jsonb, 1, $$Değişken kontrolü, gözlemlenen sonucun yalnızca bağımsız değişkenden kaynaklandığını kanıtlamak amacıyla uygulanır.$$, 4, 2),
((SELECT id FROM text_library WHERE title = 'Bilimsel Düşünme ve Araştırma Metodolojisi' LIMIT 1), 'detail', $$Tümevarım ve tümdengelim yöntemleri arasındaki temel fark nedir?$$, $json$["Tümevarım genelden özele, tümdengelim özelden genele gider","Tümevarım özelden genele, tümdengelim genelden özele gider","İkisi de aynı mantık yapısını kullanır","Tümdengelim yalnızca matematik araştırmalarında kullanılır"]$json$::jsonb, 1, $$Tümevarım, gözlemlerden genel ilkelere ulaşırken; tümdengelim, genel ilkelerden özele iner.$$, 4, 3),
((SELECT id FROM text_library WHERE title = 'Bilimsel Düşünme ve Araştırma Metodolojisi' LIMIT 1), 'inference', $$Metne göre, bir hipotezin bilimsel sayılabilmesi için taşıması gereken temel özellik nedir?$$, $json$["Toplumun büyük çoğunluğu tarafından kabul edilmesi","Yanlışlanabilir (falsifiable) olması","Yüzyıllardır değişmeden gelmesi","Yalnızca nicel verilerle desteklenmesi"]$json$::jsonb, 1, $$Bilimsel hipotezler, Popper''ın kriterine göre yanlışlanabilir olmalıdır; aksi hâlde bilimsel sınırın dışında kalır.$$, 4, 4),
((SELECT id FROM text_library WHERE title = 'Bilimsel Düşünme ve Araştırma Metodolojisi' LIMIT 1), 'vocabulary', $$Metinde geçen "replicability" (tekrarlanabilirlik) kavramı hangi anlama gelir?$$, $json$["Deneyin pahalı ekipman gerektirmesi","Araştırma bulgularının başka araştırmacılar tarafından da aynı koşullarda elde edilebilmesi","Sonuçların yalnızca özgün araştırmacı tarafından doğrulanması","Veri setinin büyük olması"]$json$::jsonb, 1, $$Tekrarlanabilirlik, bilimin temel ilkelerinden biridir; başka araştırmacıların aynı koşullarda aynı sonuçlara ulaşabilmesini ifade eder.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Küresel İklim Değişikliği' LIMIT 1), 'main_idea', $$Bu metnin ana teması aşağıdakilerden hangisidir?$$, $json$["İklim değişikliği yalnızca gelişmekte olan ülkeleri etkiler","Küresel ısınma insan faaliyetleriyle bağlantılıdır ve çok boyutlu sonuçlar doğurmaktadır","Sanayi devrimi iklim üzerinde olumlu etkiler yaratmıştır","İklim değişikliği kısa vadede çözülebilecek bir sorundur"]$json$::jsonb, 1, $$Metin, iklim değişikliğinin insan kaynaklı olduğunu ve geniş çaplı sonuçlar doğurduğunu ana eksen olarak ele almaktadır.$$, 4, 1),
((SELECT id FROM text_library WHERE title = 'Küresel İklim Değişikliği' LIMIT 1), 'detail', $$Sera etkisinin artmasına en çok katkıda bulunan gaz hangisidir?$$, $json$["Oksijen (O₂)","Karbondioksit (CO₂)","Azot (N₂)","Argon (Ar)"]$json$::jsonb, 1, $$Karbondioksit, fosil yakıt kullanımı ve ormansızlaşma nedeniyle atmosferde biriken ve sera etkisini güçlendiren başlıca gazdır.$$, 4, 2),
((SELECT id FROM text_library WHERE title = 'Küresel İklim Değişikliği' LIMIT 1), 'detail', $$Paris Anlaşması''nın temel hedefi nedir?$$, $json$["Küresel ortalama sıcaklık artışını sanayi öncesi döneme göre 2°C ile sınırlandırmak","Nükleer enerjiyi tamamen yasaklamak","Gelişmekte olan ülkelere teknoloji transferini durdurmak","Karbon vergisini uluslararası düzeyde standartlaştırmak"]$json$::jsonb, 0, $$Paris Anlaşması, küresel ısınmayı 1,5–2°C ile sınırlama hedefiyle 2015 yılında imzalanmıştır.$$, 4, 3),
((SELECT id FROM text_library WHERE title = 'Küresel İklim Değişikliği' LIMIT 1), 'inference', $$Metinden çıkarılabilecek en güçlü sonuç hangisidir?$$, $json$["İklim değişikliği sorununu tek bir ülke kendi başına çözebilir","Ormansızlaşmanın iklim üzerinde etkisi yoktur","İklim değişikliğiyle mücadele uluslararası iş birliği gerektirmektedir","Yenilenebilir enerji kaynakları ekonomik açıdan dezavantajlıdır"]$json$::jsonb, 2, $$Küresel ölçekli bir sorun olan iklim değişikliği, ülkelerin ortak hareket etmesini zorunlu kılmaktadır.$$, 4, 4),
((SELECT id FROM text_library WHERE title = 'Küresel İklim Değişikliği' LIMIT 1), 'vocabulary', $$Metinde kullanılan "iklim geri bildirimi (climate feedback)" terimi ne anlama gelmektedir?$$, $json$["Hükümetlerin iklim politikalarına verdiği yanıtlar","İklim sistemindeki bir değişikliğin kendini güçlendiren ya da zayıflatan döngüsel süreçler oluşturması","Meteoroloji tahminlerinin medyada yayılması","Okyanusların güneş ışınımını yansıtma oranı"]$json$::jsonb, 1, $$İklim geri bildirimi, bir değişikliğin sistemi aynı yönde (pozitif) ya da zıt yönde (negatif) etkileyen döngüler oluşturmasıdır.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Dil Edinimi ve Evrimsel Kökenler' LIMIT 1), 'main_idea', $$Bu metnin temel iddiası aşağıdakilerden hangisidir?$$, $json$["Dil edinimi tamamen sosyal öğrenmeyle gerçekleşir","Dil yetisi; evrimsel, nörolojik ve sosyal boyutları olan karmaşık bir insan özelliğidir","Hayvanlar da insan diliyle aynı yapıda iletişim kurar","Dil yetisi yalnızca sol beyin yarıküresinde bulunur"]$json$::jsonb, 1, $$Metin, dil ediniminin evrimsel kökenleri ve nörolojik temelleri birlikte ele alarak çok boyutlu doğasını ortaya koymaktadır.$$, 4, 1),
((SELECT id FROM text_library WHERE title = 'Dil Edinimi ve Evrimsel Kökenler' LIMIT 1), 'detail', $$Chomsky''nin "Evrensel Dilbilgisi" teorisi neyi savunmaktadır?$$, $json$["Her dil farklı beyin bölgeleri tarafından işlenir","İnsanlar doğuştan dil öğrenmeye uygun bir zihinsel altyapıyla gelir","Dil yalnızca kültürel aktarımla öğrenilir","Sözdizimi kuralları dilden dile büyük farklılıklar gösterir"]$json$::jsonb, 1, $$Chomsky''ye göre insanlar, dilden bağımsız evrensel dilbilgisel ilkeleri içselleştirmeye yatkın doğuştan bir mekanizmayla donanmıştır.$$, 4, 2),
((SELECT id FROM text_library WHERE title = 'Dil Edinimi ve Evrimsel Kökenler' LIMIT 1), 'detail', $$Broca ve Wernicke bölgelerinin dil işleme sürecindeki rolleri nasıl ayrışır?$$, $json$["Broca bölgesi anlama, Wernicke bölgesi üretimle ilgilidir","Broca bölgesi konuşma üretimi, Wernicke bölgesi dil anlama ile ilgilidir","İkisi de yalnızca yazılı dili işler","Her iki bölge de yalnızca sağ yarıkürede yer alır"]$json$::jsonb, 1, $$Broca bölgesi konuşma ve dil üretimini, Wernicke bölgesi ise dili anlamayı yönetir.$$, 4, 3),
((SELECT id FROM text_library WHERE title = 'Dil Edinimi ve Evrimsel Kökenler' LIMIT 1), 'inference', $$"Kritik dönem hipotezi" bağlamında aşağıdaki çıkarım hangisi en doğrudur?$$, $json$["Dil edinimi yetişkinlikte daha kolaydır","Erken çocukluk döneminde dil maruziyeti, ana dil yeterliliği için kritik öneme sahiptir","Dil öğrenmek için biyolojik bir hazırbulunuşluk gerekmez","Kritik dönem kavramı yalnızca yabancı dil öğrenimiyle ilgilidir"]$json$::jsonb, 1, $$Kritik dönem hipotezine göre, ilk yıllarda dile yeterince maruz kalınmayan çocuklar ana dillerini tam yetkinlikte edinemez.$$, 4, 4),
((SELECT id FROM text_library WHERE title = 'Dil Edinimi ve Evrimsel Kökenler' LIMIT 1), 'vocabulary', $$Metinde geçen "özyineleme (recursion)" özelliği dil için neden önemlidir?$$, $json$["Kelimelerin birden fazla anlamda kullanılmasını sağlar","Cümlelerin sonsuz sayıda iç içe geçmiş yapılar oluşturabilmesine olanak tanır","Söz varlığının nesilden nesile aktarılmasını kolaylaştırır","Farklı dillerin ortak kökenini kanıtlar"]$json$::jsonb, 1, $$Özyineleme sayesinde sonlu sayıda kelimeyle sonsuz sayıda anlamlı cümle üretilebilir; bu, dilin en temel üretken özelliğidir.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Ekonomik Büyüme Teorileri' LIMIT 1), 'main_idea', $$Bu metnin temel odak noktası nedir?$$, $json$["Enflasyonun döviz kuru üzerindeki etkileri","Ekonomik büyümeyi açıklayan farklı teorik yaklaşımlar ve bunların politika çıkarımları","Merkez bankalarının para politikası araçları","Uluslararası ticaretin gelir dağılımına etkisi"]$json$::jsonb, 1, $$Metin, Solow modelinden içsel büyüme teorilerine uzanan farklı yaklaşımları karşılaştırmaktadır.$$, 4, 1),
((SELECT id FROM text_library WHERE title = 'Ekonomik Büyüme Teorileri' LIMIT 1), 'detail', $$Solow büyüme modelinde uzun dönem büyümeyi belirleyen temel etken nedir?$$, $json$["Sermaye birikimi","Teknolojik ilerleme (toplam faktör verimliliği)","İşgücü artış hızı","Hükümet harcamaları"]$json$::jsonb, 1, $$Solow modeline göre uzun dönemde büyüme yalnızca dışsal kabul edilen teknolojik ilerlemeyle sürdürülebilir; sermaye birikimi azalan getiriler nedeniyle dengeye ulaşır.$$, 4, 2),
((SELECT id FROM text_library WHERE title = 'Ekonomik Büyüme Teorileri' LIMIT 1), 'detail', $$İçsel büyüme teorisi (endogenous growth theory) Solow modelinden nasıl ayrılır?$$, $json$["Teknolojik ilerlemeyi modelin dışında tutar","Teknoloji ve yeniliği modelin içinde, beşeri sermaye yatırımlarının çıktısı olarak açıklar","Devlet müdahalesini büyümenin önündeki en büyük engel olarak görür","Büyümenin yalnızca tarım sektörüne bağlı olduğunu savunur"]$json$::jsonb, 1, $$İçsel büyüme teorisi, AR-GE ve eğitim yatırımları yoluyla teknolojik ilerlemenin modelin içinde üretildiğini öne sürer.$$, 4, 3),
((SELECT id FROM text_library WHERE title = 'Ekonomik Büyüme Teorileri' LIMIT 1), 'inference', $$Metindeki argümanlardan çıkarılabilecek en makul politika önerisi hangisidir?$$, $json$["Eğitim ve AR-GE harcamalarını kısmak uzun vadeli büyümeyi artırır","Beşeri sermayeye ve yeniliğe yapılan yatırımlar sürdürülebilir büyümenin anahtarıdır","Büyüme için tek gereken sermaye ithalatıdır","Nüfus artışını durdurmak büyümenin önündeki tek engeldir"]$json$::jsonb, 1, $$İçsel büyüme modelleri, uzun vadeli büyüme için eğitim, sağlık ve yeniliğe yapılan yatırımların kritik olduğunu ima eder.$$, 4, 4),
((SELECT id FROM text_library WHERE title = 'Ekonomik Büyüme Teorileri' LIMIT 1), 'vocabulary', $$Metinde kullanılan "yakınsama hipotezi (convergence hypothesis)" ne anlama gelir?$$, $json$["Zengin ülkelerin daha hızlı büyüyeceği öngörüsü","Fakir ülkelerin, koşulları eşit tutulduğunda zengin ülkelere göre daha hızlı büyüyeceği ve aralarındaki farkın kapanacağı beklentisi","Gelişmekte olan ülkelerin büyüme potansiyelinin olmadığı görüşü","Ülkelerin büyüme hızının nüfus yoğunluğuyla doğru orantılı olması"]$json$::jsonb, 1, $$Yakınsama hipotezi, düşük gelirli ülkelerin azalan getiriler nedeniyle daha yüksek büyüme hızı yakalamasını ve sonunda zengin ülkelere yakınsamasını bekler.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Felsefede Bilgi Kuramı (Epistemoloji)' LIMIT 1), 'main_idea', $$Bu metnin temel sorusu nedir?$$, $json$["Ahlaki değerler nasıl belirlenir?","Bilginin kaynağı, sınırları ve güvenilirliği nedir?","Güzel olan nedir ve nasıl tanımlanır?","Devletin meşruiyet temeli ne olmalıdır?"]$json$::jsonb, 1, $$Epistemoloji; bilginin ne olduğu, nasıl elde edildiği ve hangi ölçütlere göre doğrulandığı sorularını ele alır.$$, 4, 1),
((SELECT id FROM text_library WHERE title = 'Felsefede Bilgi Kuramı (Epistemoloji)' LIMIT 1), 'detail', $$Descartes''ın "Cogito, ergo sum" (Düşünüyorum, öyleyse varım) ifadesi hangi epistemolojik problemi çözmeye çalışır?$$, $json$["Tanrının varlığını kanıtlamak","Şüphe edilemeyen temel bir kesin bilgiye ulaşmak","Algıların gerçekliği yansıttığını ispatlamak","Duyular aracılığıyla edinilen bilginin üstünlüğünü savunmak"]$json$::jsonb, 1, $$Descartes, radikal şüphecilik yöntemiyle tüm bilgileri sorgulayarak şüphe edilemeyen tek kesinliği—kendi düşünme eylemini—bulmuştur.$$, 4, 2),
((SELECT id FROM text_library WHERE title = 'Felsefede Bilgi Kuramı (Epistemoloji)' LIMIT 1), 'detail', $$Ampirizm ile rasyonalizm arasındaki temel ayrım nedir?$$, $json$["Ampirizm dini bilgiyi, rasyonalizm bilimsel bilgiyi savunur","Ampirizm bilginin kaynağını duyusal deneyimde, rasyonalizm ise aklın a priori ilkelerinde bulur","İkisi de bilginin yalnızca matematikten elde edildiğini savunur","Rasyonalizm belirsizliği, ampirizm ise kesinliği öne çıkarır"]$json$::jsonb, 1, $$Ampiristler (Locke, Hume) bilginin duyumlardan geldiğini; rasyonalistler (Descartes, Leibniz) aklın doğuştan ilkeler taşıdığını savunur.$$, 4, 3),
((SELECT id FROM text_library WHERE title = 'Felsefede Bilgi Kuramı (Epistemoloji)' LIMIT 1), 'inference', $$Kant''ın "sentetik a priori" kavramı hangi epistemolojik sonucu doğurur?$$, $json$["Tüm bilgi tamamen deneyimden türer","Aklın deneyimden bağımsız, ancak dünyayı anlamamızı sağlayan bilgi biçimleri vardır","Matematiksel önermelerin deneyimle doğrulanması gerekir","Metafizik sorunlar bilimsel yöntemle çözülebilir"]$json$::jsonb, 1, $$Kant, deneyimden bağımsız (a priori) ama dünyayı açıklayan (sentetik) bilgi kategorilerinin var olduğunu öne sürerek ampirizm-rasyonalizm çatışmasını aşmaya çalışmıştır.$$, 4, 4),
((SELECT id FROM text_library WHERE title = 'Felsefede Bilgi Kuramı (Epistemoloji)' LIMIT 1), 'vocabulary', $$Metinde geçen "episteme" kavramı ne anlama gelir?$$, $json$["Kişisel kanı ve inanç","Kanıtlanmış, doğrulanmış gerçek bilgi","Toplumsal uzlaşıyla oluşan ortak değerler","Dini inanç sistemleri"]$json$::jsonb, 1, $$Antik Yunan''da "episteme", sanı (doxa) ile karşıtlık içinde kanıtlanmış ve gerekçelendirilmiş gerçek bilgiyi ifade eder.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'İstatistiksel Analizde Temel Kavramlar' LIMIT 1), 'main_idea', $$Bu metnin temel amacı nedir?$$, $json$["Yalnızca frekans tablolarını açıklamak","İstatistiksel analizin temel kavramlarını ve araştırmalardaki işlevini ortaya koymak","Matematiksel kanıtlama yöntemlerini tanıtmak","Bilgisayar destekli veri işlemeyi anlatmak"]$json$::jsonb, 1, $$Metin; merkezi eğilim, dağılım ve hipotez testi gibi temel istatistiksel kavramları araştırma süreçleriyle ilişkilendirerek sunmaktadır.$$, 4, 1),
((SELECT id FROM text_library WHERE title = 'İstatistiksel Analizde Temel Kavramlar' LIMIT 1), 'detail', $$Standart sapma hangi bilgiyi vermektedir?$$, $json$["Veri setindeki en yüksek değeri","Verilerin ortalama etrafında ne kadar yayıldığını","Veri setinin ortanca değerini","Örneklemin evrenle ne kadar örtüştüğünü"]$json$::jsonb, 1, $$Standart sapma, gözlemlerin ortalamadan ne kadar uzaklaştığını ölçen ve dağılımın yayılımını gösteren bir istatistiktir.$$, 4, 2),
((SELECT id FROM text_library WHERE title = 'İstatistiksel Analizde Temel Kavramlar' LIMIT 1), 'detail', $$"p-değeri < 0.05" ifadesi araştırmacıya ne söyler?$$, $json$["Bulgu kesinlikle doğrudur","Gözlemlenen sonucun yalnızca şansa bağlı olma olasılığı %5''ten düşüktür, yani sonuç istatistiksel olarak anlamlıdır","Örneklem boyutu yetersizdir","Veri toplama süreci hatalıdır"]$json$::jsonb, 1, $$p < 0.05 eşiği, null hipotezin doğru olması durumunda elde edilen sonucun %5''ten düşük ihtimalle ortaya çıkacağını gösterir; araştırmacı null hipotezi reddeder.$$, 4, 3),
((SELECT id FROM text_library WHERE title = 'İstatistiksel Analizde Temel Kavramlar' LIMIT 1), 'inference', $$Bir araştırmada örneklem büyüklüğünün artırılmasının istatistiksel sonuçlara etkisi ne olur?$$, $json$["Standart hata artar ve bulgular daha az güvenilir hâle gelir","Standart hata azalır, güven aralıkları daralır ve bulgular daha güvenilir olur","Ortalama değer değişir","p-değeri otomatik olarak sıfıra düşer"]$json$::jsonb, 1, $$Büyük örneklemler örnekleme hatasını azaltır; bu da tahminlerin daha hassas ve genellenebilir olmasını sağlar.$$, 4, 4),
((SELECT id FROM text_library WHERE title = 'İstatistiksel Analizde Temel Kavramlar' LIMIT 1), 'vocabulary', $$Metinde geçen "korelasyon katsayısı" hangi ilişkiyi ölçer?$$, $json$["İki değişken arasındaki nedensellik ilişkisini","İki değişken arasındaki doğrusal ilişkinin yönünü ve gücünü","Bir değişkenin zaman içindeki değişim hızını","Örneklemin evreni temsil etme oranını"]$json$::jsonb, 1, $$Korelasyon katsayısı (r) iki değişkenin birlikte nasıl değiştiğini gösterir; ancak nedensellik değil, ilişki gücü hakkında bilgi verir.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Nörobilim ve Bilinç' LIMIT 1), 'main_idea', $$Bu metnin ana sorusu aşağıdakilerden hangisidir?$$, $json$["Beyin hasarı sonrası iyileşme süreci nasıl gerçekleşir?","Bilinç nedir ve nörobiyolojik temelleri nelerdir?","Sinir sisteminin evrimsel gelişimi nasıl olmuştur?","Psikiyatrik ilaçlar nöronal aktiviteyi nasıl etkiler?"]$json$::jsonb, 1, $$Metin, bilincin tanımı, ölçülmesi ve nöral korelatları üzerine odaklanmaktadır.$$, 4, 1),
((SELECT id FROM text_library WHERE title = 'Nörobilim ve Bilinç' LIMIT 1), 'detail', $$"Zor bilinç problemi" (hard problem of consciousness) neyi ifade eder?$$, $json$["Beyin görüntülemenin teknik güçlüklerini","Öznel deneyimin (qualia) neden fiziksel beyin süreçlerinden ortaya çıktığını açıklamanın zorluğunu","Bilinç bozukluklarının tedavisindeki tıbbi güçlükleri","Farklı bilinç düzeylerinin ölçülmesini"]$json$::jsonb, 1, $$David Chalmers''ın tanımladığı "zor problem", öznel deneyimin neden fiziksel süreçlerden doğduğunu açıklamanın neden bu kadar güç olduğunu sorgular.$$, 4, 2),
((SELECT id FROM text_library WHERE title = 'Nörobilim ve Bilinç' LIMIT 1), 'detail', $$Nöral korelat (NCC) kavramı hangi bağlamda kullanılmaktadır?$$, $json$["Reflekslerin omurilikte işlenme sürecini açıklamak için","Belirli bir bilinçli deneyimle eş zamanlı gerçekleşen minimum beyin aktivitesini tanımlamak için","Uyku evreleri arasındaki geçişleri tanımlamak için","Hafıza konsolidasyonunda hipokampusun rolünü belirtmek için"]$json$::jsonb, 1, $$NCC, belirli bir bilinç içeriğiyle birlikte gerçekleşen, o içeriğin doğrudan nöral taşıyıcısı olan minimum beyin süreçlerini ifade eder.$$, 4, 3),
((SELECT id FROM text_library WHERE title = 'Nörobilim ve Bilinç' LIMIT 1), 'inference', $$Metinden çıkarılabilecek en uygun sonuç hangisidir?$$, $json$["Bilinç tamamen nörobilim tarafından açıklanmış durumdadır","Bilinç sorunu hem felsefi hem de ampirik araştırmaları gerektiren çok disiplinli bir alan olmayı sürdürmektedir","Yapay zeka sistemleri tam anlamıyla bilinçlidir","Bilinç yalnızca uyku sırasında aktiftir"]$json$::jsonb, 1, $$Bilinç, salt nörobilimle açıklanamayan felsefi boyutlar taşır; bu nedenle disiplinler arası araştırma zorunludur.$$, 4, 4),
((SELECT id FROM text_library WHERE title = 'Nörobilim ve Bilinç' LIMIT 1), 'vocabulary', $$Metinde geçen "qualia" kavramı ne anlama gelir?$$, $json$["Nöronlar arasındaki elektrokimyasal sinyaller","Bir deneyimin öznel, birinci-şahıs perspektifinden nasıl hissettirdiğinin nitelikleri","Beyin loblarını birbirine bağlayan sinir lifleri","Bilinçdışı otomatik davranış kalıpları"]$json$::jsonb, 1, $$Qualia, kırmızının nasıl göründüğü ya da acının nasıl hissettirdiği gibi deneyimin öznel niteliksel boyutunu ifade eder.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Psikolojide Bilişsel Süreçler' LIMIT 1), 'main_idea', $$Bu metnin temel odağı nedir?$$, $json$["Davranışçı psikolojinin temel ilkeleri","İnsan zihninin bilgiyi nasıl aldığını, depoladığını ve kullandığını inceleyen bilişsel süreçler","Bilinçdışı motivasyonların davranış üzerindeki etkisi","Sosyal çevrenin kişilik gelişimine katkısı"]$json$::jsonb, 1, $$Metin; dikkat, bellek, algı ve problem çözme gibi bilişsel süreçleri incelemektedir.$$, 4, 1),
((SELECT id FROM text_library WHERE title = 'Psikolojide Bilişsel Süreçler' LIMIT 1), 'detail', $$Çalışma belleği (working memory) modelinde hangi bileşen sözel bilgiyi geçici olarak depolar?$$, $json$["Görsel-uzamsal not defteri","Merkezi yönetici","Ses döngüsü (phonological loop)","Epizodik tampon"]$json$::jsonb, 2, $$Baddeley modelinde ses döngüsü, sözel ve işitsel bilgiyi geçici olarak tutan alt sistemdir.$$, 4, 2),
((SELECT id FROM text_library WHERE title = 'Psikolojide Bilişsel Süreçler' LIMIT 1), 'detail', $$Bilişsel önyargılar (cognitive biases) karar verme süreçlerini nasıl etkiler?$$, $json$["Her zaman daha iyi kararlar alınmasını sağlar","Sistematik hatalar yaratarak mantıksal akıl yürütmeden sapmalara yol açar","Yaratıcılığı artırır","Yalnızca stres altında ortaya çıkar"]$json$::jsonb, 1, $$Bilişsel önyargılar; onay önyargısı, erişilebilirlik sezgisi gibi yollarla bireylerin tutarsız ve hatalı kararlar almasına neden olur.$$, 4, 3),
((SELECT id FROM text_library WHERE title = 'Psikolojide Bilişsel Süreçler' LIMIT 1), 'inference', $$Biliş araştırmalarının eğitime yönelik en önemli çıkarımı nedir?$$, $json$["Öğrenciler yalnızca pasif dinleyerek en iyi öğrenir","Geri çağırma pratiği ve aralıklı tekrar gibi yöntemler bilgiyi kalıcı hâle getirmek için etkilidir","Sınav kaygısı öğrenme performansını her zaman olumlu etkiler","Öğrenme hızı yalnızca genetikle belirlenir"]$json$::jsonb, 1, $$Bilişsel psikoloji araştırmaları, aktif geri çağırma (retrieval practice) ve dağıtılmış tekrarın uzun süreli öğrenmeye en fazla katkı sağladığını göstermektedir.$$, 4, 4),
((SELECT id FROM text_library WHERE title = 'Psikolojide Bilişsel Süreçler' LIMIT 1), 'vocabulary', $$Metinde geçen "şema (schema)" kavramı bilişsel psikolojide ne anlama gelir?$$, $json$["Beynin anatomik bölümlerini gösteren bir diyagram","Yeni bilgilerin yorumlanmasında kullanılan önceden oluşturulmuş zihinsel çerçeve ya da bilgi yapısı","Nöronlar arasındaki sinaptik bağlantı","Belirli bir uyarıcıya verilen koşullu tepki"]$json$::jsonb, 1, $$Şemalar, geçmiş deneyimlerden oluşturulmuş zihinsel yapılardır; yeni bilgiyi anlamlandırmak ve yorumlamak için kullanılır.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Sosyolojide Kimlik ve Kültür' LIMIT 1), 'main_idea', $$Bu metnin temel argümanı aşağıdakilerden hangisidir?$$, $json$["Kimlik doğuştan sabit ve değişmezdir","Kimlik; sosyal, kültürel ve tarihsel bağlamların ürünüdür ve dinamik biçimde şekillenir","Kültür yalnızca sanat ve müzik aracılığıyla aktarılır","Sosyoloji kimlik sorunlarını açıklamada yetersiz kalır"]$json$::jsonb, 1, $$Metin; kimliğin toplumsal ilişkiler, kültürel normlar ve iktidar yapıları içinde inşa edildiğini savunmaktadır.$$, 4, 1),
((SELECT id FROM text_library WHERE title = 'Sosyolojide Kimlik ve Kültür' LIMIT 1), 'detail', $$Goffman''ın "dramaturji" yaklaşımına göre bireyler sosyal hayatta ne yapar?$$, $json$["Biyolojik içgüdülerine göre hareket eder","Farklı durumlarda farklı izlenimler oluşturmak için roller sergiler (sosyal performans)","Her zaman bilinçaltı dürtüleriyle hareket eder","Yalnızca ekonomik çıkarlarını maksimize etmeye çalışır"]$json$::jsonb, 1, $$Goffman''a göre sosyal hayat bir tiyatro sahnesi gibidir; bireyler farklı izlenimler yaratmak için roller üstlenir ve kimliklerini duruma göre yönetir.$$, 4, 2),
((SELECT id FROM text_library WHERE title = 'Sosyolojide Kimlik ve Kültür' LIMIT 1), 'detail', $$"Kültürel asimilasyon" ve "kültürel çoğulculuk" kavramları arasındaki fark nedir?$$, $json$["İkisi de azınlık kültürlerinin baskın kültürle bütünleşmesini öngörür","Asimilasyon azınlık kimliklerinin baskın kültürde erimesini, çoğulculuk farklı kültürlerin bir arada yaşamasını ifade eder","Çoğulculuk ayrımcılığı meşrulaştırır","Asimilasyon yalnızca göç bağlamında geçerlidir"]$json$::jsonb, 1, $$Asimilasyon, azınlık grupların baskın kültürü benimseyip kendi kimliklerini yitirmesini; çoğulculuk ise farklılıkların korunarak bir arada yaşamasını ifade eder.$$, 4, 3),
((SELECT id FROM text_library WHERE title = 'Sosyolojide Kimlik ve Kültür' LIMIT 1), 'inference', $$Kimlik politikaları bağlamında, kimlik mücadelelerinin neden günümüzde bu kadar ön plana çıktığı çıkarımı nasıl yapılabilir?$$, $json$["Ekonomik kalkınma kimlik meselesini önemsiz kılmıştır","Küreselleşme ve teknolojinin geleneksel kimlikleri tehdit etmesiyle birlikte kimlik savunusu güçlenmiştir","Kimlik sorunları yalnızca azgelişmiş toplumlarda ortaya çıkar","Kimlik tartışmaları medyanın abartmasının ürünüdür"]$json$::jsonb, 1, $$Küreselleşme, yerelliği tehdit etmekte; bu da toplulukları kültürel kimliklerini koruma ve yeniden üretme konusunda daha güçlü tutumlar almaya itmektedir.$$, 4, 4),
((SELECT id FROM text_library WHERE title = 'Sosyolojide Kimlik ve Kültür' LIMIT 1), 'vocabulary', $$Metinde geçen "habitus" kavramı Bourdieu''ya göre ne anlama gelir?$$, $json$["Bireyin gelir düzeyi ve ekonomik sermayesi","Bireyin sosyal çevresinde kazandığı, davranış eğilimlerini yönlendiren içselleştirilmiş şemalar ve pratikler","Toplumsal normların yazılı hâle getirilmesi","Kültürel ürünlerin piyasa değeri"]$json$::jsonb, 1, $$Bourdieu''nun habitus kavramı; sosyalleşme süreci içinde bireyin kazandığı, algı, düşünce ve eylemleri yönlendiren kalıcı eğilimler sistemidir.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Yapay Zeka ve Etik Sorunlar' LIMIT 1), 'main_idea', $$Bu metnin temel kaygısı nedir?$$, $json$["Yapay zeka algoritmalarının teknik mimarisi","YZ sistemlerinin toplumsal, ahlaki ve hukuki boyutlarda yarattığı etik sorunlar","YZ''nin üretim maliyetleri ve pazar değeri","Yapay zekanın yalnızca olumlu toplumsal katkıları"]$json$::jsonb, 1, $$Metin; önyargı, hesap verebilirlik, mahremiyet ve özerklik gibi YZ''nin beraberinde getirdiği etik sorunları merkeze almaktadır.$$, 4, 1),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka ve Etik Sorunlar' LIMIT 1), 'detail', $$YZ sistemlerinde "algoritma önyargısı" nasıl ortaya çıkar?$$, $json$["Bilgisayarların hesaplama hataları yapması nedeniyle","Eğitim verilerindeki mevcut sosyal önyargıların modele yansıması sonucunda","Yazılımcıların kasıtlı olarak ayrımcı kod yazmasıyla","Donanım yetersizlikleri nedeniyle"]$json$::jsonb, 1, $$YZ modelleri, önyargılı toplumsal verileri öğrendiğinde bu önyargıları sistematik biçimde yeniden üretir; cinsiyet ve ırk önyargısı bunun tipik örnekleridir.$$, 4, 2),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka ve Etik Sorunlar' LIMIT 1), 'detail', $$"Açıklanabilir YZ" (Explainable AI) kavramı neden önem kazanmaktadır?$$, $json$["YZ sistemlerini daha hızlı çalıştırmak için","Karar süreçleri anlaşılamayan kara kutu sistemlerin hesap verebilirlik sorununu çözmek için","YZ''nin enerji tüketimini azaltmak için","YZ modellerinin telif haklarını korumak için"]$json$::jsonb, 1, $$Kara kutu YZ sistemleri karar gerekçelerini açıklayamaz; bu durum hukuki, tıbbi ve adli alanlarda hesap verebilirlik ve güven sorunlarına yol açmaktadır.$$, 4, 3),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka ve Etik Sorunlar' LIMIT 1), 'inference', $$Metinden çıkarılabilecek en uygun politika önerisi hangisidir?$$, $json$["YZ geliştirme faaliyetleri tamamen durdurulmalıdır","YZ sistemleri için şeffaflık, hesap verebilirlik ve insan gözetimini esas alan düzenleyici çerçeveler oluşturulmalıdır","YZ kararlarına itiraz hakkı kaldırılmalıdır","YZ etik sorunları teknik düzenlemelerle değil, yalnızca piyasa güçleriyle çözülmelidir"]$json$::jsonb, 1, $$YZ''nin toplumsal riskleri, hesap verebilir ve şeffaf bir regülasyon çerçevesini zorunlu kılmaktadır.$$, 4, 4),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka ve Etik Sorunlar' LIMIT 1), 'vocabulary', $$Metinde geçen "otomasyon paradoksu" ne anlama gelir?$$, $json$["YZ''nin insanları her zaman daha güvenli kararlar almaya yönlendirmesi","Sistemlerin otomasyona daha fazla güvendikçe insanların manuel becerileri kaybedip bir hata anında doğru müdahaleyi yapamaması riski","YZ sistemlerinin ekonomik verimliliği artırırken istihdamı da artırması","Otomasyon maliyetlerinin üretim faydalarını aşması"]$json$::jsonb, 1, $$Otomasyon paradoksu; yüksek otomasyon ortamlarında insan operatörlerin becerilerini yitirdiğini ve sistem arızalanınca uygun tepkiyi vermekte güçlük çektiğini anlatır.$$, 4, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Kuantum Fiziğinin Sırları' LIMIT 1), 'main_idea', $$Bu metnin ana konusu nedir?$$, $json$["Klasik fiziğin temel yasaları","Kuantum mekaniğinin sırları ve günlük yaşama etkileri","Görelilik teorisinin matematiksel temelleri","Büyük Patlama''nın evreni nasıl şekillendirdiği"]$json$::jsonb, 1, $$Metin, kuantum fiziğinin temel ilkelerini ve bu ilkelerin gerçeklik algımızı nasıl dönüştürdüğünü ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Kuantum Fiziğinin Sırları' LIMIT 1), 'detail', $$Işığın hem dalga hem de tanecik özelliği göstermesi hangi kavramla ifade edilir?$$, $json$["Termal radyasyon","Dalga-parçacık ikiliği","Fotoelektrik etki","Sürperpozisyon ilkesi"]$json$::jsonb, 1, $$Dalga-parçacık ikiliği, ışığın ve maddenin koşullara bağlı olarak hem dalga hem de parçacık davranışı sergilemesini tanımlar.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Kuantum Fiziğinin Sırları' LIMIT 1), 'detail', $$Heisenberg''in belirsizlik ilkesi neyi öngörür?$$, $json$["Elektronlar asla ölçülemez","Bir parçacığın konumu ve momentumu aynı anda tam olarak bilinemez","Tüm fiziğin istatistiksel temeli yoktur","Kuantum hesaplamalar her zaman hatalıdır"]$json$::jsonb, 1, $$Belirsizlik ilkesi, bir parçacığın konum ve momentum gibi eşlenik büyüklüklerinin ne kadar hassas ölçüldüğü arasında zorunlu bir ters orantı bulunduğunu belirtir.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Kuantum Fiziğinin Sırları' LIMIT 1), 'inference', $$Kuantum süperpozisyonu bilgisayar teknolojisi için neden önemlidir?$$, $json$["Klasik bilgisayarlara göre daha ucuz üretim sağlar","Kuantum bilgisayarların birden fazla durumu aynı anda işleyerek bazı problemleri çok daha hızlı çözmesini mümkün kılar","Elektronik devrelerin daha küçük tasarlanmasını sağlar","Veri depolama kapasitesini sıfıra düşürür"]$json$::jsonb, 1, $$Süperpozisyon, kuantum bitlerinin (qubit) 0 ve 1''i aynı anda temsil etmesine olanak tanır; bu da bazı hesaplama problemlerinde üstel hız kazanımı sağlar.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Kuantum Fiziğinin Sırları' LIMIT 1), 'vocabulary', $$Metinde geçen "kuantum dolanıklığı (entanglement)" ne anlama gelir?$$, $json$["Parçacıkların fiziksel olarak birbirine yapışması","İki parçacığın aralarındaki mesafeden bağımsız olarak anlık biçimde ilişkili durum göstermesi","Elektronların çekirdeğe yaklaşması","Işığın kırılma indisi"]$json$::jsonb, 1, $$Kuantum dolanıklığında iki parçacık, ne kadar uzakta olursa olsun birinin ölçülmesi anında diğerini etkiler; Einstein bunu "uzak mesafedeki ürkütücü eylem" olarak tanımlamıştır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Yeşil Enerji ve Sürdürülebilir Gelecek' LIMIT 1), 'main_idea', $$Bu metnin temel mesajı nedir?$$, $json$["Fosil yakıtlar yakın gelecekte tükenecektir","Yenilenebilir enerji kaynakları sürdürülebilir bir gelecek için vazgeçilmezdir","Nükleer enerji tek güvenilir alternatiftir","Enerji dönüşümü ekonomik açıdan imkânsızdır"]$json$::jsonb, 1, $$Metin, güneş, rüzgâr gibi yenilenebilir kaynakların iklim değişikliği ve enerji güvenliği sorunlarına çözüm olduğunu ortaya koymaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Yeşil Enerji ve Sürdürülebilir Gelecek' LIMIT 1), 'detail', $$Güneş enerjisinin fosil yakıtlara göre en önemli avantajı nedir?$$, $json$["Güneş enerjisi gece de üretilebilir","Sonsuz ve temiz bir kaynak olup kullanıldıkça tükenmez ve karbon emisyonu üretmez","Kurulum maliyeti sıfırdır","Güneş panelleri 100 yıl boyunca bakım gerektirmez"]$json$::jsonb, 1, $$Güneş enerjisi; yenilenebilir, emisyonsuz ve teorik olarak sonsuz bir kaynak olduğundan fosil yakıtların çevresel zararlarını ortadan kaldırır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Yeşil Enerji ve Sürdürülebilir Gelecek' LIMIT 1), 'detail', $$Enerji depolama teknolojileri yeşil enerjide neden kritik öneme sahiptir?$$, $json$["Güneş ve rüzgâr enerjisi sürekli ve öngörülebilir üretim sağlar","Güneş ve rüzgâr gibi kaynakların kesintili doğasını dengelemek ve enerjiyi talep anında kullanılabilir kılmak için","Enerji depolama maliyeti sıfıra indirilmiştir","Fosil yakıt santrallerinin çalışmasını kolaylaştırır"]$json$::jsonb, 1, $$Yenilenebilir kaynaklar kesintili (intermittent) olduğu için, güneş parlamadığı ya da rüzgâr esmediği zamanlarda enerji sağlamak için depolama zorunludur.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Yeşil Enerji ve Sürdürülebilir Gelecek' LIMIT 1), 'inference', $$Yenilenebilir enerjiye geçişin ekonomik açıdan en önemli sonucu ne olur?$$, $json$["Enerji maliyetleri kısa vadede sıfıra düşer","Uzun vadede enerji maliyetleri düşerken ithalat bağımlılığı azalır ve yeni istihdam alanları oluşur","Tüm ülkeler aynı hızda geçiş yapabilir","Mevcut enerji altyapısı değişime gerek duymaz"]$json$::jsonb, 1, $$Yenilenebilir enerjiye geçiş, dışa bağımlılığı azaltır, yeni sektörlerde istihdam yaratır ve uzun vadede enerji maliyetini düşürür.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Yeşil Enerji ve Sürdürülebilir Gelecek' LIMIT 1), 'vocabulary', $$Metinde geçen "net sıfır emisyon" hedefi ne anlama gelir?$$, $json$["Hiçbir sektörün karbon salmaması","Salınan karbonun karbon yakalama, orman gibi yutaklar aracılığıyla tamamen dengelenmesi","Yenilenebilir enerji payının %50''ye ulaşması","Fosil yakıtların yalnızca sanayide kullanılmaya devam etmesi"]$json$::jsonb, 1, $$Net sıfır, bir ekonominin saldığı sera gazı miktarıyla atmosferden uzaklaştırdığı miktarın eşitlenerek net katkının sıfırlanmasını ifade eder.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Dilin Evrimi ve Geleceği' LIMIT 1), 'main_idea', $$Bu metnin ana fikri nedir?$$, $json$["Dil değişimi zararlıdır ve önlenmelidir","Diller canlı sistemler gibi değişir, gelişir ve küresel dinamiklerden etkilenir","Dünya dilleri hızla yok olmaktadır","İngilizce yakında tek dünya dili olacaktır"]$json$::jsonb, 1, $$Metin, dillerin tarihsel süreç içinde nasıl evrildiğini ve dijital çağda dil çeşitliliğinin geleceğini ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Dilin Evrimi ve Geleceği' LIMIT 1), 'detail', $$"Lingua franca" kavramı ne anlama gelir?$$, $json$["Ölü diller","Ortak dil olarak farklı anadili konuşanlar arasında iletişimde kullanılan köprü dil","Yalnızca yazılı iletişim dili","Resmî devlet dili"]$json$::jsonb, 1, $$Lingua franca, farklı dil toplulukları arasında anlaşmayı kolaylaştırmak amacıyla ortak araç dil olarak benimsenen dildir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Dilin Evrimi ve Geleceği' LIMIT 1), 'detail', $$Dijital teknolojinin dil üzerindeki etkisi bağlamında hangisi doğrudur?$$, $json$["Dijital iletişim dil çeşitliliğini tamamen ortadan kaldırmaktadır","Sosyal medya yeni dil kullanımları (emoji, kısaltmalar, neolojizmler) üretirken azınlık dillerinin korunmasına da katkı sağlayabilir","İnternet yalnızca İngilizce dilinin yayılmasına yol açmaktadır","Dijitalleşme dilin yazılı biçimlerini tamamen geçersiz kılmaktadır"]$json$::jsonb, 1, $$Dijital ortamlar hem yeni dil biçimleri yaratmakta hem de düşük kaynaklı dillerin dijital içerik üretmesine olanak tanıyarak çeşitliliğe katkı sunmaktadır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Dilin Evrimi ve Geleceği' LIMIT 1), 'inference', $$Her iki haftada bir bir dil yok olduğu gerçeğinden çıkarılabilecek en önemli sonuç nedir?$$, $json$["Dil kayıpları önemsiz ve kaçınılmazdır","Dillerle birlikte o dile özgü kültürel bilgi, hafıza ve dünya görüşü de yok olmaktadır","Dil kaybı yalnızca dilbilimcileri ilgilendirir","Dünya daha az dille daha iyi yönetilir"]$json$::jsonb, 1, $$Her dil, o topluluğun kültürel mirasını, bilgi birikimini ve bakış açısını barındırır; dil kaybı bu değerlerin de geri dönüşümsüz yitirilmesi anlamına gelir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Dilin Evrimi ve Geleceği' LIMIT 1), 'vocabulary', $$Metinde geçen "neolojizm" ne demektir?$$, $json$["Ölü dillerden ödünç alınan kelimeler","Toplumsal, teknolojik ya da kültürel değişimlere yanıt olarak bir dile yeni katılan kelimeler ya da anlamlar","Yabancı kökenli sözcüklere karşı kullanılan öz Türkçe kelimeler","Standart dilbilgisi kurallarına aykırı kullanımlar"]$json$::jsonb, 1, $$Neolojizmler, değişen dünyanın yeni kavramlarını karşılamak amacıyla bir dile eklenen yeni sözcük ya da anlam genişlemelerdir (ör. "selfie", "tweet").$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Okyanusların Gizemli Derinlikleri' LIMIT 1), 'main_idea', $$Bu metnin ana konusu nedir?$$, $json$["Deniz yüzeyindeki akıntı sistemleri","Okyanus derinliklerinin keşfedilmemiş dünyası ve bu ortamda yaşayan canlılar","Küresel balıkçılık endüstrisi","Deniz kirliliğinin geri dönüşüm süreçleri"]$json$::jsonb, 1, $$Metin; okyanus derinliklerinin keşif güçlüğünü, buradaki eşsiz ekosistemleri ve bilimsel önemini ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Okyanusların Gizemli Derinlikleri' LIMIT 1), 'detail', $$Derin deniz hidotermal bacaları (hydrothermal vents) hangi açıdan biyolojik önem taşır?$$, $json$["Okyanus yüzeyine oksijen pompalayarak balıkların yaşamasını sağlarlar","Güneş ışığı olmaksızın, kemosintez yoluyla beslenen eşsiz ekosistemlere ev sahipliği yaparlar","Derin deniz akıntılarını düzenleyerek iklimi etkilerler","Yalnızca jeolojik açıdan önem taşırlar, canlı barındırmazlar"]$json$::jsonb, 1, $$Hidrotermal bacalar, ışığa değil kimyasal enerjiye dayalı yaşam formları barındırır; bu da yaşamın güneşten bağımsız var olabileceğini kanıtlamaktadır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Okyanusların Gizemli Derinlikleri' LIMIT 1), 'detail', $$Mariana Çukuru''nun derinliği yaklaşık kaç metredir?$$, $json$["1.000 metre","4.000 metre","11.000 metre","20.000 metre"]$json$::jsonb, 2, $$Mariana Çukuru, yaklaşık 11.000 metre derinliğiyle Dünya''nın bilinen en derin noktasıdır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Okyanusların Gizemli Derinlikleri' LIMIT 1), 'inference', $$Okyanus derinliklerinin yalnızca %20''sinin haritasının çıkarılmış olması ne anlama gelir?$$, $json$["Okyanus araştırmaları tamamen gereksizdir","Uzayın pek çok bölgesinden daha az bildiğimiz bir alan olan derin denizler, büyük keşif potansiyeli taşımaktadır","Derin denizlerde canlı yaşamadığı kesindir","Okyanus tabanı düz ve tekdüzedir"]$json$::jsonb, 1, $$Derin okyanusların büyük bölümü hâlâ bilinmezliğini korumakta; bu durum, sayısız yeni tür ve kaynak keşfine açık bir alanın varlığına işaret etmektedir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Okyanusların Gizemli Derinlikleri' LIMIT 1), 'vocabulary', $$Metinde geçen "biyolüminesans" ne anlama gelir?$$, $json$["Derin denizde bulunan mineral yatakları","Deniz canlılarının kimyasal tepkimeler yoluyla kendi ışıklarını üretme yeteneği","Güneş ışığının okyanus yüzeyinde yansıması","Planktonların fotosentez yapma biçimi"]$json$::jsonb, 1, $$Biyolüminesans; derin deniz canlılarının karanlıkta iletişim, avlanma ya da savunma amacıyla kimyasal reaksiyonlarla biyolojik ışık üretmesidir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Müziğin Psikolojik Etkileri' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Müziğin tarihsel gelişimi","Müziğin insan psikolojisi, duyguları ve bilişsel süreçleri üzerindeki etkileri","Müzik endüstrisinin ekonomik boyutları","Farklı kültürlerde müzik aletlerinin kullanımı"]$json$::jsonb, 1, $$Metin; müziğin duygusal düzenleme, hafıza ve stres üzerindeki kanıtlanmış psikolojik etkilerini ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Müziğin Psikolojik Etkileri' LIMIT 1), 'detail', $$Müzik dinlerken beyinde dopamin salınımının artması neyi gösterir?$$, $json$["Müzik beyne zarar verir","Müzik beynin ödül sistemini harekete geçirerek zevk ve motivasyon duygusunu pekiştirir","Dopamin yalnızca spor yaparken salgılanır","Müzik dinlemek bir bağımlılık türüdür"]$json$::jsonb, 1, $$Dopamin, beynin ödül merkezini aktive eden bir nörotransmiterdir; müzik dinlemek bu mekanizmayı tetikleyerek zevk ve olumlu duygusal durumlar üretir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Müziğin Psikolojik Etkileri' LIMIT 1), 'detail', $$Müzik terapisi hangi alanlarda klinik olarak kullanılmaktadır?$$, $json$["Yalnızca ses yüksekliği bozukluklarında","Alzheimer, depresyon ve kronik ağrı yönetimi gibi alanlarda","Yalnızca çocuk psikolojisinde","Yalnızca fizyoterapi süreçlerinde"]$json$::jsonb, 1, $$Müzik terapisi; hafıza bozuklukları, ruh sağlığı sorunları ve kronik hastalıklarda kanıta dayalı tamamlayıcı bir tedavi yöntemi olarak uygulanmaktadır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Müziğin Psikolojik Etkileri' LIMIT 1), 'inference', $$"Mozart Etkisi" araştırmalarından çıkarılabilecek en dengeli sonuç hangisidir?$$, $json$["Klasik müzik dinlemek zekayı kalıcı olarak artırır","Müziğin bilişsel etkileri var, ancak bunlar belirli koşullara bağlı ve genellikle kısa sürelidir; abartılı iddiaların ötesinde kanıt yoktur","Popüler müzik dinlemek hafızayı olumsuz etkiler","Yalnızca müzik eğitimi alanlar müzikten yararlanır"]$json$::jsonb, 1, $$Mozart Etkisi araştırmaları, göreve ve bireye özgü, kısa süreli bilişsel etkiler bulmuş; ancak "klasik müzik=kalıcı zekâ artışı" iddiası bilimsel olarak desteklenmemektedir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Müziğin Psikolojik Etkileri' LIMIT 1), 'vocabulary', $$Metinde geçen "ritim entrayınmanı" (rhythmic entrainment) ne anlama gelir?$$, $json$["Bir ritim enstrümanı çalmayı öğrenmek","Vücudun fizyolojik ritimlerinin (kalp atışı, nefes) dışsal bir müzik ritmiyle eşzamanlanma eğilimi","Müzisyenlerin bir arada çalma tekniği","Beynin müziği depolama biçimi"]$json$::jsonb, 1, $$Ritim entrayınmanı; kalp atışı ve nefes gibi biyolojik ritimlerin dışarıdan gelen müzik ritmiyle eşzamanlandığı, fizyolojik bir uyum sürecidir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türk Mutfağının Zengin Tarihi' LIMIT 1), 'main_idea', $$Bu metnin temel iddiası nedir?$$, $json$["Türk mutfağı yalnızca kebap ve baklavayla sınırlıdır","Türk mutfağı coğrafi ve tarihsel çeşitlilik nedeniyle dünyanın en zengin ve köklü mutfaklarından biridir","Osmanlı saray mutfağı bugün tamamen yok olmuştur","Türk mutfağı yalnızca Orta Asya''dan etkilenmiştir"]$json$::jsonb, 1, $$Metin; Türk mutfağının Orta Asya''dan Anadolu''ya, Osmanlı sarayından günümüze uzanan köklü ve çeşitli tarihini ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Türk Mutfağının Zengin Tarihi' LIMIT 1), 'detail', $$Osmanlı saray mutfağının Türk mutfağına en büyük katkısı hangisidir?$$, $json$["Yalnızca et yemeklerinin geliştirilmesi","Farklı coğrafyalardan gelen malzemelerin bir araya getirilmesiyle zengin ve sofistike bir yemek kültürünün oluşturulması","Kahvenin icat edilmesi","Baharatların tarımının yapılmaya başlanması"]$json$::jsonb, 1, $$Osmanlı saray mutfağı; Balkanlar, Ortadoğu ve Anadolu''dan gelen malzeme ve teknikleri harmanlayarak çok katmanlı bir gastronomi geleneği oluşturmuştur.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Türk Mutfağının Zengin Tarihi' LIMIT 1), 'detail', $$Türk kahvesi ile ilgili hangisi doğrudur?$$, $json$["Türk kahvesi 20. yüzyılda icat edilmiştir","Türk kahvesi UNESCO tarafından somut olmayan kültürel miras listesine alınmıştır","Türk kahvesi filtreyle hazırlanır","Türk kahvesi yalnızca şekerli içilir"]$json$::jsonb, 1, $$Türk kahvesi yapım geleneği ve kültürü, 2013 yılında UNESCO İnsanlığın Somut Olmayan Kültürel Mirası listesine girmiştir.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Türk Mutfağının Zengin Tarihi' LIMIT 1), 'inference', $$Türk mutfağının bölgesel çeşitlilik taşıması hangi sonucu doğurur?$$, $json$["Türk mutfağının tanımlanması ve korunması güçleşir","Her bölgenin kendine özgü lezzetleri, Türk mutfağını gastronomik açıdan son derece zengin kılmaktadır","Bölgesel çeşitlilik turistleri olumsuz etkiler","Standart Türk yemeği oluşturmak mümkün değildir"]$json$::jsonb, 1, $$Karadeniz''in hamsi geleneğinden Güneydoğu''nun baharatlı lezzetlerine uzanan bölgesel zenginlik, Türk mutfağını küresel gastronomi arenasında öne çıkarmaktadır.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Türk Mutfağının Zengin Tarihi' LIMIT 1), 'vocabulary', $$Metinde geçen "gastronomi" kavramı ne anlama gelir?$$, $json$["Yalnızca fast food kültürü","Yemek ve mutfak kültürünü sanatsal, bilimsel ve kültürel boyutlarıyla inceleyen alan","Diyetetik ve beslenme bilimi","Yalnızca şef yetiştiren okul"]$json$::jsonb, 1, $$Gastronomi; yemek pişirmenin tarihini, kültürünü, lezzetini ve sanatını disiplinlerarası bir perspektifle ele alan geniş bir alandır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Meditasyonun Beyne Etkisi' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Meditasyonun dini ve spiritüel boyutları","Düzenli meditasyon pratiğinin beyin yapısı ve işlevi üzerindeki bilimsel olarak kanıtlanmış etkileri","Nefes egzersizlerinin spor performansına katkısı","Stres kavramının psikolojik tanımı"]$json$::jsonb, 1, $$Metin; meditasyonun prefrontal korteks, amigdala ve nöroplastisite üzerindeki bilimsel kanıtlarını ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Meditasyonun Beyne Etkisi' LIMIT 1), 'detail', $$Araştırmalar meditasyon yapan kişilerde amigdalanın nasıl etkilendiğini göstermiştir?$$, $json$["Amigdala büyür ve stres tepkileri güçlenir","Amigdala hacmi azalır ve stres uyarıcılarına verilen tepkiler zayıflar","Amigdala tamamen devre dışı kalır","Amigdala ile prefrontal korteks arasındaki bağlantı kesilir"]$json$::jsonb, 1, $$Uzun süreli meditasyon pratisyenlerinde amigdalanın küçüldüğü ve tehdit uyarıcılarına verilen fizyolojik tepkilerin hafifleyebildiği gösterilmiştir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Meditasyonun Beyne Etkisi' LIMIT 1), 'detail', $$"Farkındalık (mindfulness)" meditasyonu hangi temel beceriyi geliştirmeyi hedefler?$$, $json$["Zihnin tamamen boşaltılması","Şimdiki ana odaklanma ve düşünceleri yargılamadan gözlemleme kapasitesinin artırılması","Geçmiş deneyimlerin yeniden yaşanması","Uyku sırasında bilinçli rüya görme"]$json$::jsonb, 1, $$Farkındalık meditasyonu; dikkat, şimdiki ana odaklanma ve yargılamadan gözlemleme becerilerini geliştirmeye yönelik sistematik bir pratiktir.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Meditasyonun Beyne Etkisi' LIMIT 1), 'inference', $$Meditasyonun nöroplastisite üzerindeki etkisinden çıkarılabilecek en önemli sonuç nedir?$$, $json$["Beyin yetişkinlikte tamamen değişmez","Yetişkin beyni bile düzenli pratikle yapısal değişimler yaşayabilir; bu, zihinsel sağlık müdahalelerini daha umut verici kılar","Meditasyon yalnızca çocuklarda fayda sağlar","Nöroplastisite yalnızca hasardan sonra gerçekleşir"]$json$::jsonb, 1, $$Nöroplastisite araştırmaları, meditasyonun gri madde yoğunluğunu artırabildiğini göstermekte; bu da yaşam boyu beyin gelişiminin mümkün olduğuna işaret etmektedir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Meditasyonun Beyne Etkisi' LIMIT 1), 'vocabulary', $$Metinde geçen "nöroplastisite" ne anlama gelir?$$, $json$["Beyin hücrelerinin ölümüyle gerçekleşen yeniden yapılanma","Beynin deneyim ve pratik yoluyla yapısal ve işlevsel olarak kendini yeniden organize edebilme kapasitesi","Sinir sisteminin enfeksiyonlara karşı direnci","Nöronlar arası kimyasal sinyal iletiminin hızı"]$json$::jsonb, 1, $$Nöroplastisite, beynin öğrenme, deneyim ya da müdahale sonucunda sinaptik bağlantılarını ve yapısını değiştirebilme yeteneğidir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Dijital Çağda Mahremiyet' LIMIT 1), 'main_idea', $$Bu metnin ana kaygısı nedir?$$, $json$["İnternet hızlarının yetersizliği","Dijital teknolojilerin kişisel verileri toplama ve işleme biçiminin bireysel mahremiyet ve özgürlük üzerindeki etkileri","Sosyal medya bağımlılığı","E-ticaret güvenlik protokolleri"]$json$::jsonb, 1, $$Metin; gözetim kapitalizminden veri güvenliğine kadar dijital mahremiyetin tehdit altındaki boyutlarını ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Dijital Çağda Mahremiyet' LIMIT 1), 'detail', $$"Gözetim kapitalizmi" (surveillance capitalism) kavramı ne anlama gelir?$$, $json$["Devletlerin vatandaşları izleme faaliyeti","Şirketlerin kullanıcı davranış verilerini toplayarak tahmin ürününe dönüştürdüğü ve sattığı ekonomik model","Kameraların şehirlerde yaygın kullanımı","Siber güvenlik hizmetlerinin ticarileşmesi"]$json$::jsonb, 1, $$Shoshana Zuboff''un tanımladığı gözetim kapitalizmi; kişisel verilerin insan davranışını tahmin etmek ve yönlendirmek amacıyla ticari bir kaynağa dönüştürüldüğü yeni bir ekonomik modeldir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Dijital Çağda Mahremiyet' LIMIT 1), 'detail', $$GDPR (Genel Veri Koruma Tüzüğü) hangi temel hakkı güvence altına alır?$$, $json$["İnternet erişim hakkı","AB vatandaşlarının kişisel verilerinin nasıl toplandığı, işlendiği ve saklandığı konusundaki denetim hakkı","Dijital içeriklere telif hakkı","Sosyal medya hesabı açma hakkı"]$json$::jsonb, 1, $$GDPR; kullanıcılara verilerine erişim, silme ve itiraz etme hakları tanıyan, veri işleyen kuruluşları şeffaflık ve hesap verebilirlik yükümlülüğüne sokan bir Avrupa düzenlemesidir.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Dijital Çağda Mahremiyet' LIMIT 1), 'inference', $$"Veriyi paylaştıkça mahremiyet azalır" kabulünden çıkarılabilecek en önemli sonuç hangisidir?$$, $json$["Bireyler dijital platformları tamamen terk etmelidir","Bireyler veri paylaşımının bedellerini anlayacak dijital okuryazarlığa ve yasal korumalara ihtiyaç duyar","Mahremiyet modern dünyada anlamsız bir kavramdır","Şirketler kullanıcı verilerini her zaman güvenle saklar"]$json$::jsonb, 1, $$Dijital mahremiyetin korunması; bireysel farkındalığı, güçlü yasal çerçeveleri ve teknoloji tasarımında "gizlilik öncelikli" yaklaşımı zorunlu kılmaktadır.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Dijital Çağda Mahremiyet' LIMIT 1), 'vocabulary', $$Metinde geçen "şifreleme (encryption)" ne anlama gelir?$$, $json$["Verilerin silinmesi","Verilerin yalnızca yetkili tarafların okuyabileceği biçime dönüştürülmesi için kullanılan matematiksel yöntem","Verilerin bulut sunucularına yüklenmesi","Çevrimiçi şifre oluşturma protokolü"]$json$::jsonb, 1, $$Şifreleme; verileri yetkisiz erişime karşı korumak amacıyla okunaksız bir formata dönüştüren kriptografik bir yöntemdir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Uzay Keşfinin Geleceği' LIMIT 1), 'main_idea', $$Bu metnin temel teması nedir?$$, $json$["Apollo görevlerinin tarihi","Uzay keşfinin gelecekteki yönelimi: Mars kolonizasyonu, ticari uzay şirketleri ve insanlığın çok gezegenli bir tür olma hedefi","Uydu iletişim teknolojileri","Uluslararası Uzay İstasyonu''nun günlük işleyişi"]$json$::jsonb, 1, $$Metin; uzayın özel sektörle birlikte nasıl dönüşen bir keşif alanına girdiğini ve uzun vadeli insan uzay yolculuğu hedeflerini ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Uzay Keşfinin Geleceği' LIMIT 1), 'detail', $$SpaceX''in yeniden kullanılabilir roket teknolojisi uzay endüstrisine nasıl katkı sağlamıştır?$$, $json$["Roket yapımını tamamen otomatikleştirmiştir","Fırlatma maliyetlerini dramatik biçimde düşürerek uzayın ticarileşmesini ve daha sık fırlatmaları mümkün kılmıştır","Roketlerin daha yüksek irtifaya çıkmasını sağlamıştır","Astronotların uzayda daha uzun süre kalmasına olanak tanımıştır"]$json$::jsonb, 1, $$Yeniden kullanılabilir roket aşamaları, her fırlatma için yeni roket üretme ihtiyacını ortadan kaldırarak fırlatma maliyetlerini 10 kat ve üzerinde azaltmıştır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Uzay Keşfinin Geleceği' LIMIT 1), 'detail', $$Mars''ta kalıcı insanlı yerleşim için en büyük teknik engel nedir?$$, $json$["Mars''ın Güneş''e çok yakın olması","Radyasyon, mikro yer çekimi, yaşam destek sistemleri ve Dünya ile iletişim gecikmesi gibi çok sayıda kritik sorunun çözülmesi gereği","Mars''ın atmosferinin çok kalın olması","Roketlerin Mars''a inişinin imkânsız olması"]$json$::jsonb, 1, $$Mars kolonizasyonu; uzun süreli radyasyon maruziyeti, düşük yer çekiminin fizyolojik etkileri, oksijen üretimi ve Güneş''ten uzak mesafeyi gibi birçok teknik zorluğu bir arada çözmek gerektirmektedir.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Uzay Keşfinin Geleceği' LIMIT 1), 'inference', $$Metinden çıkarılabilecek en uygun sonuç nedir?$$, $json$["Uzay keşfi artık yalnızca devletlerin sorumluluğundadır","Özel şirketlerin uzay yarışına girmesi, keşif hızını artırmakta ve maliyetleri düşürerek uzayı daha erişilebilir kılmaktadır","Uzay keşfi yalnızca askeri amaçlarla sürdürülmektedir","Mars''a insan göndermek mevcut teknoloji ile mümkün değildir"]$json$::jsonb, 1, $$Özel sektörün katılımı, yenilik ve rekabet yoluyla uzay keşfini dönüştürmekte; geçmişin sadece devlet alanı olan uzayı artık çok aktörlü bir platforma dönüştürmektedir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Uzay Keşfinin Geleceği' LIMIT 1), 'vocabulary', $$Metinde geçen "terraforming" ne anlama gelir?$$, $json$["Uzay aracı yakıt teknolojisi","Bir gezegenin atmosferini, iklimini ve topoğrafyasını insanların yaşayabileceği biçime dönüştürme süreci","Uzay istasyonu inşaat tekniği","Güneş sistemi dışına seyahat"]$json$::jsonb, 1, $$Terraforming; başka bir gezegeni sıcaklık, atmosfer bileşimi ve su açısından Dünya''ya benzer koşullara getirme sürecidir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Yapay Zeka Günlük Hayatı Nasıl Değiştiriyor?' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Yapay zekanın yalnızca üretim sanayiindeki uygulamaları","Yapay zekanın sağlık, ulaşım, eğitim ve iletişim gibi alanlarda günlük yaşamı nasıl dönüştürdüğü","Yapay zekanın askeri alandaki kullanımı","Yapay zekanın yalnızca büyük şirketlere faydası"]$json$::jsonb, 1, $$Metin; YZ''nin öneri sistemlerinden akıllı sağlık uygulamalarına kadar günlük yaşamı hangi alanlarda dönüştürdüğünü ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka Günlük Hayatı Nasıl Değiştiriyor?' LIMIT 1), 'detail', $$Öneri algoritmaları (recommendation algorithms) hangi prensiple çalışır?$$, $json$["Kullanıcılara rastgele içerik sunar","Kullanıcının geçmiş davranışlarını, tercihlerini ve benzer kullanıcı kalıplarını analiz ederek kişiselleştirilmiş içerik önerir","Yalnızca en popüler içerikleri sıralar","Kullanıcı profilini hiç dikkate almadan çalışır"]$json$::jsonb, 1, $$Öneri sistemleri; işbirlikçi filtreleme, içerik tabanlı filtreleme ve derin öğrenme gibi yöntemlerle kullanıcı tercihlerini modelleyerek kişiselleştirilmiş deneyimler sunar.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka Günlük Hayatı Nasıl Değiştiriyor?' LIMIT 1), 'detail', $$YZ destekli sağlık uygulamaları tıp alanında nasıl bir katkı sunmaktadır?$$, $json$["Doktorların görevlerini tamamen devralmıştır","Görüntü analizi, erken teşhis ve hasta riski tahmini gibi alanlarda klinisyenlerin karar sürecini desteklemektedir","Yalnızca randevu yönetiminde kullanılmaktadır","Tıbbi araştırma süreçlerini yavaşlatmaktadır"]$json$::jsonb, 1, $$YZ; radyoloji görüntülerini analiz etme, kanser erken tespiti ve hasta risk skorlaması gibi görevlerde hekimlerin daha hızlı ve doğru kararlar almasına yardımcı olmaktadır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka Günlük Hayatı Nasıl Değiştiriyor?' LIMIT 1), 'inference', $$YZ''nin günlük hayata hızla girmesi bireylerin hangi beceriye daha çok ihtiyaç duymasına yol açar?$$, $json$["Fiziksel güç gerektiren meslekler daha önemli hâle gelir","Eleştirel düşünme, YZ okuryazarlığı ve etik değerlendirme becerileri giderek daha kritik hale gelir","Matematik ve fen bilimleri öğrenmeye gerek kalmaz","Bireyler teknolojiden uzak durmalıdır"]$json$::jsonb, 1, $$YZ araçlarını eleştirel biçimde değerlendirebilen, çıktılarını doğrulayan ve etik boyutlarını sorgulayan bireyler, otomasyon çağında daha güçlü bir konumda olacaktır.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Yapay Zeka Günlük Hayatı Nasıl Değiştiriyor?' LIMIT 1), 'vocabulary', $$Metinde geçen "doğal dil işleme (NLP)" ne anlama gelir?$$, $json$["Programlama dillerinin bilgisayar tarafından yazılması","Bilgisayarların insan dilini anlama, yorumlama ve üretme kapasitesini inceleyen YZ alt alanı","Seslerin müziğe dönüştürülmesi","İnsan beyninin dil üretim mekanizması"]$json$::jsonb, 1, $$NLP; sohbet botları, dil çevirisi ve duygu analizi gibi uygulamalar yoluyla bilgisayarların insan diliyle etkileşime girmesini mümkün kılar.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Anadolu''nun Coğrafi Özellikleri' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Anadolu''nun yalnızca iklim özelliklerinin tanıtılması","Anadolu''nun fiziki, beşeri ve ekonomik coğrafyasının birlikte değerlendirilmesi","Ege kıyılarının turizm potansiyeli","Türkiye''nin tarihsel sınır değişimleri"]$json$::jsonb, 1, $$Metin; Anadolu''nun dağ kuşakları, akarsu havzaları, iklim çeşitliliği ve bunların nüfus ve ekonomi üzerindeki etkilerini kapsamlı biçimde ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Anadolu''nun Coğrafi Özellikleri' LIMIT 1), 'detail', $$Türkiye''nin en uzun akarsuyu hangisidir?$$, $json$["Sakarya Nehri","Kızılırmak Nehri","Fırat Nehri","Yeşilırmak Nehri"]$json$::jsonb, 1, $$Kızılırmak, yaklaşık 1.355 km uzunluğuyla Türkiye''nin yalnızca kendi toprakları içinde seyreden en uzun nehridir.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Anadolu''nun Coğrafi Özellikleri' LIMIT 1), 'detail', $$Karadeniz kıyılarında yağışın yıl boyunca dengeli dağılmasının temel nedeni nedir?$$, $json$["Kıyıya paralel uzanan dağların güney yönlü rüzgârları kesmesi","Kuzey''den gelen nemli hava kütlelerinin kıyı dağlarına çarparak yağış bırakması","Karadeniz''in tuzluluk oranının düşük olması","Karadeniz kıyılarının İç Anadolu iklimiyle aynı özelliği taşıması"]$json$::jsonb, 1, $$Kuzey''den esen nem taşıyan hava kütleleri, Kuzey Anadolu Dağları''na çarptığında burada yoğunlaşarak yıl boyunca yüksek yağış bırakır.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Anadolu''nun Coğrafi Özellikleri' LIMIT 1), 'inference', $$İç Anadolu''nun karasal iklimine sahip olmasının tarım üzerindeki en önemli etkisi nedir?$$, $json$["İç Anadolu''da tarım yapılması mümkün değildir","Sert kışlar ve kurak yazlar, sulama gerektiren tarla tarımını ön plana çıkarır; tahıl tarımı bölgenin tarımsal kimliğini şekillendirir","İç Anadolu''nun tüm coğrafi bölgeler içinde en yüksek tarım geliri elde ettiği anlamına gelir","Karasal iklim meyve yetiştiriciliğini imkânsız kılar"]$json$::jsonb, 1, $$Kışın dondurucu soğuklar ve yazın kuraklık, sulama altyapısı gerektiren buğday, arpa gibi tahıl tarımını bölgenin temel geçim kaynağı hâline getirmiştir.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Anadolu''nun Coğrafi Özellikleri' LIMIT 1), 'vocabulary', $$Metinde geçen "fay hattı" kavramı coğrafi açıdan ne anlama gelir?$$, $json$["Nehirlerin yataklarında oluşan çöküntüler","Yer kabuğundaki levha sınırlarını oluşturan kırık ve çatlak hatları; bu hatlarda depremler yoğunlaşır","Dağ sıralarının zirve çizgisi","Deniz ve kara arasındaki gel-git bölgesi"]$json$::jsonb, 1, $$Fay hatları; tektonik levhaların birbirinden ayrıldığı ya da sürüştüğü kırık zonlardır; Türkiye''nin Kuzey Anadolu Fay Hattı bunun en önemli örneğidir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Dış Politikası' LIMIT 1), 'main_idea', $$Bu metnin temel odağı nedir?$$, $json$["Türkiye''nin tarihsel sınır değişimleri","Türkiye''nin dış politika öncelikleri, çok boyutlu ilişkileri ve bölgesel aktörlük rolü","Türkiye''nin yalnızca NATO üyeliğinin değerlendirilmesi","Türkiye-AB ilişkilerinin hukuki boyutu"]$json$::jsonb, 1, $$Metin; Türkiye''nin Batı ittifakı, komşu bölgeler ve küresel aktörlerle çok katmanlı dış politika yürüttüğünü ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Dış Politikası' LIMIT 1), 'detail', $$Türkiye''nin NATO''ya katılımı hangi yılda gerçekleşmiştir?$$, $json$["1945","1952","1960","1974"]$json$::jsonb, 1, $$Türkiye, 1952 yılında Yunanistan ile birlikte NATO''ya katılarak Kuzey Atlantik ittifakının üyesi olmuştur.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Dış Politikası' LIMIT 1), 'detail', $$"Stratejik derinlik" doktrini Türk dış politikasında ne anlama gelir?$$, $json$["Yalnızca komşu ülkelerle ilişkilerin güçlendirilmesi","Türkiye''nin Osmanlı mirası ve tarihsel bağlara dayanarak çok boyutlu ve aktif bir dış politika izlemesi gerektiği görüşü","Türkiye''nin askeri kapasitesinin artırılması","Avrupa ile ilişkilerin yoğunlaştırılması"]$json$::jsonb, 1, $$Ahmet Davutoğlu''nun geliştirdiği stratejik derinlik; Türkiye''nin Orta Doğu, Balkanlar, Kafkasya ve Afrika''daki tarihi bağlarını diplomatik etki alanına dönüştürmesini öngörür.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Dış Politikası' LIMIT 1), 'inference', $$Türkiye''nin hem NATO üyesi olması hem de Rusya ile S-400 alımında işbirliği yapması hangi dış politika yaklaşımını yansıtmaktadır?$$, $json$["Türkiye Batılı ittifaktan tamamen kopmuştur","Türkiye çok boyutlu ve pragmatik bir dış politika izleyerek farklı güç merkezleriyle aynı anda ilişkilerini sürdürmektedir","Türkiye yalnızca ekonomik çıkar odaklı dış politika yürütmektedir","Bu durum Türkiye''nin uluslararası hukuku ihlal ettiğinin kanıtıdır"]$json$::jsonb, 1, $$Türkiye; Batı ittifakı içinde kalmayı sürdürürken Rusya, Çin ve Körfez ülkeleriyle pragmatik ilişkiler kurarak özerk bir dış politika alanı açmaktadır.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Dış Politikası' LIMIT 1), 'vocabulary', $$Metinde geçen "yumuşak güç (soft power)" kavramı ne anlama gelir?$$, $json$["Askeri kuvvet kullanımı","Kültür, diplomasi, medya ve ekonomi gibi zorlamaya dayanmayan araçlarla diğer ülkeler üzerinde etki kurma kapasitesi","Deniz kuvvetlerinin uluslararası sulardaki varlığı","Resmi ittifak anlaşmaları"]$json$::jsonb, 1, $$Joseph Nye''ın tanımladığı yumuşak güç; bir ülkenin değerlerini, kültürünü ve kurumlarını çekici kılarak başkalarını zorlama değil, ikna yoluyla etkileme kapasitesidir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Ekonomik Kalkınma Süreci' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Osmanlı döneminin ticaret politikaları","Türkiye''nin Cumhuriyet döneminden günümüze ekonomik kalkınma stratejileri ve dönüşüm süreçleri","Tarım sektörünün 19. yüzyıldaki yapısı","Türkiye''nin dış borç sorunları"]$json$::jsonb, 1, $$Metin; devletçilik politikalarından ihracata yönelik büyüme stratejilerine uzanan Türkiye''nin ekonomik dönüşümünü ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Ekonomik Kalkınma Süreci' LIMIT 1), 'detail', $$1980 yılında Türkiye''de uygulanan ekonomik dönüşüm paketinin temel özelliği nedir?$$, $json$["Devlet mülklerinin kamulaştırılması","İthal ikameci modelden ihracata dayalı ve serbest piyasa odaklı bir ekonomi modeline geçiş","Tarım reformunun uygulamaya konması","Katma değer vergisinin kaldırılması"]$json$::jsonb, 1, $$24 Ocak 1980 Kararları; ithal ikameci sanayileşme politikalarından ihracata yönelik ve piyasa mekanizmasına dayalı bir ekonomik modele geçişi simgelemektedir.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Ekonomik Kalkınma Süreci' LIMIT 1), 'detail', $$2001 krizi sonrasında Türkiye''de uygulanan ekonomik programın öne çıkan özelliği nedir?$$, $json$["Döviz kurunu sabitleme","Merkez Bankası bağımsızlığının güçlendirilmesi, bankacılık düzenlemesi ve maliye disiplini","Tüm kamu bankalarının özelleştirilmesi","İthalat vergilerinin artırılması"]$json$::jsonb, 1, $$2001 krizi sonrası IMF destekli program; merkez bankası bağımsızlığını, bankacılık sektörü reformunu ve sıkı maliye politikasını ön plana çıkarmış ve 2002-2007 arasında güçlü büyüme dönemini hazırlamıştır.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Ekonomik Kalkınma Süreci' LIMIT 1), 'inference', $$Türkiye''nin kalkınma sürecinde "orta gelir tuzağı" riskiyle karşılaşmasının nedeni neden önemlidir?$$, $json$["Türkiye zaten yüksek gelirli bir ekonomidir","Gelişmekte olan ekonomilerin düşük maliyetli üretimden uzaklaşıp yüksek katma değerli sanayilere geçişi başaramaması durumunda büyüme yavaşlar","Türkiye''nin nüfusu büyümeyi desteklemek için çok fazladır","Orta gelir tuzağı yalnızca Asya ülkeleri için geçerlidir"]$json$::jsonb, 1, $$Orta gelir tuzağı; ucuz iş gücü avantajını kaybeden ama teknoloji ve yenilik yoğun sektörlere geçişi henüz tamamlayamamış ekonomiler için kritik bir kalkınma sorunudur.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Ekonomik Kalkınma Süreci' LIMIT 1), 'vocabulary', $$Metinde geçen "cari açık" kavramı ne anlama gelir?$$, $json$["Devlet bütçesinin gider fazlası","Bir ülkenin mal, hizmet ve faktör gelirlerinden oluşan dış ödemeler dengesinde giderlerin gelirleri aşması","Merkez bankasının döviz rezervlerindeki azalma","Dış ticaret vergilerinden elde edilen gelirler"]$json$::jsonb, 1, $$Cari açık; bir ülkenin belirli bir dönemde yurt dışından ithal ettiği mal ve hizmetlerin, ihracatından fazla olması nedeniyle oluşan dış denge açığıdır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'İnsan Hakları ve Türkiye' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkiye''nin yalnızca ekonomik haklar alanındaki başarıları","Türkiye''nin uluslararası insan hakları normlarıyla ilişkisi ve bu alandaki tarihsel gelişimi","Türkiye''nin NATO yükümlülükleri","Türkiye''de yargı reformu"]$json$::jsonb, 1, $$Metin; Türkiye''nin uluslararası insan hakları sözleşmeleri, Avrupa İnsan Hakları Mahkemesi kararları ve iç hukuktaki dönüşümleri bağlamında insan hakları sicilini ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'İnsan Hakları ve Türkiye' LIMIT 1), 'detail', $$Avrupa İnsan Hakları Mahkemesi (AİHM) hangi amaçla kurulmuştur?$$, $json$["AB üyesi devletlerin ekonomik uyumunu denetlemek için","Avrupa İnsan Hakları Sözleşmesi''nden doğan hakların bireyler tarafından başvurulabileceği ulusüstü bir yargı organı oluşturmak için","NATO üyeliğinin koşullarını belirlemek için","Uluslararası ticaret anlaşmazlıklarını çözmek için"]$json$::jsonb, 1, $$AİHM; devletlere karşı bireysel başvuru hakkı tanıyan ve AİHS ihlallerini bağlayıcı kararlarla denetleyen bir Avrupa Konseyi kurumudur.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'İnsan Hakları ve Türkiye' LIMIT 1), 'detail', $$Türkiye''nin 1982 Anayasası''nda insan hakları bağlamında en çok eleştirilen husus nedir?$$, $json$["Temel haklara hiç yer vermemesi","Temel hak ve özgürlüklerin kapsamlı sınırlandırma gerekçeleri ve olağanüstü hâl hükümleriyle fiilen daraltılabilmesi","Seçim sisteminin haksız olması","Yargı bağımsızlığına hiçbir güvence tanımaması"]$json$::jsonb, 1, $$1982 Anayasası; geniş sınırlama ve askıya alma hükümleri nedeniyle insan hakları örgütleri ve AB tarafından temel hak güvencesi açısından yetersiz bulunmaktadır.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'İnsan Hakları ve Türkiye' LIMIT 1), 'inference', $$AİHM''de Türkiye aleyhine açılan dava sayısının Avrupa''da en yüksek ülkeler arasında yer alması ne anlama gelir?$$, $json$["Türkiye yargısı her zaman hukuka aykırı karar vermektedir","Türkiye''deki bireyler haklarını savunmak için uluslararası başvuru yollarını kullanmakta; bu iç hukuk yollarının yetersizliğine işaret etmektedir","AİHM Türkiye''ye karşı önyargılıdır","Bu durum, Türkiye''nin diğer ülkelerden daha fazla nüfusa sahip olmasından kaynaklanmaktadır"]$json$::jsonb, 1, $$Yüksek dava sayısı; iç hukukta hak ihlallerinin karşılanmadığını ve bireylerin uluslararası güvence mekanizmalarına yöneldiğini göstermektedir.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'İnsan Hakları ve Türkiye' LIMIT 1), 'vocabulary', $$Metinde geçen "evrensel yargı yetkisi (universal jurisdiction)" ne anlama gelir?$$, $json$["Yalnızca BM güvenlik konseyinin kullandığı hukuki yetki","Bir devletin, suç mağduru ya da faili kendi vatandaşı olmasa bile insanlığa karşı işlenen ağır suçları yargılama hakkı","AİHM''nin iç mahkemeler üzerindeki denetim yetkisi","Uluslararası Ceza Mahkemesi''nin kuruluş ilkesi"]$json$::jsonb, 1, $$Evrensel yargı yetkisi; soykırım, işkence ve insanlığa karşı suçlar gibi ağır ihlallerde coğrafi bağ aranmaksızın yargılama yapılabilmesine olanak tanır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Anayasal Düzeni' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkiye''nin seçim kampanya stratejileri","Türkiye''nin anayasal yapısı, temel ilkeleri ve hükümet sistemi","Türkiye''nin yargı bütçesi","Türkiye''nin belediye sistemi"]$json$::jsonb, 1, $$Metin; Türkiye''nin anayasal çerçevesini, temel ilkelerini (cumhuriyetçilik, laiklik vb.) ve hükümet sisteminin yapısını ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Anayasal Düzeni' LIMIT 1), 'detail', $$1982 Anayasası''nın değiştirilemez ve değiştirilmesi teklif bile edilemez hükümleri nelerdir?$$, $json$["Yalnızca cumhurbaşkanlığı seçim sistemi","Devletin cumhuriyet niteliği, ülkenin bütünlüğü, resmî dili, başkenti ve laik demokratik devlet ilkeleri","Sadece başkent Ankara''nın değiştirilemezliği","Devlet bütçesinin denk olması zorunluluğu"]$json$::jsonb, 1, $$Anayasa''nın 4. maddesi; cumhuriyetin temel niteliklerini, başkentini, resmî dilini ve devlet şeklini değiştirilemez ve değiştirilmesi teklif bile edilemez hükümler olarak koruma altına almıştır.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Anayasal Düzeni' LIMIT 1), 'detail', $$2017 anayasa değişikliğiyle Türkiye''de hükümet sistemi nasıl dönüşmüştür?$$, $json$["Parlamenter sistem güçlendirilmiş ve başbakanlık makamı kalıcı hâle getirilmiştir","Parlamenter sistemden cumhurbaşkanlığı hükümet sistemine geçilmiş, yürütme yetkisi cumhurbaşkanında toplanmıştır","Yarı başkanlık sisteminden tam parlamenter sisteme dönülmüştür","Cumhurbaşkanlığı sembolik bir makama dönüştürülmüştür"]$json$::jsonb, 1, $$2017 referandumuyla kabul edilen ve 2018''de yürürlüğe giren değişiklikle başbakanlık kaldırılmış, yürütme yetkisi cumhurbaşkanında toplanmıştır.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Anayasal Düzeni' LIMIT 1), 'inference', $$Anayasa Mahkemesi''nin bireysel başvuru hakkını kabul etmesinin en önemli anayasal sonucu nedir?$$, $json$["Anayasa Mahkemesi yargı denetimini devre dışı bırakmıştır","Bireyler, temel haklarının ihlal edildiği iddiasıyla olağan yargı yollarını tükettikten sonra doğrudan Anayasa Mahkemesi''ne başvurabilmektedir","Bu düzenleme yürütmenin yetkisini artırmaktadır","Bireysel başvuru hakkı yalnızca Türk vatandaşlarına tanınmıştır"]$json$::jsonb, 1, $$2012''de hayata geçirilen bireysel başvuru; temel hak ihlali iddiasında bulunan kişilere AİHM''ye gitmeden önce iç hukukta çözüm arayan anayasal bir güvence mekanizması sağlamaktadır.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Anayasal Düzeni' LIMIT 1), 'vocabulary', $$Metinde geçen "hukuk devleti" ilkesi ne anlama gelir?$$, $json$["Devletin yasama yetkisini tek başına kullanması","Devlet eylem ve işlemlerinin bağlayıcı hukuk kurallarına, yargısal denetime ve hak güvencelerine tabi olması","Anayasa mahkemelerinin yargı yetkisinin sınırlanması","Hükümetin kararname yetkisini genişletmesi"]$json$::jsonb, 1, $$Hukuk devleti ilkesi; devlet yetkisinin anayasa ve yasalarla sınırlandırıldığı, keyfi uygulamanın önlendiği ve bireylerin yargısal güvenceden yararlandığı düzeni ifade eder.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkiye''de Demokratikleşme Süreci' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkiye''nin 1923''ten bu yana kesintisiz demokratik gelişimi","Türkiye''de çok partili hayata geçişten günümüze demokratikleşmenin ilerlemeleri, kırılmaları ve gerilimleri","Türkiye''de yerel seçim sistemleri","Siyasi partilerin ideolojik dönüşümü"]$json$::jsonb, 1, $$Metin; 1946''daki çok partili hayata geçişten başlayarak askeri müdahaleler, Avrupa entegrasyonu ve siyasal kutuplaşma üzerinden demokratikleşme tarihini ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Türkiye''de Demokratikleşme Süreci' LIMIT 1), 'detail', $$Türkiye''de 1946''da çok partili hayata geçişin simgesi olarak kurulan muhalefet partisi hangisidir?$$, $json$["Cumhuriyet Halk Partisi","Demokrat Parti","Adalet Partisi","Millet Partisi"]$json$::jsonb, 1, $$Demokrat Parti; 1946''da Celal Bayar, Adnan Menderes ve arkadaşları tarafından kurulmuş ve 1950''de iktidar olarak Türkiye''de ilk gerçek iktidar değişikliğini gerçekleştirmiştir.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Türkiye''de Demokratikleşme Süreci' LIMIT 1), 'detail', $$1960, 1971 ve 1980 askeri müdahalelerinin Türk demokrasisi açısından ortak sonucu nedir?$$, $json$["Her müdahale kalıcı askeri yönetimleri beraberinde getirmiştir","Her müdahale demokratik süreci sekteye uğratmış ve yeni anayasal düzenlemelerle sivil siyasete yeniden geçilmiştir","Askeri yönetimler ekonomiyi her seferinde büyük ölçüde geliştirmiştir","Müdahaleler uluslararası toplum tarafından onaylanmıştır"]$json$::jsonb, 1, $$Her müdahale parlamentoyu ve hükümeti feshetmiş; ardından yeni anayasa ya da değişikliklerle sivillere bırakılan ama kısıtlanmış siyasal düzenler kurulmuştur.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Türkiye''de Demokratikleşme Süreci' LIMIT 1), 'inference', $$AB üyelik sürecinin Türkiye''deki demokratikleşmeye katkısı nasıl değerlendirilebilir?$$, $json$["AB süreci Türkiye''de hiçbir hukuki değişikliğe yol açmamıştır","2000''li yıllarda AB uyum paketleriyle temel haklar, yargı bağımsızlığı ve azınlık hakları alanlarında önemli yasal reformlar hayata geçirilmiştir","AB süreci Türkiye''de antidemokratik gelişmelere zemin hazırlamıştır","AB yalnızca ekonomik koşullar koymuştur"]$json$::jsonb, 1, $$2002-2006 arasında hayata geçirilen AB uyum yasaları; işkence yasağının güçlendirilmesi, ifade özgürlüğünün genişletilmesi ve ölüm cezasının kaldırılması gibi önemli demokratik reformları içermektedir.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Türkiye''de Demokratikleşme Süreci' LIMIT 1), 'vocabulary', $$Metinde geçen "demokratik konsolidasyon" ne anlama gelir?$$, $json$["İlk serbest seçimin yapılması","Demokratik ilke ve kurumların tüm siyasi aktörler tarafından meşru ve sorgulanamaz kabul edildiği olgunluk aşaması","Anayasanın değiştirilmesi","Seçim sisteminin orantılı temsile geçmesi"]$json$::jsonb, 1, $$Demokratik konsolidasyon; seçimlerin, hukukun üstünlüğünün ve sivil özgürlüklerin tüm aktörler tarafından içselleştirildiği ve dönüşüme kapalı bir demokrasi olgunluğunu ifade eder.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'İkinci Dünya Savaşı ve Türkiye' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkiye''nin İkinci Dünya Savaşı''ndaki askeri operasyonları","Türkiye''nin İkinci Dünya Savaşı süresince izlediği tarafsızlık politikası ve bu politikanın ulusal çıkarlar temelindeki gerekçeleri","Türkiye''nin müttefik olarak savaşa katılma süreci","Türkiye''nin Almanya ile ticari ilişkileri"]$json$::jsonb, 1, $$Metin; Türkiye''nin savaş boyunca tarafsız kalma kararını, İngiltere-Almanya arasında denge politikasını ve bu tutumun iç politikaya yansımalarını ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'İkinci Dünya Savaşı ve Türkiye' LIMIT 1), 'detail', $$"Varlık Vergisi" uygulaması hangi yılda hayata geçirilmiş ve kimler üzerinde ağır bir yük oluşturmuştur?$$, $json$["1938; tüm Türk vatandaşları","1942; başta gayrimüslim azınlıklar, yabancı uyruklu tüccarlar ve Dönmeler olmak üzere varlıklı nüfus","1950; çiftçiler ve köylüler","1945; kamu görevlileri"]$json$::jsonb, 1, $$1942''de uygulanan Varlık Vergisi; gayrimüslimlere orantısız vergi yükü bindiren, servetlerine el konulmasına ya da zorunlu çalışmaya yol açan ayrımcı bir uygulamadır.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'İkinci Dünya Savaşı ve Türkiye' LIMIT 1), 'detail', $$Türkiye''nin savaşın son aşamasında (Şubat 1945) Almanya''ya savaş ilan etmesinin temel nedeni nedir?$$, $json$["Almanya''nın Türk topraklarına saldırması","San Francisco BM Konferansı''na katılabilmek ve Batı ittifakıyla ilişkileri güçlendirmek için müttefiklerin talebini kabul etmesi","Sovyetler''in baskısından kurtulmak","Müttefiklerin askeri desteğini sağlamak"]$json$::jsonb, 1, $$Türkiye, Mart 1945''teki BM Konferansı''na katılma koşulunu yerine getirmek amacıyla Şubat 1945''te sembolik nitelikte Almanya ve Japonya''ya savaş ilan etmiştir.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'İkinci Dünya Savaşı ve Türkiye' LIMIT 1), 'inference', $$Türkiye''nin savaş boyunca tarafsız kalması uzun vadede nasıl değerlendirilebilir?$$, $json$["Bu politika Türkiye''yi uluslararası arenada tamamen yalnızlaştırmıştır","Tarafsızlık; Türkiye''nin savaş yıkımından korunmasını sağlamış, ancak Batı ittifakına gecikmiş katılım ve ekonomik sıkıntılar gibi bedelleri de beraberinde getirmiştir","Bu politika Türkiye''yi büyük bir askeri güce dönüştürmüştür","Tarafsızlık uluslararası toplum tarafından tam olarak onaylanmıştır"]$json$::jsonb, 1, $$Stratejik tarafsızlık, Türkiye''yi yıkımdan korumuş; ancak savaş sonrası düzenin şekillenmesinde etkisizliğe ve Batılı ittifakın güveninden kısmen uzak kalmaya yol açmıştır.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'İkinci Dünya Savaşı ve Türkiye' LIMIT 1), 'vocabulary', $$Metinde geçen "aktif tarafsızlık" politikası ne anlama gelir?$$, $json$["Savaşa aktif olarak katılmak","Her iki tarafla siyasi ve ekonomik ilişkileri sürdürürken resmen savaş dışı kalmak","Yalnızca savunmaya yönelik ittifak anlaşmaları imzalamak","BM kararlarına uymak"]$json$::jsonb, 1, $$Aktif tarafsızlık; resmî olarak savaş dışında kalmayı sürdürürken hem müttefik hem de mihver güçlerle ilişkilerini dengeli biçimde yöneterek ulusal çıkarları maksimize etme politikasıdır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Millî Mücadele Dönemi ve Kurtuluş Savaşı' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Osmanlı Devleti''nin Birinci Dünya Savaşı''na katılma kararı","İşgal koşullarında başlatılan Millî Mücadele, Kurtuluş Savaşı''nın kazanılması ve Türkiye Cumhuriyeti''nin kuruluşu","Türk-Yunan ilişkilerinin tarihsel arka planı","Sevr Antlaşması''nın coğrafi sonuçları"]$json$::jsonb, 1, $$Metin; Mondros''tan Lozan''a uzanan süreçte Millî Mücadele''nin örgütlenmesini, cephelerini ve Cumhuriyet''in kuruluşunu ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Millî Mücadele Dönemi ve Kurtuluş Savaşı' LIMIT 1), 'detail', $$Türkiye Büyük Millet Meclisi hangi tarihte açılmıştır?$$, $json$["19 Mayıs 1919","23 Nisan 1920","29 Ekim 1923","10 Ağustos 1920"]$json$::jsonb, 1, $$TBMM, olağanüstü yetkilere sahip bir meclis olarak 23 Nisan 1920''de Ankara''da açılmıştır.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Millî Mücadele Dönemi ve Kurtuluş Savaşı' LIMIT 1), 'detail', $$Lozan Antlaşması''nın önemi nedir?$$, $json$["Osmanlı''nın Birinci Dünya Savaşı''ndaki yenilgisini resmileştirmesi","Türkiye''nin uluslararası arenada egemen ve tam bağımsız bir devlet olarak tanınması ve modern Türk devletinin sınırlarının belirlenmesi","Türk-Yunan nüfus mübadelesinin başlatılması","Boğazların Türk egemenliğine geçmesi"]$json$::jsonb, 1, $$1923''te imzalanan Lozan Antlaşması; Türkiye''nin uluslararası hukuk çerçevesinde egemenliğini ve toprak bütünlüğünü tanıyan, Misak-ı Millî sınırlarının temeli sayılan antlaşmadır.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Millî Mücadele Dönemi ve Kurtuluş Savaşı' LIMIT 1), 'inference', $$Mustafa Kemal''in Samsun''a çıkışını (19 Mayıs 1919) Millî Mücadele''nin başlangıcı olarak simgelemesi neyi vurgulamaktadır?$$, $json$["Bu tarihin Türk-Yunan savaşının başlangıcı olduğunu","Millî direniş hareketinin örgütsel ve siyasal anlamda bilinçli bir kadro tarafından başlatıldığını","Mondros Mütarekesi''nin imzalanma tarihiyle çakıştığını","Ankara''nın başkent olarak seçildiği tarihi"]$json$::jsonb, 1, $$19 Mayıs 1919, Millî Mücadele''nin Anadolu''da örgütlü bir direniş hareketi olarak bilinçle başlatıldığını simgelemektedir.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Millî Mücadele Dönemi ve Kurtuluş Savaşı' LIMIT 1), 'vocabulary', $$Metinde geçen "Misak-ı Millî" ne anlama gelir?$$, $json$["Osmanlı''nın son dönemi millet meclisinin tüzüğü","Türk milletinin elde tutulmasını tartışmasız kabul ettiği minimum toprak sınırlarını ve ulusal hedefleri belirleyen siyasi belge","Lozan görüşmelerinde kabul edilen ilk taslak antlaşma","Kurtuluş Savaşı''nda alınan en büyük muharebe"]$json$::jsonb, 1, $$Ocak 1920''de son Osmanlı Meclisi''nde kabul edilen Misak-ı Millî; Anadolu ve Doğu Trakya''yı kapsayan minimum ulusal toprak ve bağımsızlık taleplerini ortaya koymaktadır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Osmanlı Millet Sistemi' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Osmanlı''nın askeri teşkilatı","Osmanlı İmparatorluğu''nda dinî cemaatlere dayalı çoğulcu yönetim modeli olan millet sistemi","Osmanlı''da toprak yönetimi","Osmanlı ticaret hukuku"]$json$::jsonb, 1, $$Metin; Osmanlı''nın gayrimüslim ve Müslüman olmayan toplulukları kendi dini hukuku ve kurumlarıyla yönetmesine olanak tanıyan millet sistemini ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Osmanlı Millet Sistemi' LIMIT 1), 'detail', $$Millet sisteminde gayrimüslim cemaatler hangi alanlarda özerklikten yararlanmıştır?$$, $json$["Yalnızca ticari faaliyetlerde","Dinî ibadet, eğitim, aile hukuku (evlilik, miras) ve topluluk yönetimi gibi alanlarda","Osmanlı ordusu içindeki konumlarında","Tüm kamu yönetimi alanında"]$json$::jsonb, 1, $$Rum Ortodoks, Ermeni ve Yahudi milletleri; patrik ya da haham başları aracılığıyla kendi dinî hukuku, eğitim ve aile meselelerini yönetme hakkına sahipti.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Osmanlı Millet Sistemi' LIMIT 1), 'detail', $$19. yüzyılda Tanzimat reformları millet sistemini nasıl etkilemiştir?$$, $json$["Millet sistemini tamamen kaldırmıştır","Gayrimüslimlere teorik olarak Müslümanlarla eşit hukuki statü tanıyarak milleti daha bireyci bir vatandaşlık anlayışına doğru dönüştürmüştür","Millet sistemini resmî anayasal hüküm hâline getirmiştir","Yalnızca Yahudi milletini etkileyen değişiklikler getirmiştir"]$json$::jsonb, 1, $$1839 Tanzimat Fermanı ve 1856 Islahat Fermanı, gayrimüslimlere resmî eşitlik tanımış; bu süreç millet sistemini geleneksel kolektif özerklikten bireysel haklara dayalı bir modele doğru dönüştürmüştür.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Osmanlı Millet Sistemi' LIMIT 1), 'inference', $$Millet sisteminin modern çokkültürcülük tartışmalarıyla ilişkisi nasıl kurulabilir?$$, $json$["Millet sistemi modern çokkültürcülüğün birebir öncülüdür","Millet sistemi; modern çokkültürcülükten farklı biçimde dinî cemaatler üzerinden kolektif kimliği tanımış, bireysel haklar yerine topluluk haklarını ön plana çıkarmıştır","İki sistem arasında hiçbir kavramsal bağlantı yoktur","Millet sistemi liberal demokrasiden daha gelişmiş bir model sunmaktadır"]$json$::jsonb, 1, $$Millet sistemi; topluluk kimliğini dinî temelde örgütlemesi ve kolektif özerkliği esas almasıyla modern bireyci çokkültürcülükten ayrışmaktadır.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Osmanlı Millet Sistemi' LIMIT 1), 'vocabulary', $$Metinde geçen "zimmi" statüsü ne anlama gelir?$$, $json$["Osmanlı topraklarında yaşayan tüm gayrimüslimler","İslam hukuku çerçevesinde bir İslam devletinde yaşayan, vergi ödeyen ve belirli korumalardan yararlanan gayrimüslim tebaanın hukuki statüsü","Osmanlı''nın fethetttiği topraklarda askerlik görevinden muaf tutulan kişiler","Devşirme yoluyla seçilen ve saray hizmetinde görevlendirilen gençler"]$json$::jsonb, 1, $$Zimmi; İslam yönetimi altında can ve mülk güvencesi ile dinî ibadet hakkından yararlanan gayrimüslim topluluklara verilen hukuki statüdür.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Atatürk''ün Eğitim Reformları' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Osmanlı medrese eğitiminin başarıları","Atatürk''ün laik, evrensel ve ulusal bir eğitim sistemi kurmak amacıyla gerçekleştirdiği köklü reformlar","Türkiye''nin günümüz eğitim sorunları","Yükseköğretimin finansman modelleri"]$json$::jsonb, 1, $$Metin; Tevhid-i Tedrisat''tan alfabe devrimine, kız eğitiminin yaygınlaşmasından üniversite reformuna uzanan Atatürk dönemi eğitim dönüşümünü ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Atatürk''ün Eğitim Reformları' LIMIT 1), 'detail', $$Tevhid-i Tedrisat Kanunu''nun (1924) temel amacı nedir?$$, $json$["Üniversite eğitimini zorunlu kılmak","Tüm eğitim kurumlarını tek çatı altında, Millî Eğitim Bakanlığı''na bağlamak ve medreseleri kapatmak","Yabancı okullara devlet desteği sağlamak","Eğitimi yalnızca büyük şehirlerle sınırlandırmak"]$json$::jsonb, 1, $$Tevhid-i Tedrisat; dinî ve laik okul ikiliğine son vererek tüm eğitimi devlet denetimine almış, medreseleri kapatmış ve ulusal müfredatı standartlaştırmıştır.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Atatürk''ün Eğitim Reformları' LIMIT 1), 'detail', $$1928 harf devrimi Türk toplumunu nasıl etkilemiştir?$$, $json$["Arap alfabesine geçişi kolaylaştırmıştır","Latin alfabesine geçiş okuryazarlığı artırmış, ancak Osmanlı yazılı mirasına erişimi kesmiştir","Eğitimi tamamen İngilizce''ye taşımıştır","Okuma yazma oranı kısa sürede yüz yüze eğitimle %90''a ulaşmıştır"]$json$::jsonb, 1, $$Latin alfabesine geçiş öğrenmeyi kolaylaştırmış ve okuryazarlık oranlarının uzun vadede yükselmesine zemin hazırlamış; ancak Osmanlıca kaynaklara doğrudan erişimi kısıtlamıştır.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Atatürk''ün Eğitim Reformları' LIMIT 1), 'inference', $$Kız çocuklarının eğitimine verilen önemin en önemli uzun vadeli toplumsal sonucu nedir?$$, $json$["Yalnızca nüfus artışını teşvik etmiştir","Kadınların toplumsal ve mesleki hayata katılımını artırarak toplumsal cinsiyet eşitliğinin temeli atılmıştır","Geleneksel aile yapısını güçlendirmiştir","Erkek istihdamında azalmaya yol açmıştır"]$json$::jsonb, 1, $$Kız eğitiminin yaygınlaşması; kadınların yüksek öğrenim görmesinin, mesleki hayata girmesinin ve kamusal alanda yer almasının önünü açarak toplumsal dönüşümün motoru olmuştur.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Atatürk''ün Eğitim Reformları' LIMIT 1), 'vocabulary', $$Metinde geçen "Halk Evleri" ne anlama gelir?$$, $json$["Osmanlı döneminde kurulan geleneksel kütüphaneler","Cumhuriyet''in kuruluş yıllarında açılan, yetişkin eğitimi, kültürel faaliyetler ve yeni Türk kimliğinin yaygınlaştırılması amacıyla kullanılan çok işlevli kurumlar","Yükseköğretim veren kurumlar","Göçmen ailelere yönelik barınma tesisleri"]$json$::jsonb, 1, $$1932''de kurulan Halk Evleri; alfabe öğretimi, tiyatro, müzik ve konferanslar aracılığıyla Cumhuriyet değerlerini ve laik kültürü Anadolu''ya taşıyan sosyal-kültürel merkezlerdir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Besinlerin Sindirimi ve Emilimi' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Dolaşım sisteminin kalp yapısı","Besinlerin sindirim sisteminde parçalanması ve kana geçmesi","Solunum sisteminde oksijen taşınması","Boşaltım sisteminin görevleri"]$json$::jsonb, 1, $$Metin; besinlerin ağızdan başlayarak ince bağırsağa kadar nasıl kimyasal ve fiziksel olarak parçalandığını ve emildiğini anlatmaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Besinlerin Sindirimi ve Emilimi' LIMIT 1), 'detail', $$Proteinlerin sindirimini gerçekleştiren sindirim enzimi hangisidir?$$, $json$["Amilaz","Lipaz","Pepsin ve tripsin","Maltaz"]$json$::jsonb, 2, $$Proteinler; midede pepsin, ince bağırsakta pankreastan gelen tripsin ve kimotripsin enzimleriyle amino asitlere parçalanır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Besinlerin Sindirimi ve Emilimi' LIMIT 1), 'detail', $$Besinlerin emilimi ağırlıklı olarak hangi organda gerçekleşir?$$, $json$["Mide","Kalın bağırsak","İnce bağırsak","Karaciğer"]$json$::jsonb, 2, $$İnce bağırsakta bulunan villi ve mikrovilli yapıları yüzey alanını artırarak besinlerin kana ve lenf damarlarına emilimini sağlar.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Besinlerin Sindirimi ve Emilimi' LIMIT 1), 'inference', $$Safranın yağ sindirimindeki rolü ile ilgili aşağıdaki çıkarım hangisi doğrudur?$$, $json$["Safra yağları doğrudan sindirir","Safra bir enzim olmayıp yağ damlacıklarını küçülterek (emülsifikasyon) lipazın yüzeye erişimini kolaylaştırır","Safra yalnızca su çözünür vitaminlerin emiliminde görev alır","Safra ince bağırsakta üretilir"]$json$::jsonb, 1, $$Karaciğerde üretilen safra; yağ damlacıklarını emülsifiye ederek lipaz enziminin etkili çalışabileceği yüzeyi artırır.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Besinlerin Sindirimi ve Emilimi' LIMIT 1), 'vocabulary', $$Metinde geçen "peristaltizm" ne anlama gelir?$$, $json$["Sindirim enzimlerinin salgılanma mekanizması","Sindirim kanalı boyunca besinleri ilerletmek için kasların dalgalı kasılıp gevşemesi","Midenin asit salgılaması","Ağızda başlayan mekanik sindirim"]$json$::jsonb, 1, $$Peristaltizm; sindirim kanalı duvarındaki düz kasların koordineli kasılma-gevşeme hareketiyle besinleri ileriye doğru itmesini sağlayan mekanizmadır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Ekosistem ve Biyoçeşitlilik' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Yalnızca hayvan türlerinin sınıflandırılması","Ekosistemlerin yapısı, bileşenleri ve biyoçeşitliliğin önemi","Yağmur ormanlarının coğrafi konumu","Nesli tükenen hayvanların listesi"]$json$::jsonb, 1, $$Metin; üretici, tüketici ve ayrıştırıcıların oluşturduğu ekosistemleri ve biyoçeşitliliğin neden korunması gerektiğini ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Ekosistem ve Biyoçeşitlilik' LIMIT 1), 'detail', $$Bir ekosistemde madde döngülerinde en kritik rolü hangi canlı grubu üstlenir?$$, $json$["Üreticiler (bitkiler)","Birincil tüketiciler (otçullar)","Ayrıştırıcılar (bakteri ve mantarlar)","İkincil tüketiciler (etçiller)"]$json$::jsonb, 2, $$Ayrıştırıcılar; ölü organik maddeyi inorganik bileşenlere parçalayarak madde döngülerini tamamlar ve besinlerin tekrar üreticilere ulaşmasını sağlar.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Ekosistem ve Biyoçeşitlilik' LIMIT 1), 'detail', $$Biyoçeşitliliğin azalmasının en önemli nedeni hangisidir?$$, $json$["İklim değişikliği","Habitat kaybı ve parçalanması","İnvazif türlerin yayılması","Aşırı avlanma"]$json$::jsonb, 1, $$Bilimsel araştırmalar; ormansızlaşma, kentleşme ve tarım alanı açılması gibi habitat yıkımının tür yok oluşlarının en temel nedeni olduğunu göstermektedir.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Ekosistem ve Biyoçeşitlilik' LIMIT 1), 'inference', $$Bir ekosistemde anahtar tür (keystone species) ortadan kalktığında ne olur?$$, $json$["Sistem dengesini kolayca korur","Anahtar türün ekolojik rolü o kadar kritiktir ki yok olması besin ağını bozarak zincirleme türlerden kayıplara neden olabilir","Diğer türler hızla anahtar türün nişini doldurur","Yalnızca o türün avlarını etkiler"]$json$::jsonb, 1, $$Anahtar türler; enerji akışını ve popülasyon dengesini orantısız biçimde düzenlediklerinden yoklukları tüm ekosistemin işlevini tehlikeye atabilir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Ekosistem ve Biyoçeşitlilik' LIMIT 1), 'vocabulary', $$Metinde geçen "biyom" kavramı ne anlama gelir?$$, $json$["Tek bir türün yaşam alanı","Benzer iklim ve bitki örtüsüne sahip, geniş coğrafi ölçekli ekolojik bölge (tropikal yağmur ormanı, tundra vb.)","Bir göl ya da nehrin ekolojik sistemi","Küçük ölçekli laboratuvar ortamında oluşturulan yapay ekosistem"]$json$::jsonb, 1, $$Biyomlar; iklim, bitki örtüsü ve baskın fauna özellikleriyle tanımlanan geniş kara ya da su ekolojik bölgeleridir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Elektrik ve Manyetizma' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Işığın dalga boyunun ölçülmesi","Elektrik yükü, akım, gerilim, direnç ve manyetik alan arasındaki ilişkiler","Isı iletiminin madde boyunca yayılması","Kimyasal reaksiyonlarda enerji dönüşümü"]$json$::jsonb, 1, $$Metin; temel elektrik büyüklüklerini, Ohm yasasını ve elektrik-manyetizma ilişkisini açıklamaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Elektrik ve Manyetizma' LIMIT 1), 'detail', $$Ohm Yasası''na göre bir iletkendeki akım şiddeti nasıl hesaplanır?$$, $json$["Akım = Direnç × Gerilim","Akım = Gerilim / Direnç","Akım = Gerilim × Direnç","Akım = Direnç / Gerilim"]$json$::jsonb, 1, $$Ohm Yasası: I = V / R; akım (I), gerilim (V) ile doğru; direnç (R) ile ters orantılıdır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Elektrik ve Manyetizma' LIMIT 1), 'detail', $$Bir mıknatısın kuzey kutbundan çıkan manyetik alan çizgileri nereye gider?$$, $json$["Mıknatısın herhangi bir noktasına","Güney kutbuna","Mıknatısın orta noktasına","Çevredeki metal cisimlere"]$json$::jsonb, 1, $$Manyetik alan çizgileri dışarıda kuzeyden güneye, içeride güneyden kuzeye doğru kapalı döngüler oluşturur.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Elektrik ve Manyetizma' LIMIT 1), 'inference', $$Elektromanyetik indüksiyonun pratik uygulaması aşağıdakilerden hangisidir?$$, $json$["Pil üretimi","Elektrik jeneratörleri ve transformatörler","Güneş panelleri","LED ampuller"]$json$::jsonb, 1, $$Faraday''ın keşfettiği elektromanyetik indüksiyon; değişen manyetik alanın iletkenleğe akım üretmesidir. Jeneratörler ve transformatörler bu ilkeye dayalı çalışır.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Elektrik ve Manyetizma' LIMIT 1), 'vocabulary', $$Metinde geçen "iletken" ve "yalıtkan" kavramları arasındaki fark nedir?$$, $json$["İletkenler ısıyı, yalıtkanlar sesi engeller","İletkenler elektrik akımını kolayca geçirirken yalıtkanlar akımın geçişini engeller","Yalıtkanlar manyetik alan üretir, iletkenler üretmez","İkisi de aynı özelliğe sahiptir"]$json$::jsonb, 1, $$İletkenlerde serbest elektronlar akımı kolayca taşır (bakır, demir); yalıtkanlarda serbest elektron yoktur, akım geçemez (plastik, cam).$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Hücrenin Yapısı ve Organelleri' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Canlıların sınıflandırılması","Hücrenin temel yapısı, organelleri ve bu organellerin işlevleri","Fotosentezin kimyasal denklemleri","Virüslerin üreme mekanizması"]$json$::jsonb, 1, $$Metin; hücre zarından çekirdeğe kadar hücrenin yapısal bileşenlerini ve her birinin görevini ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Hücrenin Yapısı ve Organelleri' LIMIT 1), 'detail', $$Mitokondri hangi işlevi yerine getirir?$$, $json$["Protein sentezi","Hücresel solunum yoluyla ATP (enerji) üretimi","Hücre bölünmesini yönetme","Atık maddeleri hücre dışına atma"]$json$::jsonb, 1, $$Mitokondri; besinlerden oksijeni kullanarak ATP sentezleyen ve bu nedenle "hücrenin enerji santrali" olarak adlandırılan organeldir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Hücrenin Yapısı ve Organelleri' LIMIT 1), 'detail', $$Bitki hücresini hayvan hücresinden ayıran yapılar hangileridir?$$, $json$["Mitokondri ve ribozom","Hücre duvarı, kloroplast ve büyük merkezi koful","Çekirdek ve hücre zarı","Golgi aygıtı ve endoplazmik retikulum"]$json$::jsonb, 1, $$Bitki hücreleri; selüloz hücre duvarı, fotosentez yapan kloroplastlar ve hücre suyunu depolayan büyük merkezi koful ile hayvan hücrelerinden ayrılır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Hücrenin Yapısı ve Organelleri' LIMIT 1), 'inference', $$Ribozom sayısının fazla olduğu hücrelerin hangi işlevi yoğun biçimde gerçekleştirdiği söylenebilir?$$, $json$["Enerji depolama","Protein sentezi","DNA replikasyonu","Hücresel sinyal iletimi"]$json$::jsonb, 1, $$Ribozomlar protein sentezinin gerçekleştiği organellerdir; dolayısıyla ribozomu fazla olan hücreler yoğun protein sentezi yapan hücrelerdir (pankreas enzim salgılayan hücreler gibi).$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Hücrenin Yapısı ve Organelleri' LIMIT 1), 'vocabulary', $$Metinde geçen "osmoz" ne anlama gelir?$$, $json$["Hücre zarının tüm maddeleri geçirmesi","Suyun yarı geçirgen bir zar aracılığıyla düşük çözünen konsantrasyonlu bölgeden yüksek konsantrasyonlu bölgeye geçmesi","Besinlerin aktif taşınma ile hücreye alınması","Hücre zarının yırtılması"]$json$::jsonb, 1, $$Osmoz; suyun yarı geçirgen zardan çözünen madde konsantrasyonu düşük olan taraftan yüksek olan tarafa pasif difüzyonla geçişidir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Işığın Kırılması ve Optik Olaylar' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Sesin havada yayılması","Işığın farklı ortamlar arasında geçişinde yön değiştirmesi (kırılma) ve bununla ilgili optik olaylar","Radyoaktif bozunma","Manyetik alanların ışığa etkisi"]$json$::jsonb, 1, $$Metin; kırılma indisi, toplam iç yansıma ve mercek sistemi gibi optik olgularını ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Işığın Kırılması ve Optik Olaylar' LIMIT 1), 'detail', $$Işık seyrek ortamdan yoğun ortama geçerken normal ile arasındaki açı nasıl değişir?$$, $json$["Açı büyür","Açı küçülür","Açı değişmez","Işık yansır, ortamı geçemez"]$json$::jsonb, 1, $$Işık seyrekten yoğuna geçerken yavaşlar ve normala yaklaşır; bu nedenle kırılma açısı gelme açısından küçük olur.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Işığın Kırılması ve Optik Olaylar' LIMIT 1), 'detail', $$Gökkuşağı oluşumunda kırılmanın rolü nedir?$$, $json$["Güneş ışığı yağmur damlalarında yalnızca yansır","Güneş ışığı yağmur damlalarına girerken kırılır, her renk farklı açıyla ayrışır ve çıkışta tekrar kırılarak gökkuşağı oluşur","Gökkuşağı yalnızca yansıma ile açıklanır","Yağmur damlaları ışığın rengini değiştirir"]$json$::jsonb, 1, $$Beyaz güneş ışığı yağmur damlaları içinde kırılırken farklı dalga boyları farklı açılarda ayrışır (dağılım); bu da gökkuşağının renkli bantlarını oluşturur.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Işığın Kırılması ve Optik Olaylar' LIMIT 1), 'inference', $$Optik fiberin çalışma prensibi hangi olguya dayanır?$$, $json$["Kırılmaya","Toplam iç yansımaya","Girişim olayına","Kırınıma"]$json$::jsonb, 1, $$Optik fiber; ışığın yoğun ortamdan seyreğe geçişte kritik açıyı aşınca hiç kırılmadan tamamen yansıması (toplam iç yansıma) ilkesine dayanır.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Işığın Kırılması ve Optik Olaylar' LIMIT 1), 'vocabulary', $$Metinde geçen "kırılma indisi" ne anlama gelir?$$, $json$["Işığın bir engele çarptığında ne kadarının yansıdığının oranı","Işığın boşluktaki hızının o ortamdaki hızına oranı; ortamın optik yoğunluğunu gösterir","Merceklerin odak uzaklığı","Işığın dalga boyunun frekansla çarpımı"]$json$::jsonb, 1, $$Kırılma indisi (n = c/v); ışığın boşluktaki hızının ilgili ortamdaki hızına oranıdır ve değer ne kadar büyükse ortam o kadar optik yoğundur.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Technology in Our Daily Lives' LIMIT 1), 'main_idea', $$Bu metnin ana fikri nedir?$$, $json$["Teknoloji insanların sosyal ilişkilerini tamamen yok etmiştir","Teknoloji günlük yaşamı hem kolaylaştırmakta hem de bazı toplumsal sorunlara yol açmaktadır","Teknoloji yalnızca okul çağındaki çocukları etkiler","Teknolojik gelişmeler yalnızca zengin ülkelere fayda sağlar"]$json$::jsonb, 1, $$Metin; teknolojinin iletişimden sağlığa günlük hayatı dönüştürdüğünü ve beraberinde getirdiği riskleri dengeli biçimde ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Technology in Our Daily Lives' LIMIT 1), 'detail', $$Akıllı telefonların günlük hayata en belirgin katkısı nedir?$$, $json$["Fiziksel aktiviteyi artırması","İletişim, bilgiye erişim ve günlük görevleri tek bir cihazda birleştirme","Uyku kalitesini iyileştirmesi","Yüz yüze sosyal etkileşimi güçlendirmesi"]$json$::jsonb, 1, $$Akıllı telefonlar; arama, mesajlaşma, navigasyon, alışveriş ve bilgiye erişimi tek bir cihazda toplarken zamanı da daha verimli kullanmayı sağlamaktadır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Technology in Our Daily Lives' LIMIT 1), 'detail', $$"Screen time" (ekran süresi) ile ilgili en yaygın kaygı nedir?$$, $json$["Ekranların göz yaşı salgısını artırması","Uzun süreli ekran kullanımının özellikle çocuklarda dikkat sorunları, uyku bozuklukları ve fiziksel hareketsizliğe yol açması","Ekranların büyüyünce küçülmesi","Ekran süresinin dil öğrenimini kolaylaştırması"]$json$::jsonb, 1, $$Araştırmalar; yoğun ekran kullanımının dikkat süresini kısaltabildiğini, uyku kalitesini düşürebildiğini ve hareketsiz yaşama katkı sağlayabildiğini göstermektedir.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Technology in Our Daily Lives' LIMIT 1), 'inference', $$Metne göre, teknolojiyi sağlıklı biçimde kullanmak için en önemli tutum hangisidir?$$, $json$["Tüm teknolojik cihazları reddetmek","Teknolojiyi belirli sınırlar içinde bilinçli ve amaçlı kullanmak","Teknoloji kullanımını yalnızca iş saatleriyle sınırlamak","Çocukların teknolojiye hiç maruz kalmamasını sağlamak"]$json$::jsonb, 1, $$Metin; dijital okuryazarlık ve bilinçli kullanımın teknolojiyi bir araç olarak yaşamı zenginleştirmesine izin verdiğini ima etmektedir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Technology in Our Daily Lives' LIMIT 1), 'vocabulary', $$Metinde kullanılan "digital literacy" (dijital okuryazarlık) ne anlama gelir?$$, $json$["Yalnızca kod yazabilme becerisi","Dijital araç ve kaynakları eleştirel ve etkin biçimde kullanabilme becerisi","Sosyal medya hesabı yönetme","İnternet hızını ölçme kapasitesi"]$json$::jsonb, 1, $$Dijital okuryazarlık; çevrimiçi bilgiyi değerlendirme, teknolojiyi amaçlı kullanma ve dijital riskleri tanıma gibi becerileri kapsar.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Amaç ve Sonuç İlişkisi' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede fiil çekimi kuralları","Cümlelerde eylem ile amaç ya da sonuç arasındaki anlam ilişkilerinin kurulması","Sözcük türlerinin cümledeki görevleri","Noktalama işaretlerinin kullanımı"]$json$::jsonb, 1, $$Metin; "diye, için, amacıyla" gibi bağlayıcılarla kurulan amaç cümlelerini ve "bunun sonucunda, böylece" gibi ifadelerle kurulan sonuç cümlelerini örneklerle açıklamaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Amaç ve Sonuç İlişkisi' LIMIT 1), 'detail', $$"Sınava hazırlanmak için her gece düzenli çalıştı." cümlesinde altı çizili bölüm hangi anlam ilişkisini taşır?$$, $json$["Neden","Amaç","Sonuç","Koşul"]$json$::jsonb, 1, $$"İçin" bağlacı bu cümlede amacı (niçin çalıştığını) belirtmektedir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Amaç ve Sonuç İlişkisi' LIMIT 1), 'detail', $$"Çok yorulmuştu; bu yüzden erken uyudu." cümlesinde anlam ilişkisi nedir?$$, $json$["Amaç-eylem","Neden-sonuç","Koşul-sonuç","Zaman-eylem"]$json$::jsonb, 1, $$"Bu yüzden" bağlacı, önceki cümledeki nedeni (yorgunluk) ve ardından gelen sonucu (erken uyumak) birbirine bağlamaktadır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Amaç ve Sonuç İlişkisi' LIMIT 1), 'inference', $$Amaç cümleleri ile sonuç cümlelerini ayırt etmenin en güvenilir yolu nedir?$$, $json$["İkisi de aynı bağlaçlarla kurulur","Amaç cümlelerinde eylem gerçekleşmeden önceki istek ifade edilir; sonuç cümlelerinde ise eylem gerçekleştikten sonra ortaya çıkan durum aktarılır","Amaç cümleleri daima olumsuz fiil içerir","Sonuç cümleleri daima geçmiş zaman kipindedir"]$json$::jsonb, 1, $$Amaç cümleleri ileriye yönelik bir isteği; sonuç cümleleri ise gerçekleşmiş bir durumu aktarır; bağlaçlar ve zaman ilişkisi bu ayrımı belirler.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Amaç ve Sonuç İlişkisi' LIMIT 1), 'vocabulary', $$"Amacıyla" sözcüğü cümleye hangi anlamı katar?$$, $json$["Karşılaştırma","Niyet ve hedef","Zıtlık","Şart"]$json$::jsonb, 1, $$"Amacıyla" sözcüğü, gerçekleştirilen ya da gerçekleştirilecek eylemin hangi niyet ya da hedefle yapıldığını belirtir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Cümlede Anlam İlişkileri — Karma' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türk dili tarihindeki değişimler","Cümlelerde anlam ilişkilerinin (neden-sonuç, amaç, koşul, zıtlık vb.) karma biçimde ele alınması","Şiirde ses uyumu","Paragraf oluşturma kuralları"]$json$::jsonb, 1, $$Metin; farklı anlam ilişkilerinin aynı metinde bir arada nasıl kullanıldığını örnekleriyle ortaya koymaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Cümlede Anlam İlişkileri — Karma' LIMIT 1), 'detail', $$"Ama, fakat, ancak, oysa" bağlaçları hangi anlam ilişkisini kurar?$$, $json$["Neden-sonuç","Zıtlık ve karşılaştırma","Amaç","Koşul"]$json$::jsonb, 1, $$Bu bağlaçlar; iki cümle ya da öge arasında zıt ya da beklenmedik bir anlam ilişkisi kurar.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Cümlede Anlam İlişkileri — Karma' LIMIT 1), 'detail', $$"Eğer zamanında gelseydin, treni kaçırmazdın." cümlesinde anlam ilişkisi nedir?$$, $json$["Neden-sonuç","Koşul-sonuç","Amaç-eylem","Zaman-eylem"]$json$::jsonb, 1, $$"Eğer…-seydi" yapısı; gerçekleşmeyen bir koşulun sonucunu aktararak koşul-sonuç ilişkisi kurar.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Cümlede Anlam İlişkileri — Karma' LIMIT 1), 'inference', $$Bir metindeki bağlaçları doğru okumak neden önemlidir?$$, $json$["Bağlaçlar yalnızca yazım kurallarıyla ilgilidir","Bağlaçlar; cümleler arasındaki mantıksal ilişkiyi ortaya koyar ve metnin anlamını doğru kavramayı sağlar","Bağlaçlar fiillerin zamanını belirler","Bağlaçlar yalnızca şiir metinlerinde önem taşır"]$json$::jsonb, 1, $$Bağlaçlar metindeki argüman zincirini, nedenselliği ve zıtlığı işaret eder; yanlış yorumlanmaları metnin anlamını büyük ölçüde değiştirebilir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Cümlede Anlam İlişkileri — Karma' LIMIT 1), 'vocabulary', $$"Bunun yanı sıra" ifadesi cümleye hangi anlamı katar?$$, $json$["Zıtlık","Ek bilgi ve ekleme","Neden","Koşul"]$json$::jsonb, 1, $$"Bunun yanı sıra" bağlayıcısı, önceki düşünceye ek bilgi ya da düşünce eklemek için kullanılır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Dolaylı Anlatım ve Aktarma' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede özne-yüklem uyumu","Başkasının sözünü ya da düşüncesini doğrudan ya da dolaylı aktarmanın dil kuralları ve anlam farklılıkları","Atasözü ve deyimlerin metindeki işlevi","Sözcüklerin ses bilgisel özellikleri"]$json$::jsonb, 1, $$Metin; doğrudan aktarım (tırnak içinde birebir söz) ile dolaylı aktarım (ki, diye bağlaçlı dönüştürme) arasındaki farkı ve bu dönüşümde yaşanan anlam farklılıklarını ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Dolaylı Anlatım ve Aktarma' LIMIT 1), 'detail', $$"Ayşe, 'Yarın gelemeyeceğim.' dedi." cümlesi dolaylı anlatıma çevrildiğinde nasıl olur?$$, $json$["Ayşe, yarın gelemeyeceğimi söyledi.","Ayşe, yarın gelemeyeceğini söyledi.","Ayşe, yarın geleceğini söyledi.","Ayşe yarın gelmeyeceğim dedi."]$json$::jsonb, 1, $$Dolaylı anlatımda şahıs eki değişir: "gelemeyeceğim" (birinci şahıs) → "gelemeyeceğini" (üçüncü şahıs) + ki/diye kalıbı ya da "-eceğini söyledi" yapısı kullanılır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Dolaylı Anlatım ve Aktarma' LIMIT 1), 'detail', $$Doğrudan aktarımda hangi noktalama işareti kullanılır?$$, $json$["Noktalı virgül","İki nokta ve tırnak işareti","Sadece virgül","Parantez"]$json$::jsonb, 1, $$Doğrudan aktarımda iki nokta (:) konuşmayı girişten ayırır; tırnak işareti (" ") birebir alıntılanan sözcükleri çerçeveler.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Dolaylı Anlatım ve Aktarma' LIMIT 1), 'inference', $$Dolaylı anlatım kullanıldığında sözün özgünlüğünde ne tür değişiklikler yaşanabilir?$$, $json$["Hiçbir değişiklik olmaz","Şahıs ekleri, zaman ve vurgu değişebildiğinden söylenenlerin tam olarak aktarılmaması ya da yorum katılması riski doğabilir","Dolaylı anlatım her zaman daha doğru aktarımı sağlar","Dolaylı anlatım yalnızca yazılı metinlerde kullanılır"]$json$::jsonb, 1, $$Dolaylı aktarımda kişi, zaman ve tonlama dönüşümleri gerçekleştiğinden özgün söylem yorum katılarak değiştirilmiş olabilir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Dolaylı Anlatım ve Aktarma' LIMIT 1), 'vocabulary', $$Metinde geçen "aktarma" kavramı dilbilgisel bağlamda ne anlama gelir?$$, $json$["Metni başka bir dile çevirmek","Bir konuşmacının sözünü ya da düşüncesini başka bir bağlamda yeniden dile getirmek","Sözcükleri ses değerlerine göre sıralamak","Bir metni özetlemek"]$json$::jsonb, 1, $$Aktarma; bir kişinin sözünü, yazısını ya da düşüncesini doğrudan (birebir) veya dolaylı (yorumlanarak) başka bir bağlamda sunma eylemidir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Karşılaştırma ve Zıtlık İlişkisi' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede sıfat çekimi","Cümlelerde karşılaştırma ve zıtlık anlam ilişkilerinin bağlaçlar ve yapılar aracılığıyla kurulması","Fiilimsilerin cümledeki görevleri","Paragraf bütünlüğü"]$json$::jsonb, 1, $$Metin; "ama, oysa, aksine, buna karşın" gibi bağlaçlarla kurulan zıtlık ilişkisini ve "daha, -den çok" yapılarıyla oluşturulan karşılaştırmaları örnekler üzerinden açıklamaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Karşılaştırma ve Zıtlık İlişkisi' LIMIT 1), 'detail', $$"Ahmet çok çalıştı; oysa başarılı olamadı." cümlesinde hangi anlam ilişkisi vardır?$$, $json$["Neden-sonuç","Zıtlık (beklenmedik sonuç)","Amaç","Koşul"]$json$::jsonb, 1, $$"Oysa" bağlacı; birinci cümledeki eyleme karşın beklenenin tersinin gerçekleştiğini ifade ederek zıtlık/beklenmedik sonuç ilişkisi kurar.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Karşılaştırma ve Zıtlık İlişkisi' LIMIT 1), 'detail', $$"Kitap okumayı, film izlemekten daha çok severim." cümlesinde hangi anlam ilişkisi kurulmuştur?$$, $json$["Zıtlık","Karşılaştırma (üstünlük)","Koşul","Neden-sonuç"]$json$::jsonb, 1, $$"Daha çok" yapısı ile iki eylem arasında derece bakımından üstünlük karşılaştırması yapılmaktadır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Karşılaştırma ve Zıtlık İlişkisi' LIMIT 1), 'inference', $$Bir argümanda zıtlık bağlaçlarının yerinde kullanılması okuyucuya nasıl katkı sağlar?$$, $json$["Okuyucunun dikkatini dağıtır","Beklentilerin tersine döndüğü noktaları belirginleştirerek argümanı güçlendirir ve metnin mantığını netleştirir","Metni gereksiz yere uzatır","Okuyucuyu yanıltır"]$json$::jsonb, 1, $$Zıtlık bağlaçları; argümanda karşı görüşü ya da beklenmedik durumu işaret ederek düşüncenin nüanslı ve ikna edici biçimde sunulmasını sağlar.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Karşılaştırma ve Zıtlık İlişkisi' LIMIT 1), 'vocabulary', $$"Aksine" sözcüğü cümlede ne anlama gelir?$$, $json$["Ek bilgi sunar","Önceki ifadenin tersini, karşıtını vurgular","Benzerlik kurar","Koşul belirtir"]$json$::jsonb, 1, $$"Aksine" sözcüğü; önceki cümlede öne sürülen durumun tam zıttının doğru olduğunu güçlü biçimde vurgulamak için kullanılır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Karşılaştırma Yoluyla Anlam' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede ek-fiil kullanımı","Kavramların, nesnelerin ya da durumların benzerlik ve farklılıkları üzerinden anlatılmasında karşılaştırma tekniklerinin işlevi","Şiirde ölçü ve uyak","Metin türlerinin özellikleri"]$json$::jsonb, 1, $$Metin; benzetme, zıtlık ve derece karşılaştırması gibi tekniklerin anlam oluşturma ve okuyucu üzerinde ikna edici etki yaratmadaki rolünü ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Karşılaştırma Yoluyla Anlam' LIMIT 1), 'detail', $$"Onun sesi, bir bülbül gibi tatlıydı." cümlesinde karşılaştırma hangi amaçla kullanılmıştır?$$, $json$["İki sesin aynı olmadığını vurgulamak","Sesi somutlaştırmak ve okuyucuda bir izlenim yaratmak amacıyla benzetme (teşbih) yapılmıştır","Nesnel bir ölçüm sunmak","Karşıtlık oluşturmak"]$json$::jsonb, 1, $$Benzetme; soyut ya da yeni bir kavramı, okuyucunun tanıdığı somut bir unsurla ilişkilendirerek anlamı güçlendirir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Karşılaştırma Yoluyla Anlam' LIMIT 1), 'detail', $$Karşılaştırmalı cümlelerde "kadar" sözcüğü hangi ilişkiyi kurar?$$, $json$["Üstünlük derecesini","Eşitlik ya da benzerlik derecesini","Zıtlık","Neden-sonuç"]$json$::jsonb, 1, $$"Kadar" bağımsız karşılaştırma ögesi; iki şeyin belli bir nitelik açısından eşit ya da yakın derece taşıdığını ifade eder.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Karşılaştırma Yoluyla Anlam' LIMIT 1), 'inference', $$Yazarların karşılaştırmayı sık kullanmasının en temel sebebi nedir?$$, $json$["Metni kısaltmak için","Soyut ya da karmaşık kavramları somutlaştırmak, okuyucunun zihninde canlı imgeler oluşturmak ve ikna gücünü artırmak için","Dilbilgisi kurallarına uymak için","Edebi türleri birbirinden ayırt etmek için"]$json$::jsonb, 1, $$Karşılaştırmalar; okuyucunun anlamı daha hızlı kavramasına, soyut fikirleri zihinde canlandırmasına ve yazının etkisini hissetmesine yardımcı olur.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Karşılaştırma Yoluyla Anlam' LIMIT 1), 'vocabulary', $$Metinde geçen "benzetme (teşbih)" sanatı ne anlama gelir?$$, $json$["Bir kavramı kişileştirmek","Bir şeyi daha iyi açıklamak amacıyla aralarındaki benzerlik noktasından yararlanarak başka bir şeye benzetmek","Bir cümleyi olumsuz anlamda kullanmak","Sözün gerçek anlamının dışına çıkmak"]$json$::jsonb, 1, $$Teşbih; "gibi, sanki, kadar" gibi benzetme edatlarıyla ya da bunlar olmaksızın iki şeyin ortak niteliği üzerinden yapılan güçlü bir anlam sanatıdır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Koşul İfadeleri ve Cümle Yapısı' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede soru cümleleri","Koşul cümlelerinin yapısı, kullanılan ekler ve bu cümlelerin anlamsal özellikleri","Türkçede bağlaçların sınıflandırılması","Türkçenin tarihsel gelişimi"]$json$::jsonb, 1, $$Metin; "-se/-sa" koşul ekiyle ve "eğer, şayet" sözcükleriyle kurulan koşul cümlelerini anlam ve yapı bakımından ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Koşul İfadeleri ve Cümle Yapısı' LIMIT 1), 'detail', $$"Eğer erken kalkarsan, treni kaçırmazsın." cümlesinde koşul hangi eke dayanmaktadır?$$, $json$["-(y)arak","-(y)ınca","-sa/-se","-(y)ip"]$json$::jsonb, 2, $$Türkçede koşul kipi "-sa/-se" ekiyle kurulur; bu ek fiilin gerçekleşmesini öngörülen bir şarta bağlar.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Koşul İfadeleri ve Cümle Yapısı' LIMIT 1), 'detail', $$"Çalışsaydın, başarılı olurdun." cümlesi hangi tür koşul ilişkisi kurar?$$, $json$["Gerçekleşmesi mümkün koşul","Gerçekleşmemiş (varsayımsal/karşı olgusal) koşul","Tekrarlanan alışkanlık koşulu","Genel doğru bildiren koşul"]$json$::jsonb, 1, $$"-(y)saydı…-(y)ırdı" yapısı; gerçekleşmemiş bir koşulun geçmişe yönelik karşı olgusal sonucunu aktarır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Koşul İfadeleri ve Cümle Yapısı' LIMIT 1), 'inference', $$Koşul cümlelerinin günlük dildeki en yaygın işlevi nedir?$$, $json$["Geçmişte yaşanan olayları aktarmak","Belirli bir eylemin gerçekleşmesi için yerine getirilmesi gereken ön koşulları ya da varsayımları ifade etmek","Emirler vermek","Duygusal durum bildirmek"]$json$::jsonb, 1, $$Koşul cümleleri; tavsiye, uyarı, varsayım ve plan gibi durumlarda eylemin gerçekleşmesi için gerekli şartı belirtir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Koşul İfadeleri ve Cümle Yapısı' LIMIT 1), 'vocabulary', $$"Şayet" sözcüğü cümlede hangi işlevi üstlenir?$$, $json$["Sonuç bildirmek","Eğer anlamında koşul başlatmak ve varsayımı güçlendirmek","Zıtlık kurmak","Neden bildirmek"]$json$::jsonb, 1, $$"Şayet" sözcüğü "eğer" ile eş anlamlıdır; koşul cümlesini başlatarak varsayımsal ya da şarta bağlı bir anlamı pekiştirir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Koşul ve Amaç Cümlelerinde Anlam' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede ad tamlamaları","Koşul cümlelerinin amaç cümlelerinden yapısal ve anlamsal farkları","Türkçede sıfat fiil ekleri","Paragraf yazma teknikleri"]$json$::jsonb, 1, $$Metin; koşul (şart) ile amaç anlam ilişkilerinin hangi ekler ve bağlaçlarla kurulduğunu karşılaştırmalı biçimde açıklamaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Koşul ve Amaç Cümlelerinde Anlam' LIMIT 1), 'detail', $$"İyi bir üniversiteye girebilmek için çok çalıştı." cümlesindeki anlam ilişkisi hangisidir?$$, $json$["Neden-sonuç","Amaç","Koşul","Zaman"]$json$::jsonb, 1, $$"İçin" eki + mastar yapısı bu cümlede amacı belirtmektedir; eylem, belirtilen hedef doğrultusunda yapılmıştır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Koşul ve Amaç Cümlelerinde Anlam' LIMIT 1), 'detail', $$Koşul cümlesi ile amaç cümlesinin temel farkı nedir?$$, $json$["İkisi de aynı anlam ilişkisini kurar","Koşul cümlesi bir şartı; amaç cümlesi ise gerçekleştirilmek istenen hedefi ifade eder","Amaç cümleleri yalnızca emir kipinde kurulur","Koşul cümleleri her zaman olumsuz anlam taşır"]$json$::jsonb, 1, $$Koşul cümlesinde bir öncülün (şartın) sağlanması gerekir; amaç cümlesinde ise sonraki eylemin neden/hangi hedefle yapıldığı belirtilir.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Koşul ve Amaç Cümlelerinde Anlam' LIMIT 1), 'inference', $$"Eğer yeterince uyursan, daha verimli çalışırsın." cümlesinin amacı ifade etmek yerine koşul belirtmesinin kanıtı nedir?$$, $json$["Cümlede 'eğer' sözcüğü bulunmaktadır","Cümlede gerçekleşmesi belirsiz bir şarta bağlı sonuç bildiriliyor; eylem bir hedef için değil, belirli bir koşulun yerine getirilmesi durumunda gerçekleşiyor","Cümlede 'için' sözcüğü yoktur","Cümle geniş zaman kipiyle kurulmuştur"]$json$::jsonb, 1, $$Koşul cümlelerinde eylem belirli bir şartın gerçekleşmesine bağlıdır ve ön koşul-sonuç ilişkisi kurar; amaçta ise niyet ön plana çıkar.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Koşul ve Amaç Cümlelerinde Anlam' LIMIT 1), 'vocabulary', $$"Diye" sözcüğü amaç cümlelerinde hangi anlama gelir?$$, $json$["Neden-sonuç bağlantısı","Amacıyla, için; gerçekleştirilmek istenen hedefe yönelik yapılan eylemi ifade eder","Zıtlık ve karşıtlık","Zaman ilişkisi"]$json$::jsonb, 1, $$"Diye" bağlacı; özellikle konuşma dilinde "için, amacıyla" anlamında kullanılarak amaç ilişkisi kurar.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Neden ve Sonuç Bağlantısı' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede zaman eklerinin kullanımı","Cümlelerde neden-sonuç anlam ilişkisinin bağlaçlar ve yapılar aracılığıyla kurulması","Türkçede yüklem türleri","Yazıda paragraf düzeni"]$json$::jsonb, 1, $$Metin; "çünkü, bu yüzden, dolayısıyla, bunun sonucunda" gibi bağlayıcılarla kurulan neden-sonuç cümlelerini örneklerle ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Neden ve Sonuç Bağlantısı' LIMIT 1), 'detail', $$"Çünkü" bağlacı cümleye hangi anlamı katar?$$, $json$["Zıtlık","Sonucu ifade eder","Kendinden önceki yargının nedenini, gerekçesini sunar","Koşul bildirir"]$json$::jsonb, 2, $$"Çünkü" bağlacı, önceki cümlede ifade edilen sonucun ya da durumun gerekçesini, sebebini belirten bir neden bağlacıdır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Neden ve Sonuç Bağlantısı' LIMIT 1), 'detail', $$"Hava çok soğuktu; bu nedenle okul tatil edildi." cümlesinde nedensellik ilişkisi nasıl kurulmuştur?$$, $json$["İki bağımsız cümle birbirinden bağımsızdır","'Bu nedenle' bağlayıcısıyla birinci cümledeki durum (soğuk) ikinci cümledeki sonuca (tatil) neden olarak bağlanmıştır","'Bu nedenle' sözcüğü koşul ifade eder","Cümleler arasında zıtlık ilişkisi kurulmuştur"]$json$::jsonb, 1, $$"Bu nedenle / bu yüzden / dolayısıyla" bağlayıcıları; önceki cümlede açıklanan durumu sonraki cümlede gerçekleşen olayın nedeni olarak konumlandırır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Neden ve Sonuç Bağlantısı' LIMIT 1), 'inference', $$Bir metinde nedensellik bağlantılarını doğru okumak neden önemlidir?$$, $json$["Yalnızca bilimsel metinlerde önemlidir","Olaylar ya da durumlar arasındaki sebep-etki ilişkisini anlamak, metnin argümanını ve yazarın niyetini doğru yorumlamak için gereklidir","Nedensellik ilişkileri her zaman açıkça ifade edilir","Nedensellik yalnızca sözlü dilde kullanılır"]$json$::jsonb, 1, $$Nedensellik zincirini doğru takip etmek; yazarın öne sürdüğü argümanı, sonuçların neden kaçınılmaz ya da öngörülebilir olduğunu anlamayı sağlar.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Neden ve Sonuç Bağlantısı' LIMIT 1), 'vocabulary', $$"Dolayısıyla" sözcüğü metinde hangi işlevi üstlenir?$$, $json$["Zıtlık kurar","Önceki ifadeden mantıksal sonuç çıkarmak için kullanılır","Koşul belirtir","Ek bilgi ekler"]$json$::jsonb, 1, $$"Dolayısıyla" bağlayıcısı; önceki cümlede verilen bilgiden mantıksal olarak çıkan zorunlu sonucu, doğal devamı belirtir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Nesnellik ve Doğrulanabilir Bilgi' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçe metinlerde anlatım biçimleri","Nesnel (objektif) ve öznel (subjektif) yargıların ayırt edilmesi ile doğrulanabilir bilginin önemi","Yazıda paragraf bütünlüğü","Türkçede zaman kiplerinin anlamı"]$json$::jsonb, 1, $$Metin; nesnel bilginin kanıtlanabilir/doğrulanabilir niteliğini, öznel yargının ise kişisel görüşe dayandığını örneklerle karşılaştırmaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Nesnellik ve Doğrulanabilir Bilgi' LIMIT 1), 'detail', $$"Türkiye''nin yüzölçümü 783.562 km²dir." ifadesi hangi özelliği taşır?$$, $json$["Öznel yargı, çünkü kişisel değerlendirme içerir","Nesnel bilgi, çünkü ölçülebilir ve doğrulanabilir bir gerçeği aktarır","Sanı, çünkü kesin bilinmesi mümkün değildir","Görüş bildirme, çünkü farklı kaynaklarda farklı değerler yer alabilir"]$json$::jsonb, 1, $$Nesnel bilgi; ölçüm, gözlem ve deney yoluyla doğrulanabilir; kişiden kişiye değişmeyen olgusal gerçeği aktarır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Nesnellik ve Doğrulanabilir Bilgi' LIMIT 1), 'detail', $$"Bu film çok sıkıcıydı." ifadesi hangi özelliği taşır?$$, $json$["Nesnel bilgi, çünkü seyirci sayısıyla doğrulanabilir","Öznel yargı, çünkü kişisel beğeniye ve deneyime dayanır","Olgu bildirme","Bilimsel kanıt"]$json$::jsonb, 1, $$Öznel yargılar; bireysel deneyim, beğeni ve değer yargısına dayandığından kişiden kişiye değişebilir ve evrensel doğrulama gerektirmez.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Nesnellik ve Doğrulanabilir Bilgi' LIMIT 1), 'inference', $$Günlük hayatta nesnel ve öznel bilgiyi ayırt edebilmek neden önemlidir?$$, $json$["Yalnızca akademik çevrelerde önem taşır","Bilginin güvenilirliğini değerlendirmek, doğrulanmış gerçeklerle kişisel görüşleri ayırt etmek ve bilinçli karar vermek için gereklidir","Nesnel bilgi her zaman doğrudur, öznel bilgi her zaman yanlıştır","Ayrım yalnızca gazetecilik etiğini ilgilendirir"]$json$::jsonb, 1, $$Nesnel-öznel ayrımını yapabilen bireyler, bilgiyi eleştirel biçimde değerlendirebilir ve dezenformasyona karşı daha dirençli olabilir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Nesnellik ve Doğrulanabilir Bilgi' LIMIT 1), 'vocabulary', $$Metinde geçen "doğrulanabilirlik" ilkesi bilimsel açıdan ne anlama gelir?$$, $json$["Bir bilginin çoğunluk tarafından onaylanması","Bir önermenin gözlem, deney ya da ölçüm yoluyla gerçeklik değerinin sınanabilmesi","Bilginin yazılı bir kaynaktan alınması","Bilginin mantıklı görünmesi"]$json$::jsonb, 1, $$Doğrulanabilirlik; bir bilginin nesnel standartlara göre sınanabilmesi ve başkaları tarafından tekrarlanabilir yöntemlerle onaylanabilmesidir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Öznel Yargının Dile Yansıması' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede zamir kullanımı","Öznel yargıların cümle yapısına, sözcük seçimine ve anlatım biçimine nasıl yansıdığı","Türkçede ses uyumu kuralları","Metinde ana fikri bulma stratejileri"]$json$::jsonb, 1, $$Metin; "bence, kanımca, sanırım, güzel, iyi, kötü" gibi sözcük ve yapıların öznel yargıyı nasıl dile getirdiğini açıklamaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Öznel Yargının Dile Yansıması' LIMIT 1), 'detail', $$"Bence bu kitap çok değerli." cümlesinde öznel yargıyı gösteren unsur hangisidir?$$, $json$["'kitap' sözcüğü","'bence' sözcüğü ve 'değerli' sıfatı","'bu' işaret sıfatı","'çok' zarfı"]$json$::jsonb, 1, $$"Bence" sözcüğü kişisel görüşü; "değerli" sıfatı ise değer yargısını gösterir; ikisi birlikte cümlenin öznel niteliğini belirler.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Öznel Yargının Dile Yansıması' LIMIT 1), 'detail', $$Hangi cümle nesnel bir bilgiyi aktarmaktadır?$$, $json$["Bu sergi harikaydı.","Yönetmen bu filmi yanlış kurgula.","Fotosentez, bitkilerin güneş ışığını kullanarak besin üretmesi sürecidir.","O şarkı kulağa hoş gelmiyor."]$json$::jsonb, 2, $$Fotosentezin tanımı; ölçülebilir ve doğrulanabilir bir biyolojik gerçeği aktarmakta olup kişisel değerlendirme içermez.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Öznel Yargının Dile Yansıması' LIMIT 1), 'inference', $$Bir eleştiri yazısında öznel ve nesnel ifadelerin bir arada kullanılmasının amacı ne olabilir?$$, $json$["Okuyucuyu yanıltmak","Öznel değerlendirmelere nesnel kanıtlarla destek sağlayarak daha güçlü ve dengeli bir argüman oluşturmak","Yazıyı gereksiz yere uzatmak","Yalnızca duygusal tepki yaratmak"]$json$::jsonb, 1, $$İyi bir eleştiri; öznel yargılarını nesnel kanıtlar ve örneklerle destekleyerek okuyucuya hem kişisel görüşü hem de gerekçeyi birlikte sunar.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Öznel Yargının Dile Yansıması' LIMIT 1), 'vocabulary', $$"Kanımca" sözcüğü cümlede hangi anlama gelir?$$, $json$["Kesin olarak biliyorum ki","Benim görüşüme göre, bence; kişisel değerlendirmeyi belirtir","Bilimsel araştırmalara göre","Toplumun genel kanısına göre"]$json$::jsonb, 1, $$"Kanımca" sözcüğü; birinci tekil şahsın kişisel görüşünü, düşüncesini ya da değerlendirmesini aktardığını ifade eder.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Denklemler ve Eşitsizlikler' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Geometrik şekillerin alanları","Denklem ve eşitsizliklerin tanımı, çözüm yöntemleri ve günlük hayattaki uygulamaları","Olasılık hesapları","Üslü sayılar"]$json$::jsonb, 1, $$Metin; birinci dereceden denklem ve eşitsizliklerin matematiksel yapısını, çözüm kümelerini ve gerçek hayat problemlerine uygulanmasını ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Denklemler ve Eşitsizlikler' LIMIT 1), 'detail', $$"2x + 5 = 13" denkleminin çözümü nedir?$$, $json$["x = 4","x = 9","x = 3","x = 6"]$json$::jsonb, 0, $$2x = 13 - 5 = 8, x = 4.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Denklemler ve Eşitsizlikler' LIMIT 1), 'detail', $$Bir eşitsizlikte her iki taraf negatif sayıyla çarpılırsa ne olur?$$, $json$["Eşitsizlik işareti değişmez","Eşitsizlik işareti tersine döner","Eşitsizlik denklem hâline gelir","Çözüm kümesi boşalır"]$json$::jsonb, 1, $$Eşitsizliğin her iki tarafı negatif sayıyla çarpılır veya bölünürse eşitsizlik işareti (<, >) ters yöne döner; bu temel kural ihlali yanlış çözüme yol açar.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Denklemler ve Eşitsizlikler' LIMIT 1), 'inference', $$Bir sayının 3 katının 7 fazlası 22''den küçük olduğuna göre bu sayı için en uygun tanım hangidir?$$, $json$["x > 5","x < 5","x ≥ 5","x ≤ 5"]$json$::jsonb, 1, $$3x + 7 < 22 → 3x < 15 → x < 5.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Denklemler ve Eşitsizlikler' LIMIT 1), 'vocabulary', $$"Çözüm kümesi" matematiksel bağlamda ne anlama gelir?$$, $json$["Bir denklemde yalnızca tam sayı olan sonuçlar","Bir denklem veya eşitsizliği sağlayan tüm x değerlerinin kümesi","Denklemin yalnızca pozitif çözümleri","Denklemi sağlamayan değerlerin kümesi"]$json$::jsonb, 1, $$Çözüm kümesi; denklem ya da eşitsizlikte yerine koyulduğunda ifadeyi doğru kılan tüm değerlerin toplamıdır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Olasılık ve İstatistik' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Cebir ve denklem çözümleri","Rastgele olayların sayısal olarak ifadesi (olasılık) ve veri toplulukları için merkezi eğilim ve dağılım ölçüleri (istatistik)","Geometrik dönüşümler","Trigonometri"]$json$::jsonb, 1, $$Metin; olasılığın temel tanımını, örnek uzayı kavramını ve ortalama, ortanca, tepe değer gibi istatistiksel ölçüleri ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Olasılık ve İstatistik' LIMIT 1), 'detail', $$Bir madeni para atıldığında yazı gelme olasılığı nedir?$$, $json$["1/4","1/3","1/2","2/3"]$json$::jsonb, 2, $$Bir madalyonun iki eşit olası yüzü (yazı ve tura) vardır; yazı gelme olasılığı = 1/2''dir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Olasılık ve İstatistik' LIMIT 1), 'detail', $$5, 8, 6, 9, 7 sayılarının aritmetik ortalaması nedir?$$, $json$["6","7","8","9"]$json$::jsonb, 1, $$(5+8+6+9+7) / 5 = 35 / 5 = 7.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Olasılık ve İstatistik' LIMIT 1), 'inference', $$Bir veri setinde aritmetik ortalama ile ortancanın birbirinden çok farklı olması ne anlama gelir?$$, $json$["Veri seti hatalıdır","Veri setinde aşırı uç değerler (outlier) bulunmaktadır; ortalama bu değerlerden etkilenirken ortanca etkilenmez","Veri sayısı yeterince fazladır","Standart sapma sıfırdır"]$json$::jsonb, 1, $$Ortalama aşırı değerlere duyarlıdır; ortanca ise yalnızca sıralı listedeki ortadaki değeri gösterdiğinden aşırı değerlerden etkilenmez.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Olasılık ve İstatistik' LIMIT 1), 'vocabulary', $$"Örneklem" istatistiksel bağlamda ne anlama gelir?$$, $json$["Çalışmanın bütün amacı","İstatistiksel çıkarım yapmak amacıyla büyük bir evrenden seçilen daha küçük ve temsili veri grubu","Veri setindeki en küçük değer","Olasılık hesaplamalarında kullanılan formül"]$json$::jsonb, 1, $$Örneklem; tüm evreni incelemenin olanaksız ya da pratik olmadığı durumlarda evreni temsil etmek amacıyla seçilen alt kümedir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Coğrafi Bölgeleri' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkiye''de yalnızca tarım faaliyetleri","Türkiye''nin 7 coğrafi bölgesinin iklim, bitki örtüsü, nüfus ve ekonomik faaliyetler bakımından temel özellikleri","Türkiye''nin tarihsel sınır değişimleri","Türkiye''de demiryolu ağının dağılımı"]$json$::jsonb, 1, $$Metin; Karadeniz''den Güneydoğu Anadolu''ya her coğrafi bölgenin ayırt edici doğal ve beşeri özelliklerini ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Coğrafi Bölgeleri' LIMIT 1), 'detail', $$Türkiye''nin en geniş yüzölçümüne sahip coğrafi bölgesi hangisidir?$$, $json$["Karadeniz Bölgesi","Marmara Bölgesi","İç Anadolu Bölgesi","Doğu Anadolu Bölgesi"]$json$::jsonb, 3, $$Doğu Anadolu Bölgesi, yaklaşık 163.000 km² ile Türkiye''nin yüzölçümü bakımından en büyük coğrafi bölgesidir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Coğrafi Bölgeleri' LIMIT 1), 'detail', $$Ege Bölgesi''nin Türkiye tarımındaki önemi neden büyüktür?$$, $json$["Sert kıta iklimi tahıl tarımına uygundur","Akdeniz iklimi, zeytin, üzüm, incir ve tütün gibi yüksek değerli tarım ürünlerinin yetiştirilmesine elverişlidir","Bölgede büyük nehir ovaları tahıl üretimine ayrılmıştır","Ege Bölgesi''nde tarım yapılmaz"]$json$::jsonb, 1, $$Ege Bölgesi; ılık, yağışlı kışlar ve sıcak, kurak yazlarla tanımlanan Akdeniz iklimi sayesinde endüstri bitkilerinde Türkiye''nin önde gelen üretim merkezidir.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Coğrafi Bölgeleri' LIMIT 1), 'inference', $$Marmara Bölgesi''nin Türkiye nüfusunun yaklaşık üçte birini barındırmasının temel nedeni nedir?$$, $json$["Bölgenin iklimi sıcak olduğu için","İstanbul başta olmak üzere sanayileşmenin, ticaretin ve tarihi birikimin yarattığı güçlü ekonomik çekim gücü","Marmara''nın en geniş tarım arazilerine sahip bölge olması","Devlet yatırımlarının tarihsel olarak yalnızca bu bölgeye yapılmış olması"]$json$::jsonb, 1, $$Marmara Bölgesi; ülkenin sanayi, ticaret, lojistik ve kültürel merkezi olarak iş olanaklarının yoğunluğu nedeniyle göçü cezbetmektedir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Türkiye''nin Coğrafi Bölgeleri' LIMIT 1), 'vocabulary', $$"Beşeri coğrafya" kavramı ne anlama gelir?$$, $json$["Dağ ve nehir gibi fiziksel unsurları inceleyen coğrafya dalı","İnsan faaliyetleri, nüfus, yerleşme, ekonomi ve kültür gibi beşeri unsurlara odaklanan coğrafya dalı","Hava ve iklim sistemlerini inceleyen meteoroloji","Uzaktan algılama teknikleriyle harita çizme"]$json$::jsonb, 1, $$Beşeri coğrafya; insanların çevreyle etkileşimini, nüfus hareketlerini, şehirleri ve ekonomik etkinlikleri inceleyen coğrafyanın bir alt dalıdır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Anadolu Medeniyetleri' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türklerin Anadolu''ya göçünün anlatılması","Anadolu topraklarında tarih boyunca kurulan uygarlıkların siyasi, kültürel ve ekonomik mirası","Osmanlı İmparatorluğu''nun genişleme politikası","Eski Yunan''ın kültürel etkisi"]$json$::jsonb, 1, $$Metin; Hitit''ten Frig''e, Lidya''dan Urartular''a Anadolu''yu yurt edinen medeniyetlerin katkılarını ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Anadolu Medeniyetleri' LIMIT 1), 'detail', $$Hititler hangi alanda döneminin en ileri medeniyetlerinden biri sayılmıştır?$$, $json$["Denizcilik ve sömürgecilik","Demir işlemciliği ve dünya tarihinin ilk yazılı uluslararası antlaşmasını imzalamaları","Sulama kanalları ve baraj yapımı","Trigonometri ve astronomi"]$json$::jsonb, 1, $$Hititler; MÖ 1274''te Mısır ile imzalanan Kadeş Antlaşması ve demir metalurjisindeki uzmanlıkla anılır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Anadolu Medeniyetleri' LIMIT 1), 'detail', $$Lidyalıların dünya tarihine en önemli katkısı nedir?$$, $json$["Yazıyı bulmak","Madeni parayı icat etmek ve ticareti kolaylaştırmak","İlk demokrasi deneyimini yaşatmak","İlk hukuk kodeksini oluşturmak"]$json$::jsonb, 1, $$Lidyalılar; MÖ 7. yüzyılda elektron (altın-gümüş alaşımı) madeni para üretmiş ve dünya ticaret tarihini dönüştürmüştür.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Anadolu Medeniyetleri' LIMIT 1), 'inference', $$Anadolu''nun "medeniyetler beşiği" olarak adlandırılmasının en temel nedeni nedir?$$, $json$["Anadolu''nun küçük bir coğrafi alan olması","Anadolu''nun verimli topraklar, stratejik konum ve köprü rolü sayesinde tarih boyunca birbirini izleyen birçok büyük medeniyete ev sahipliği yapması","Anadolu''nun yalnızca Türklerin yurdu olması","Anadolu''da madenlerin çok bol bulunması"]$json$::jsonb, 1, $$Doğu-Batı ve Kuzey-Güney ticaret yollarının kesişiminde konumlanan Anadolu; tarih boyunca pek çok farklı medeniyete yurt olmuş, kültürel birikimini bir sonrakine aktarmıştır.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Anadolu Medeniyetleri' LIMIT 1), 'vocabulary', $$Metinde geçen "senkretizm" kültürel bağlamda ne anlama gelir?$$, $json$["Bir medeniyetin diğerini tamamen yok etmesi","Farklı kültürel, dinî ya da felsefi unsurların bir arada kaynaşarak yeni bir sentezi oluşturması","Ticaret yollarının güvenliğinin sağlanması","Toplumun yazıyı benimsemesi"]$json$::jsonb, 1, $$Senkretizm; farklı kültür ya da inanç sistemlerinin unsurlarının birleşerek özgün bir yeni bütün oluşturması sürecidir; Anadolu''nun kültürel katmanları bunun en zengin örneklerini barındırır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Osmanlı''nın Yükseliş Dönemi' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Osmanlı''nın kuruluşundan önceki Anadolu beylikleri","15-16. yüzyıllarda Osmanlı İmparatorluğu''nun askeri, siyasi ve kurumsal güce ulaşma süreci","Osmanlı''nın 18. yüzyıldaki gerileme nedenleri","Osmanlı-Safevi ilişkileri"]$json$::jsonb, 1, $$Metin; Fatih döneminden Kanuni dönemine Osmanlı''nın siyasi, askeri ve kurumsal açıdan zirveye ulaşmasını ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Osmanlı''nın Yükseliş Dönemi' LIMIT 1), 'detail', $$İstanbul''un fethinin (1453) Osmanlı İmparatorluğu için önemi nedir?$$, $json$["Osmanlı''nın ilk kez Avrupa''ya geçmesi","Bizans İmparatorluğu''na son verilerek doğu-batı ticaret yolları üzerinde Osmanlı denetiminin kurulması ve imparatorluğun yeni başkentinin belirlenmesi","Yeniçeri ordusunun kurulması","Devşirme sisteminin uygulamaya konması"]$json$::jsonb, 1, $$1453''te İstanbul''un fethiyle Bizans sona erdi; şehir Osmanlı başkenti oldu ve Boğazlar üzerindeki Osmanlı kontrolü ticaret yollarını köklü biçimde yeniden şekillendirdi.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Osmanlı''nın Yükseliş Dönemi' LIMIT 1), 'detail', $$Kanuni Sultan Süleyman döneminin Osmanlı tarihindeki yeri neden önemlidir?$$, $json$["Osmanlı bu dönemde Hindistan''ı fethetmiştir","Osmanlı bu dönemde Avrupa, Asya ve Afrika''ya yayılmış; hukuki ve kurumsal yapı zirveye ulaşmıştır","Bu dönemde Osmanlı''nın toprakları ilk kez küçülmüştür","Kanuni, ticaret yollarını Portekizlilere bırakmıştır"]$json$::jsonb, 1, $$Kanuni döneminde Osmanlı''nın en geniş sınırlara ulaştığı, Süleymaniye Külliyesi ile mimari zirvenin yaşandığı ve Kanunname ile hukuki düzenlemelerin tamamlandığı görülür.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Osmanlı''nın Yükseliş Dönemi' LIMIT 1), 'inference', $$Devşirme sisteminin Osmanlı''nın güçlenmesine katkısı nasıl değerlendirilebilir?$$, $json$["Devşirme sistemi yalnızca askeri güçsüzlüğün göstergesiydi","Yetenekli gençlerin eğitilerek yönetim ve orduya kazandırılması Osmanlı kurumsal kapasitesini güçlendirmiş, ama aynı zamanda kültürel gerilimi de beraberinde getirmiştir","Devşirme sistemi yalnızca dinî amaçlarla uygulandı","Sistem hiçbir işe yaramamış ve kısa sürede terk edilmiştir"]$json$::jsonb, 1, $$Devşirme; Osmanlı''nın yüksek nitelikli bürokratlar ve askerler yetiştirerek merkeziyetçi devlet yapısını güçlendirdiği, ancak aynı zamanda ailelerin çocuklarından koparılması nedeniyle sosyal gerilime yol açan bir sistemdi.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Osmanlı''nın Yükseliş Dönemi' LIMIT 1), 'vocabulary', $$Metinde geçen "tımar sistemi" ne anlama gelir?$$, $json$["Osmanlı''da toprak mülkiyetinin merkezi hazineye ait olduğu düzen","Devlet hizmetleri karşılığında asker ve yöneticilere belirli bir araziden vergi toplama hakkı tanınan Osmanlı toprak-asker sistemi","Osmanlı''da lonca teşkilatının yönetim biçimi","Saray içi görev dağılım düzeni"]$json$::jsonb, 1, $$Tımar sistemi; asker ya da yöneticiye belirli bir arazi gelirini tahsis ederek hem sipahi ordusunu finanse eden hem de devlete mali yük bindirmeyen Osmanlı tarım-askeriye düzeniydi.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türkçede Sözcük Türleri' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçenin tarihsel gelişimi","Türkçedeki sözcük türlerinin (isim, sıfat, zarf, fiil vb.) tanımı ve cümledeki işlevleri","Türkçede ses değişimleri","Türkçede yazım kuralları"]$json$::jsonb, 1, $$Metin; sözcüklerin anlamsal ve dilbilgisel niteliklerini tanımlayan sözcük türlerini örneklerle açıklamaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Türkçede Sözcük Türleri' LIMIT 1), 'detail', $$"Güzel" sözcüğü "Güzel çiçekler açmış." cümlesinde hangi görevdedir?$$, $json$["Zarf","İsim","Sıfat","Zamir"]$json$::jsonb, 2, $$"Güzel" sözcüğü "çiçekler" ismini nitelendirmektedir; bu işlevde bulunan sözcük sıfattır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Türkçede Sözcük Türleri' LIMIT 1), 'detail', $$"Hızlı koştu." cümlesinde "hızlı" hangi sözcük türündedir?$$, $json$["Sıfat","Zarf","İsim","Zamir"]$json$::jsonb, 1, $$Eylem (koştu) üzerinde etki yaparak nasıl koşulduğunu belirten "hızlı" sözcüğü bu cümlede zarf olarak kullanılmaktadır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Türkçede Sözcük Türleri' LIMIT 1), 'inference', $$Aynı sözcük farklı cümlelerde farklı görevler üstlenebilir mi?$$, $json$["Hayır, her sözcük yalnızca tek bir sözcük türüne aittir","Evet; bağlam ve cümle içindeki konumuna göre aynı sözcük isim, sıfat ya da zarf işleviyle kullanılabilir","Yalnızca fiiller farklı görevlerde bulunabilir","Yalnızca isimler farklı görevler alabilir"]$json$::jsonb, 1, $$Türkçede pek çok sözcük bağlama göre farklı sözcük türü işlevi görür; "güzel" hem isim hem sıfat hem de zarf olarak kullanılabilir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Türkçede Sözcük Türleri' LIMIT 1), 'vocabulary', $$Metinde geçen "zamir" sözcük türü ne anlama gelir?$$, $json$["Hareket bildiren sözcükler","İsimlerin yerini tutmak amacıyla kullanılan sözcükler (ben, sen, o, bu vb.)","Niteleme ve belirtme işlevi gören sözcükler","Sayıları gösteren sözcükler"]$json$::jsonb, 1, $$Zamirler; tekrar etmemek amacıyla isimlerin yerini tutan sözcüklerdir; kişi (ben, sen, o), işaret (bu, şu, o), soru (kim, ne) ve belgisiz (herkes, hiçbiri) olarak sınıflandırılır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Atalarımızdan Miras: Atasözleri' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçenin gramer yapısı","Atasözlerinin kültürel önemi, anlam özellikleri ve dildeki işlevi","Türk edebiyatında halk şiiri geleneği","Masalların çocuk gelişimine katkısı"]$json$::jsonb, 1, $$Metin; atasözlerinin kuşaklar boyu aktarılan deneyimleri kısa ve kalıcı ifadelerle nasıl dile getirdiğini ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Atalarımızdan Miras: Atasözleri' LIMIT 1), 'detail', $$"Damlaya damlaya göl olur." atasözünün iletmek istediği temel mesaj nedir?$$, $json$["Suyu tasarruflu kullanmak gerekir","Küçük ve sürekli çabaların zamanla büyük sonuçlar doğurabileceği","Göl kenarında yaşamak tehlikelidir","Yağmurlar birikince sel olur"]$json$::jsonb, 1, $$Bu atasözü; sabır ve süreklilik ile küçük birikimlerin zamanla büyük başarılara ulaştırabileceğini mecazi biçimde anlatır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Atalarımızdan Miras: Atasözleri' LIMIT 1), 'detail', $$Atasözlerini deyimlerden ayıran en temel özellik nedir?$$, $json$["Atasözleri yalnızca şiir biçiminde söylenir","Atasözleri genel bir deneyim ya da öğüt bildiren tam yargılardır; deyimler ise kalıplaşmış anlamlı söz öbeklerinden oluşur","Deyimler her zaman daha uzundur","Atasözleri yalnızca yazılı metinlerde bulunur"]$json$::jsonb, 1, $$Atasözleri yargı içeren, genel geçer bir deneyimi aktaran tam cümlelerdir; deyimler ise mecazi anlam taşıyan ancak yargı bildirmeyen kalıp sözcük gruplarıdır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Atalarımızdan Miras: Atasözleri' LIMIT 1), 'inference', $$Atasözlerinin sözlü kültürde yüzyıllar boyunca yaşamasının temel nedeni nedir?$$, $json$["Devlet tarafından öğretilmesi zorunluluğu","Kısa, akılda kalıcı ve evrensel insan deneyimlerine değinen yapıları sayesinde kolayca bellekte tutulabilir ve aktarılabilir olmaları","Atasözlerinin yalnızca belirli toplumsal sınıflar tarafından kullanılması","Atasözlerinin yabancı dillerden çevrilmiş olması"]$json$::jsonb, 1, $$Atasözleri; kısa, kafiyeli ya da ritimli yapıları ve geniş insan deneyimlerine temas etmeleri sayesinde sözlü bellekte kolayca yaşatılmaktadır.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Atalarımızdan Miras: Atasözleri' LIMIT 1), 'vocabulary', $$Metinde geçen "mecaz anlam" ne anlama gelir?$$, $json$["Sözcüğün sözlükteki ilk anlamı","Sözcüğün gerçek anlamının dışında, benzerlik ya da ilişki yoluyla kazandığı yeni anlam","Sözcüğün yabancı dilden gelmesi","Sözcüğün yalnızca yazılı dilde kullanılması"]$json$::jsonb, 1, $$Mecaz anlam; sözcüğün temel anlamının ötesine geçerek benzetme, çağrışım ya da duygu yoluyla kazandığı örtülü ve dolaylı anlamdır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Sözcüğün İki Yüzü' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede sözcük köklerinin tarihsel değişimi","Sözcüklerin gerçek (temel) ve mecaz (yan) anlam boyutları ile bunların dildeki işlevleri","Türkçede ek sistemi","Metinde tema ve motif kavramları"]$json$::jsonb, 1, $$Metin; sözcüklerin hem gerçek hem mecaz anlam taşıdığını, bağlamın hangi anlamın aktif olduğunu belirlediğini örneklerle ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Sözcüğün İki Yüzü' LIMIT 1), 'detail', $$"Soğuk" sözcüğü hangi cümlede mecaz anlamda kullanılmıştır?$$, $json$["Bugün hava soğuk.","Buzdolabındaki su soğuk.","O bana karşı son derece soğuk davrandı.","Kışın deniz suyu soğuk olur."]$json$::jsonb, 2, $$"Soğuk davrandı" ifadesinde "soğuk"; ısı değil, duygu uzaklığını (ilgisizliği) anlatmak için mecaz kullanılmıştır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Sözcüğün İki Yüzü' LIMIT 1), 'detail', $$Sözcüğün gerçek (temel) anlamı ile yan (mecaz) anlamı arasındaki fark nedir?$$, $json$["Gerçek anlam sözlükte yer alır, mecaz anlam hiçbir zaman sözlükte yer almaz","Gerçek anlam sözcüğün ilk, somut ve sözlük anlamıdır; yan anlam bağlama göre kazanılan mecazi ya da genişlemiş anlamdır","İkisi de her zaman aynı anlamı taşır","Mecaz anlam yalnızca şiirde kullanılır"]$json$::jsonb, 1, $$Temel anlam, sözcüğün doğrudan ve tarihsel ilk anlamıdır; yan anlam ise benzetme, çağrışım ya da aktarma yoluyla sözcüğün genişlediği ikincil anlamdır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Sözcüğün İki Yüzü' LIMIT 1), 'inference', $$Mecaz anlamların dile zenginlik kattığı hangi argümanla desteklenebilir?$$, $json$["Mecaz anlam dili anlaşılmaz kılar","Mecaz anlam; soyut duygu ve durumları somut imgelerle ifade etmeyi mümkün kılarak dilin anlatım gücünü ve çeşitliliğini artırır","Mecaz anlam yalnızca çocuk edebiyatında kullanılır","Mecaz anlam dilin yabancı dillerden etkilenmesinin kanıtıdır"]$json$::jsonb, 1, $$Mecaz kullanımlar; soyut kavramların görselleştirilmesini, duyguların somutlaştırılmasını ve dilin yaratıcı anlatım olanağını genişletmesini sağlar.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Sözcüğün İki Yüzü' LIMIT 1), 'vocabulary', $$Metinde geçen "ad aktarması (mecaz-ı mürsel)" ne anlama gelir?$$, $json$["Bir sözcüğü benzetme amacıyla başka sözcükle değiştirmek","Bir sözcüğü benzetme amacı gütmeksizin ilişkili başka bir kavramın yerine kullanmak (ör. 'Türkiye kazandı' ifadesinde Türkiye yerine milli takımı kastetmek)","İki sözcüğü anlamlarını birleştirerek kullanmak","Sözcüğün ses yapısının anlamına yansıması"]$json$::jsonb, 1, $$Ad aktarması; bir kavramı onunla ilişkili (parça-bütün, kap-içerik, neden-sonuç) başka bir kavramın adıyla ifade etme sanatıdır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Deyimlerin İzi' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede bağlaçların kullanımı","Deyimlerin tanımı, kalıplaşma özellikleri ve dilde mecaz anlam üretme işlevleri","Türk halk şiirinin biçimsel özellikleri","Türkçede ad tamlamalarının yapısı"]$json$::jsonb, 1, $$Metin; deyimlerin biçim ve anlam özelliklerini, atasözleriyle farklılıklarını ve günlük dildeki canlılığını ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Deyimlerin İzi' LIMIT 1), 'detail', $$"Kulak misafiri olmak" deyiminin anlamı nedir?$$, $json$["Bir toplantıya katılmak","Yanlışlıkla ya da farkında olmadan başkalarının konuşmasını duymak","Birine yardım etmek","Sır saklamak"]$json$::jsonb, 1, $$"Kulak misafiri olmak" deyimi; kasıtlı olmaksızın, tesadüfen başkalarının konuşmasını işitmek anlamına gelir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Deyimlerin İzi' LIMIT 1), 'detail', $$Deyimlerin en belirgin dil özelliği nedir?$$, $json$["Her sözcüğün gerçek anlamında kullanılması","Kalıplaşmış sözcük grubu olmaları; birleşik anlamlarının sözcüklerin ayrı ayrı anlamlarının toplamından farklı olması","Yalnızca fiil ile kurulmaları","Cümle içinde kullanılamamaları"]$json$::jsonb, 1, $$Deyimlerde sözcükler kalıplaşmış bir bütün oluşturur; bu bütünün mecaz anlamı parçaların bireysel anlamlarından çıkarılamaz.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Deyimlerin İzi' LIMIT 1), 'inference', $$Deyimlerin sözlükte tanımlanmasının önemi nedir?$$, $json$["Deyimler sözlükte yer almaz","Deyimlerin mecaz anlamları doğrudan çıkarılamadığından anlamlarının kayıt altına alınması dil öğrenenler ve yabancılar için zorunludur","Deyimler yalnızca şiirde kullanıldığı için sözlükte yer almaları gereksizdir","Deyimler yeterince açık anlamlı olduğu için sözlüğe ihtiyaç yoktur"]$json$::jsonb, 1, $$Deyimlerin mecaz anlamları önceden bilinmeden kavranamayacağından sözlüklerde belgelenmesi dil öğrenimi ve iletişim için kritik önem taşır.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Deyimlerin İzi' LIMIT 1), 'vocabulary', $$"Kalıplaşma" terimi deyimler bağlamında ne anlama gelir?$$, $json$["Deyimlerin tarihsel olarak değişmesi","Sözcüklerin anlam ve biçim bakımından sabit bir bütün oluşturarak söylemde bağımsızlıklarını yitirmesi","Deyimlerin yeni bağlaçlarla genişlemesi","Deyimlerin farklı şivelerde farklı biçimler alması"]$json$::jsonb, 1, $$Kalıplaşma; bir sözcük grubunun söylem içinde sabit bir form ve özel bir mecaz anlam kazanarak değiştirilemeyen bir dil birimi hâline gelmesidir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Söz Hazinesinden Birkaç İnci' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede ek fiil kullanımı","Türkçenin zengin söz varlığından seçilmiş çeşitli yapıların (atasözü, deyim, özdeyiş) anlam ve kullanım özellikleri","Türkçede cümle türleri","Türkçede dilbilgisel cinsiyet"]$json$::jsonb, 1, $$Metin; Türkçenin söz hazinesindeki deyim, atasözü ve özdeyişlerin anlam zenginliğini ve kültürel derinliğini örnekler üzerinden ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Söz Hazinesinden Birkaç İnci' LIMIT 1), 'detail', $$"Özdeyiş" nedir?$$, $json$["Halk geleneğinden gelen anonim öğütler","Genellikle bir yazara ya da düşünüre atfedilen, kısa ve özlü bir fikri dile getiren anlamlı söz","Bir dilin söz varlığındaki yabancı kökenli kelimeler","İki sözcüğün anlamca kaynaşarak oluşturduğu birleşik ad"]$json$::jsonb, 1, $$Özdeyiş (vecize/aforizma); genellikle ünlü bir kişiye atfedilen, kısa ama derin anlamlı düşünce cümlesidir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Söz Hazinesinden Birkaç İnci' LIMIT 1), 'detail', $$Söz varlığı bakımından zengin bir dil olmak ne anlama gelir?$$, $json$["Yalnızca çok sayıda kelimeye sahip olmak","Farklı kavramları ince ayrımlarla ifade eden, mecaz ve kültürel birikimi yansıtan çeşitli sözcük ve kalıplara sahip olmak","Yabancı dillerden en az sözcük almak","Gramer kurallarının basit olması"]$json$::jsonb, 1, $$Söz varlığı zenginliği; hem sayısal genişliği hem de kavramsal nüansları, kültürel derinliği ve mecaz üretme kapasitesini kapsar.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Söz Hazinesinden Birkaç İnci' LIMIT 1), 'inference', $$Özdeyiş ve atasözlerinin bir toplumun kültürel belleğindeki yeri nasıl değerlendirilebilir?$$, $json$["Bunlar yalnızca dil öğretiminde işe yarar","Ortak deneyimleri, değerleri ve yaşam bilgeliğini kısa ama yoğun biçimde aktararak toplumsal belleği ve kimliği şekillendirir","Bu ifadeler yalnızca yazılı kültüre aittir","Modern dünyada artık hiçbir önemi kalmamıştır"]$json$::jsonb, 1, $$Atasözleri ve özdeyişler; kuşaklar arası deneyim aktarımının ve ortak değer sisteminin en yoğun dilsel taşıyıcılarıdır.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Söz Hazinesinden Birkaç İnci' LIMIT 1), 'vocabulary', $$"Söz varlığı" kavramı dil bilimsel bağlamda ne anlama gelir?$$, $json$["Yalnızca gramer kurallarının toplamı","Bir dilin tüm sözcüklerini, deyimlerini, atasözlerini ve kalıp sözlerini kapsayan bütünsel kelime hazinesi","Bir dilin ses sistemi","Bir dilin yazı sistemi"]$json$::jsonb, 1, $$Söz varlığı; bir dilin tüm sözcüklerini, kalıplarını ve kültürel dil unsurlarını kapsayan, o dilin anlatım gücünü belirleyen bütünsel hazinedir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Bir Sözcüğün Bin Yüzü' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede ses uyumu kuralları","Tek bir sözcüğün farklı bağlamlarda birden fazla anlam taşıyabilmesi (çok anlamlılık)","Türkçede fiil çekimi","Türkçenin yabancı dillerle karşılaştırılması"]$json$::jsonb, 1, $$Metin; çok anlamlılık olgusunu, bağlamın anlamı belirlemedeki rolünü ve Türkçedeki örnekleri ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Bir Sözcüğün Bin Yüzü' LIMIT 1), 'detail', $$"Göz" sözcüğü Türkçede kaç farklı anlamda kullanılır?$$, $json$["Yalnızca biyolojik görme organı","Biyolojik organ, iğne gözü, çorap gözü, tuzak gözü gibi pek çok farklı bağlamda kullanılan çok anlamlı bir sözcüktür","Yalnızca mecaz anlamlarda kullanılır","Sadece iki anlamı vardır"]$json$::jsonb, 1, $$"Göz"; beden organı, iğne deliği, çorap halkası gibi 10''dan fazla anlam taşıyan Türkçenin en çok anlamlı sözcüklerinden biridir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Bir Sözcüğün Bin Yüzü' LIMIT 1), 'detail', $$Çok anlamlılık (polisemi) ile sesteşlik (eşseslilik) arasındaki fark nedir?$$, $json$["İkisi aynı anlama gelir","Çok anlamlı sözcükler kökensel olarak ilişkili farklı anlamlar taşır; sesteş sözcükler ise yazılış-söylenişleri aynı ama kökeni ve anlamı tamamen farklı sözcüklerdir","Eşseslilik yalnızca yabancı kökenli sözcüklerde görülür","Çok anlamlılık yalnızca fiillerde, sesteşlik yalnızca isimlerde görülür"]$json$::jsonb, 1, $$Polisemide farklı anlamlar aynı kökenden gelir ve anlam genişlemesiyle oluşur; homoforide ise sözcükler yalnızca ses benzerliği nedeniyle aynı biçimdedir, kökenleri farklıdır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Bir Sözcüğün Bin Yüzü' LIMIT 1), 'inference', $$Bir dilde çok anlamlı sözcüklerin fazla olmasının hem avantajı hem dezavantajı nedir?$$, $json$["Yalnızca avantajlıdır","Avantaj: az sözcükle geniş anlam alanı. Dezavantaj: bağlamdan kopuk kullanımda yanlış anlama riski","Yalnızca dezavantajlıdır","Ne avantajı ne dezavantajı vardır"]$json$::jsonb, 1, $$Çok anlamlılık; ekonomik bir dil kullanımı sağlarken bağlamın anlamı belirlemediği durumlarda yanlış yoruma kapı aralar.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Bir Sözcüğün Bin Yüzü' LIMIT 1), 'vocabulary', $$"Anlam genişlemesi" ne anlama gelir?$$, $json$["Sözcüğün anlamının tamamen değişmesi","Bir sözcüğün zaman içinde özgün anlamının yanı sıra yeni ve daha geniş anlamlar kazanması","Sözcüğün yabancı dilden Türkçeye geçmesi","Sözcüğün kullanımdan düşmesi"]$json$::jsonb, 1, $$Anlam genişlemesi; bir sözcüğün tarihsel süreç içinde özgün dar anlamının ötesine geçerek daha geniş kavram alanlarını kapsaması sürecidir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Karlı Bir Kış Sabahı' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Meteoroloji ve hava tahminleri","Karlı bir kış sabahının betimleyici anlatımı aracılığıyla doğanın insanda uyandırdığı duygular ve izlenimler","Kış mevsiminin tarımsal olumsuz etkileri","Soğuk iklim bölgelerinde yaşam koşulları"]$json$::jsonb, 1, $$Metin; kış sabahı tablosunu duyulara seslenen ayrıntılarla çizerek okuyucuda doğaya karşı derin bir duyarlılık uyandırmaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Karlı Bir Kış Sabahı' LIMIT 1), 'detail', $$Betimleyici metinlerde hangi anlatım tekniği ön plana çıkar?$$, $json$["Olayların kronolojik sırayla aktarılması","Duyulara (görme, işitme, koklama vb.) seslenen ayrıntılarla bir tablonun gözler önüne serilmesi","Nedenlerin ve sonuçların sıralanması","Karşıt görüşlerin karşılaştırılması"]$json$::jsonb, 1, $$Betimleme; yer, nesne ya da olayı canlı kılmak için görsel, işitsel, dokunsal ve koku gibi duyusal ayrıntıları işleyen anlatım biçimidir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Karlı Bir Kış Sabahı' LIMIT 1), 'detail', $$"Karların üzerine düşen ilk ışınlar kristalleri parlatıyordu." cümlesinde hangi edebi sanat vardır?$$, $json$["Abartma (mübalağa)","Kişileştirme","Benzetme","Teşbih (karla kristali benzetmek)"]$json$::jsonb, 3, $$Kar taneciklerini kristallere benzeterek sunan bu ifade, benzetme (teşbih) sanatı kullanmaktadır; "gibi" edatı olmasa da imge yoluyla benzetme yapılmaktadır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Karlı Bir Kış Sabahı' LIMIT 1), 'inference', $$Doğa betimlemelerinin edebi metinlerdeki işlevi ne olabilir?$$, $json$["Yalnızca bilgi vermek","Okuyucuda his ve imgeler uyandırarak atmosfer kurmak, kahramanın iç dünyasını yansıtmak ya da temayı güçlendirmek","Yalnızca bilimsel bilgi aktarmak","Bölümler arası geçişi sağlamak"]$json$::jsonb, 1, $$Doğa betimlemeleri; okuyucuyu mekâna yerleştirmekte, duygu tonu (atmosfer) yaratmakta ve kahramanın iç durumunu dışa yansıtmakta işlev görür.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Karlı Bir Kış Sabahı' LIMIT 1), 'vocabulary', $$Metinde geçen "haiku" ya da "imge" kavramı şiir bağlamında ne anlama gelir?$$, $json$["Şiirdeki uyak düzeni","Sözcüklerle oluşturulan zihinsel görüntü ya da duyusal tasarım; okuyucunun zihninde canlandırılan somut ya da soyut bir sahne","Şiirin nazım birimi","Şiirde tekrar eden ses grupları"]$json$::jsonb, 1, $$Şiirsel imge; sözcüklerin yarattığı zihinsel görüntü ya da duyusal deneyimdir; okuyucunun hayal gücünü harekete geçirerek metni canlı kılar.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Anlam Dünyasında Bir Gezinti' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede hece yapısı","Sözcüklerin, ifadelerin ve metinlerin anlam katmanları; anlam ilişkilerinin çeşitliği","Türkçede fiil çekimi tabloları","Noktalama işaretlerinin doğru kullanımı"]$json$::jsonb, 1, $$Metin; eş anlamlılık, karşıt anlamlılık, sesteşlik ve mecaz anlam gibi anlam ilişkilerini keşfederek dilin anlam evrenini tanıtmaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Anlam Dünyasında Bir Gezinti' LIMIT 1), 'detail', $$"Sevmek" sözcüğünün eş anlamlısı hangisidir?$$, $json$["Nefret etmek","Görmek","Sevda duymak / beğenmek","Bilmek"]$json$::jsonb, 2, $$Eş anlamlılar (eş değerler / sinonimler), birbirinin yerine kullanılabilen ve benzer anlam taşıyan sözcüklerdir; "sevmek" ve "sevda duymak/beğenmek" bu ilişkidedir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Anlam Dünyasında Bir Gezinti' LIMIT 1), 'detail', $$"Güzel" sözcüğünün karşıt anlamlısı hangisidir?$$, $json$["Hoş","Tatlı","Çirkin","Narin"]$json$::jsonb, 2, $$Karşıt anlamlılık (antonimy); birbirinin tam zıttı olan sözcükler arasındaki anlamsal ilişkidir; "güzel"in karşıtı "çirkin"dir.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Anlam Dünyasında Bir Gezinti' LIMIT 1), 'inference', $$Bir metni doğru anlamak için anlam ilişkilerini bilmek neden önemlidir?$$, $json$["Yalnızca yazarın biyografisini bilmek yeterlidir","Anlam ilişkileri; sözcük seçimini, ton farkını ve mecazları doğru yorumlayarak bütünsel metin anlamına ulaşmayı sağlar","Gramer kuralları bilinirse anlam ilişkileri önemsizdir","Anlam ilişkileri yalnızca şiir okuma için gereklidir"]$json$::jsonb, 1, $$Anlam ilişkilerini kavramak; yazarın sözcük tercihlerini, karşıtlık ve benzerlik üzerinden kurduğu argümanları ve mecazları doğru yorumlamayı mümkün kılar.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Anlam Dünyasında Bir Gezinti' LIMIT 1), 'vocabulary', $$Metinde geçen "sesteş (eşsesli) sözcükler" ne anlama gelir?$$, $json$["Aynı anlamı farklı sözcüklerle ifade eden kelimeler","Yazılışları ve söylenişleri aynı, ancak anlamları birbirinden tamamen farklı sözcükler (ör. kır-kır)","Kök anlamı aynı ama ekleri farklı sözcükler","Yalnızca şiirde kafiye oluşturan sözcükler"]$json$::jsonb, 1, $$Sesteş sözcükler; ses ve yazı biçimi özdeş olan ama köken ve anlam bakımından birbirinden bağımsız sözcüklerdir (ör. "yüz" = sayı / vücudun üst bölümü / yüzmek fiilinin kökü).$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Şehrin Nabzı' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Şehirlerdeki altyapı sorunları","Modern şehir yaşamının hızını, çeşitliliğini ve insan ilişkileri üzerindeki etkilerini yansıtan gözlemsel bir anlatı","Şehirlerin ekonomik kalkınma stratejileri","Kentsel dönüşüm projeleri"]$json$::jsonb, 1, $$Metin; şehrin koşuşturması, renkliliği ve insanların bu ritim içindeki yalnızlığı ya da aidiyet duygusunu betimleyici bir bakışla aktarmaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Şehrin Nabzı' LIMIT 1), 'detail', $$Şehir anlatılarında "kalabalık içinde yalnızlık" teması neyi simgeler?$$, $json$["Nüfus yoğunluğunun fazla olması","Şehirde çok sayıda insanla çevrili olmak rağmen anlamlı bağlardan yoksun hissetme paradoksu","Şehirdeki gürültü kirliliği","Şehrin nüfus hareketleri"]$json$::jsonb, 1, $$Şehrin büyük kalabalıkları yüzeysel etkileşimleri artırırken derin insan bağlarını zaman zaman aşındırmakta, bu da modern yalnızlık olgusunu doğurmaktadır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Şehrin Nabzı' LIMIT 1), 'detail', $$"Şehrin nabzı" metaforunda "nabız" sözcüğü hangi anlamda kullanılmıştır?$$, $json$["Gerçek anlamda, kan dolaşımı için","Şehrin canlılığını, ritimini ve sürekli hareket eden enerjisini anlatmak amacıyla mecaz anlamda","Tıbbi bir terimi açıklamak amacıyla","Şehir sakinlerinin sağlık durumunu belirtmek için"]$json$::jsonb, 1, $$"Nabız" sözcüğü burada kişileştirme yoluyla şehri canlı bir organizma gibi betimlemek, onun ritim ve dinamizmini ifade etmek için mecaz anlamda kullanılmaktadır.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Şehrin Nabzı' LIMIT 1), 'inference', $$Şehrin ritmine ilişkin gözlemler yazarın asıl neyi anlatmak istediğini ortaya koyabilir?$$, $json$["Şehirde yaşamak her zaman iyidir","Şehrin hızlı temposu insanları birbirinden uzaklaştırabilir; yazar bu ritim içinde anlamı, bağlılığı ya da kimliği sorgulamaktadır","Şehir yaşamı kırsal yaşamdan mutlaka daha iyi değildir","Yazarın şehirden şikayetçi olduğu"]$json$::jsonb, 1, $$Şehir betimlemelerindeki gözlemler çoğunlukla modernitenin yalnızlaştırıcı, kimliği aşındırıcı etkilerine ilişkin daha derin bir sorgulama içerir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Şehrin Nabzı' LIMIT 1), 'vocabulary', $$Metinde geçen "kişileştirme (teşhis)" sanatı ne anlama gelir?$$, $json$["İnsan dışı varlıklara ya da kavramlara insan nitelikleri, duyguları ya da eylemler yüklenmesi","Bir sözcüğün sesini anlama benzetmek","İki nesneyi açık biçimde karşılaştırmak","Bir olayı abartarak anlatmak"]$json$::jsonb, 0, $$Kişileştirme; doğa, nesne ya da soyut kavramlara insan özelliği atfederek onları daha canlı ve duygusal biçimde anlatmayı sağlayan bir edebi sanattır.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Bilimlerin Ortak Dili' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçenin yabancı sözcüklerden arındırılması","Bilimsel dilin nesnel, kesin ve evrensel olma gerekliliği ile bu özelliklerin dile yansıması","Şiirsel anlatımın özellikleri","Fen bilimlerindeki deney yazımı kuralları"]$json$::jsonb, 1, $$Metin; bilimsel metnin nesnel, terim odaklı ve tekrarlanabilir bilgiyi aktarma işlevini ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Bilimlerin Ortak Dili' LIMIT 1), 'detail', $$Bilimsel metinlerin sanatsal metinlerden en belirgin farkı nedir?$$, $json$["Bilimsel metinler daha kısa olur","Bilimsel metinler nesnel, kanıta dayalı ve teknik terimler içerirken sanatsal metinler öznel, imgeli ve duygusal anlatımı ön plana çıkarır","Sanatsal metinler daha zor anlaşılır","İkisi arasında hiçbir fark yoktur"]$json$::jsonb, 1, $$Bilimsel yazım; doğrulanabilir bilgiyi açık ve tekrarlanabilir biçimde aktarmayı amaçlarken sanatsal yazım duygu, imge ve bireysel perspektifi ön plana çıkarır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Bilimlerin Ortak Dili' LIMIT 1), 'detail', $$Matematik bilimsel dilin "evrensel ortak dili" olarak neden öne çıkmaktadır?$$, $json$["Matematiksel ifadeler yalnızca fizikçiler tarafından anlaşılır","Matematiksel gösterim; kültür ve dilden bağımsız, kesin ve evrensel bir iletişim aracı sunar","Matematik diğer bilimlerde hiç kullanılmaz","Matematiksel formüller her ülkede farklıdır"]$json$::jsonb, 1, $$Matematiksel semboller ve formüller, hangi ülkede ve hangi dil konuşulursa konuşulsun aynı anlama geldiğinden bilimler arası iletişimde evrensel köprü işlevi görür.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Bilimlerin Ortak Dili' LIMIT 1), 'inference', $$Bilimsel terimlerin gündelik dile girmesinin toplumsal sonuçları neler olabilir?$$, $json$["Gündelik dil bozulur","Toplumun bilimsel kavramları anlaması kolaylaşır; ancak terimlerin yanlış ya da yüzeysel kullanılmasıyla anlam kayması riski de doğar","Bilimsel terimlerin gündelik dile girmesi imkânsızdır","Yalnızca akademisyenleri etkiler"]$json$::jsonb, 1, $$Yaygınlaşan bilimsel terimler (DNA, algoritma, karantina vb.) kamusal söylemde bilim okuryazarlığını artırırken yanlış kullanımı da beraberinde getirebilir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Bilimlerin Ortak Dili' LIMIT 1), 'vocabulary', $$Metinde geçen "terim" sözcüğü dil bilgisel bağlamda ne anlama gelir?$$, $json$["Dilbilgisi kitabında geçen her sözcük","Belirli bir bilim, meslek ya da uzmanlık alanında özel ve kesin bir kavramı karşılamak için benimsenen sözcük ya da sözcük grubu","Atasözü ve deyimler","Mecaz anlam kazanmış sözcükler"]$json$::jsonb, 1, $$Terimler; bir alanda net tanıma sahip, bağlamdan bağımsız olarak aynı anlamı taşıyan ve uzmanlar arasında iletişim tutarlılığını sağlayan özel sözcüklerdir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Zıtlıkların Dili' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkçede ses uyumu","Karşıt anlamlı sözcüklerin dildeki işlevi, edebi metinlerdeki kullanımı ve anlam gücü","Türkçede fiilimsilerin türleri","Şiirde ölçü sistemi"]$json$::jsonb, 1, $$Metin; karşıt anlamlılığın anlam ilişkisini, edebi metinlerde tezat (antitez) sanatının nasıl kullanıldığını ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Zıtlıkların Dili' LIMIT 1), 'detail', $$Edebi metinlerde "tezat (antitez)" sanatı hangi işlevi üstlenir?$$, $json$["Metni gereksiz yere uzatır","Karşıt kavramların bir arada kullanılmasıyla anlam vurgusunu güçlendirir ve okuyucuda derin etki bırakır","Yalnızca şiirin uyak düzenini belirler","Metni anlaşılmaz kılar"]$json$::jsonb, 1, $$Tezat sanatı; ışık-karanlık, doğum-ölüm, sevinç-hüzün gibi karşıt kavramların aynı bağlamda kullanılmasıyla anlam derinliği ve duygusal yoğunluk yaratır.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Zıtlıkların Dili' LIMIT 1), 'detail', $$"Yaz-kış, gece-gündüz, aydınlık-karanlık" sözcük çiftleri hangi anlam ilişkisini örnekler?$$, $json$["Eş anlamlılık","Sesteşlik","Karşıt anlamlılık (antonimy)","Ad aktarması"]$json$::jsonb, 2, $$Bu sözcük çiftleri birbirinin tam zıttı olan kavramları gösterir ve dilde karşıt anlamlılık ilişkisini örnekler.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Zıtlıkların Dili' LIMIT 1), 'inference', $$Zıtlıkların dilde bu kadar sık kullanılmasının altında yatan temel neden nedir?$$, $json$["Yazarların başka sözcük bilmemesi","İnsan deneyimi büyük ölçüde karşıtlıklar üzerine kurulduğundan dil de bu yapıyı yansıtır; zıtlıklar anlam sınırlarını belirginleştirir","Zıtlıklar yalnızca şiirde kullanılır","Zıtlıklar dilbilgisi kurallarının zorunlu sonucudur"]$json$::jsonb, 1, $$İnsan kavramsal düşüncesi büyük ölçüde karşıtlık çiftleri üzerine kuruludur (iyi-kötü, sıcak-soğuk); dil bu bilişsel yapıyı yansıtır ve zıtlıkları anlam sınırlayıcı olarak kullanır.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Zıtlıkların Dili' LIMIT 1), 'vocabulary', $$Metinde geçen "paradoks" ne anlama gelir?$$, $json$["Birbirinden tamamen bağımsız iki cümle","Mantıksal olarak çelişkili görünen ama gerçek ya da derin bir doğruyu barındıran önerme","Aynı anlama gelen iki sözcük","Abartılı bir benzetme"]$json$::jsonb, 1, $$Paradoks; ilk bakışta saçma ya da çelişkili görünen ama içinde derin bir gerçek barındıran ifadedir (ör. "En güçlü olan affeden kişidir.").$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Demokrasi ve Temel Haklar' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Türkiye''nin seçim sistemi","Demokrasinin temel ilkeleri ile bireylerin devredilemez hakları arasındaki ilişki","Belediye yönetiminin işleyişi","Uluslararası kuruluşların yapısı"]$json$::jsonb, 1, $$Metin; halk egemenliği, hukukun üstünlüğü, azınlık hakları ve bireysel özgürlüklerin demokratik sistemdeki yerini ele almaktadır.$$, 2, 1),
((SELECT id FROM text_library WHERE title = 'Demokrasi ve Temel Haklar' LIMIT 1), 'detail', $$Demokratik yönetimin en temel ilkesi nedir?$$, $json$["Devletin her şeye kadir olması","Egemenliğin tek kişide toplanması","Egemenliğin kayıtsız şartsız millete ait olması ve halkın iradesinin seçimler yoluyla yönetimi belirlemesi","Yargı ile yasama organlarının tek elde birleşmesi"]$json$::jsonb, 2, $$Demokrasinin özü; egemenliğin millete ait olduğu, yöneticilerin seçimle belirlendiği ve hukukun üstünlüğünün güvence altında tutulduğu sistemdir.$$, 2, 2),
((SELECT id FROM text_library WHERE title = 'Demokrasi ve Temel Haklar' LIMIT 1), 'detail', $$Temel haklar hangi özelliği nedeniyle "devredilemez" sayılır?$$, $json$["Devlet istediğinde geri alabilir","İnsan onurunun ayrılmaz parçası olduklarından hiçbir koşulda bireyin elinden alınamaz ya da devir-alınıp-satılamaz","Yalnızca vatandaşlara tanınmış haklardır","Bu haklar yalnızca savaş dönemlerinde geçerlidir"]$json$::jsonb, 1, $$Temel haklar; evrensel insan onuruyla özdeşleştiği için hiçbir devlet eylemi ya da sözleşme yoluyla tamamen ortadan kaldırılamaz ya da devredilemez niteliktedir.$$, 2, 3),
((SELECT id FROM text_library WHERE title = 'Demokrasi ve Temel Haklar' LIMIT 1), 'inference', $$"Azınlık hakları" neden demokratik sistemin vazgeçilmez bir parçasıdır?$$, $json$["Azınlıklar daima çoğunluktan daha güçlüdür","Saf çoğunlukçu anlayış azınlıkları baskı altına alabileceğinden demokrasi, çoğunluk egemenliğini azınlık haklarına saygıyla dengelemek zorundadır","Azınlık hakları yalnızca etnik gruplara uygulanır","Azınlıklar özel yasalara ihtiyaç duymaz"]$json$::jsonb, 1, $$Demokrasi yalnızca çoğunluk yönetimi değil; azınlıkların temel haklarının da güvence altında tutulduğu bir sistemdir. Çoğunlukçuluk tek başına yeterli değildir.$$, 2, 4),
((SELECT id FROM text_library WHERE title = 'Demokrasi ve Temel Haklar' LIMIT 1), 'vocabulary', $$Metinde geçen "hukukun üstünlüğü" ilkesi ne anlama gelir?$$, $json$["En güçlünün her şeye karar verdiği düzen","Devlet de dahil olmak üzere tüm bireyler ve kurumların bağlayıcı hukuk kurallarına tabi olduğu ve kimsenin yasaların üzerinde yer almadığı düzen","Yasaların yalnızca vatandaşları bağladığı düzen","Yargı bağımsızlığı olmaksızın işleyen hukuk sistemi"]$json$::jsonb, 1, $$Hukukun üstünlüğü; devlet de dahil tüm bireylerin ve kurumların yasa önünde eşit olduğu, keyfi uygulamanın önlendiği temel demokratik ilkedir.$$, 2, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'DNA''nın Keşfi ve Genetik Devrim' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Evrim teorisinin tarihsel gelişimi","DNA yapısının keşfinden gen terapisine uzanan genetiğin tarihsel gelişimi ve biyoloji bilimine etkileri","Hücre bölünmesinin matematiksel modellenmesi","Protein sentezinin biyokimyasal ayrıntıları"]$json$::jsonb, 1, $$Metin; Watson-Crick çift sarmal modelinden CRISPR teknolojisine uzanan genetik devrimin kilometre taşlarını ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'DNA''nın Keşfi ve Genetik Devrim' LIMIT 1), 'detail', $$Watson ve Crick DNA''nın yapısını tanımlarken hangi araştırma verilerinden kritik biçimde yararlanmıştır?$$, $json$["Gregor Mendel''in bezelye deneyleri","Rosalind Franklin''in X-ışınları kırınım fotoğrafları","Louis Pasteur''ün mikrop teorisi","Thomas Morgan''ın meyve sineği deneyleri"]$json$::jsonb, 1, $$Rosalind Franklin''in "Fotoğraf 51" olarak bilinen X-ışını kırınım görüntüsü; DNA''nın çift sarmal yapısını doğrulamak için belirleyici kanıt sağlamıştır.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'DNA''nın Keşfi ve Genetik Devrim' LIMIT 1), 'detail', $$DNA''daki baz eşleşme kuralı (Chargaff kuralı) ne öngörür?$$, $json$["Adenin her zaman Sitozinle, Guanin her zaman Timinle eşleşir","Adenin (A) Timinle (T), Guanin (G) ise Sitozinle (C) eşleşir","Her iki sarmal aynı baz sırasını taşır","Baz eşleşmesi rastgele gerçekleşir"]$json$::jsonb, 1, $$Chargaff''ın bulduğu A=T ve G=C eşitliği, Watson-Crick çift sarmal modelinin temel kimyasal dayanağını oluşturmuştur.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'DNA''nın Keşfi ve Genetik Devrim' LIMIT 1), 'inference', $$CRISPR-Cas9 teknolojisinin genetik mühendisliği açısından en devrimci yönü nedir?$$, $json$["Yalnızca bakteri genomlarını değiştirmesi","Genom üzerinde son derece hassas, hızlı ve düşük maliyetli hedef odaklı düzenleme yapılabilmesini mümkün kılması","Tüm genleri aynı anda silmesi","Sadece tarımsal uygulamalarda kullanılabilmesi"]$json$::jsonb, 1, $$CRISPR; genoma belirli bir noktada makas gibi girip istenen değişikliği yapabildiğinden hastalık tedavisinden tarıma kadar geniş uygulama alanı olan bir gen düzenleme devrimi yaratmıştır.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'DNA''nın Keşfi ve Genetik Devrim' LIMIT 1), 'vocabulary', $$Metinde geçen "replikasyon" kavramı ne anlama gelir?$$, $json$["Proteinlerin hücre içinde taşınması","DNA''nın hücre bölünmesinden önce kendisinin aynısını oluşturarak kopyalanması süreci","mRNA''nın ribozomda protein üretmesi","Mutasyonun DNA''ya yansıması"]$json$::jsonb, 1, $$DNA replikasyonu; her hücre bölünmesinden önce çift sarmalın ayrılarak her sarmalın şablon görevi yaptığı ve özdeş iki DNA molekülünün oluştuğu süreçtir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Enzimler ve Metabolizma' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Virüslerin canlı hücreleri enfekte etme mekanizması","Enzimlerin yapısı, çalışma mekanizması ve metabolizmadaki temel rolleri","Hormonların kana salgılanma süreci","Osmozun hücre zarındaki mekanizması"]$json$::jsonb, 1, $$Metin; enzimlerin biyolojik katalizör olarak işlevini, etkinliklerini etkileyen faktörleri ve katabolizma-anabolizma süreçlerindeki rollerini ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Enzimler ve Metabolizma' LIMIT 1), 'detail', $$Enzimlerin "biyolojik katalizör" olarak tanımlanmasının nedeni nedir?$$, $json$["Reaksiyonlarda enerji üretirler","Reaksiyon sürecinde kendileri değişmeden kimyasal reaksiyon hızını büyük ölçüde artırırlar","Reaksiyonun yönünü değiştirirler","Substrat ile kalıcı kimyasal bağ oluştururlar"]$json$::jsonb, 1, $$Enzimler; aktivasyon enerjisini düşürerek reaksiyonu hızlandırır, ancak reaksiyon sonunda özgün yapılarını koruyarak yeniden kullanılabilirler.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Enzimler ve Metabolizma' LIMIT 1), 'detail', $$Sıcaklık enzimlerin aktivitesini nasıl etkiler?$$, $json$["Sıcaklık arttıkça enzim aktivitesi sürekli artar","Enzimler belirli bir optimum sıcaklıkta en yüksek aktivite gösterir; bu noktanın üzerinde sıcaklık artışı enzimi denatüre ederek aktiviteyi düşürür","Sıcaklık enzim aktivitesini hiç etkilemez","Düşük sıcaklık enzimleri kalıcı olarak bozar"]$json$::jsonb, 1, $$Her enzimin optimal çalışma sıcaklığı vardır; yüksek sıcaklıkta üç boyutlu yapısı bozulur (denatürasyon) ve aktif bölge işlevsiz hâle gelir.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Enzimler ve Metabolizma' LIMIT 1), 'inference', $$Enzimlerin "anahtar-kilit" modeli hangi temel ilkeyi yansıtmaktadır?$$, $json$["Enzimler her substratla etkileşime girebilir","Enzimlerin yüksek özgüllüğü; aktif bölgelerinin yalnızca belirli bir substratla geometrik olarak uyum sağlayarak bağlanmasından kaynaklanır","Enzim konsantrasyonu reaksiyon hızını belirlemez","Tüm enzimler aynı substratla çalışır"]$json$::jsonb, 1, $$Anahtar-kilit modeli; enzim aktif bölgesi ile substratın özgül üç boyutlu yapısal uyumunu ve bu uyumdan doğan seçici katalitik aktiviteyi açıklar.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Enzimler ve Metabolizma' LIMIT 1), 'vocabulary', $$Metinde geçen "inhibitör" ne anlama gelir?$$, $json$["Enzim aktivitesini artıran moleküller","Enzim aktivitesini azaltan ya da tamamen engelleyen moleküller","Substratı ürüne dönüştüren yardımcı maddeler","Enzimin üretildiği organeller"]$json$::jsonb, 1, $$Enzim inhibitörleri; aktif bölgeye ya da allosterik bölgeye bağlanarak reaksiyon hızını düşüren veya durduran moleküllerdir; pek çok ilaç bu prensiple çalışır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Sinir Sistemi ve Nöronlar' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Kas sisteminin yapısı ve kasılma mekanizması","Sinir sisteminin temel birimi olan nöronların yapısı, sinir iletimi ve sinaps mekanizması","Kan dolaşımının hormon taşıma işlevi","Endokrin bezlerin salgı mekanizması"]$json$::jsonb, 1, $$Metin; nöronların yapısını (dendrit, akson, miyelin kılıf), aksiyon potansiyelini ve sinaptik iletimi ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Sinir Sistemi ve Nöronlar' LIMIT 1), 'detail', $$Miyelin kılıfının nöron iletimindeki işlevi nedir?$$, $json$["Nörona besin sağlar","Sinir iletimini yavaşlatır","Aksiyon potansiyelinin atlama (Ranvier boğumları) yoluyla hızlı iletilmesini sağlar","Nöronlar arası bağlantıyı doğrudan kurar"]$json$::jsonb, 2, $$Miyelin; aksonun yalıtkan kılıfı olarak Ranvier boğumlarında atlayarak ilerleyen (sıçramalı iletim) ve bu sayede çok daha hızlı sinyal iletimini mümkün kılar.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Sinir Sistemi ve Nöronlar' LIMIT 1), 'detail', $$Sinaptik aralıkta nörotransmiterler nasıl çalışır?$$, $json$["Elektrik akımı doğrudan sinaptik aralığı geçer","Nörotransmiterler presinaptik nörondan serbest bırakılır, sinaptik aralığı geçer ve postsinaptik nörondaki reseptörlere bağlanarak uyarı ya da baskılama yanıtı oluşturur","Nöronlar fiziksel temas yoluyla iletişim kurar","Nörotransmiterler yalnızca inhibisyon sinyali taşır"]$json$::jsonb, 1, $$Kimyasal sinaps; veziküllerdeki nörotransmiterlerin ekzositozla aralığa bırakılması ve karşı nöronun reseptörüne bağlanarak iyon kanallarını açması/kapatmasıyla çalışır.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Sinir Sistemi ve Nöronlar' LIMIT 1), 'inference', $$Multiple skleroz (MS) hastalığının miyelin kılıfını tahrip etmesi hangi nörolojik sonuçlara yol açar?$$, $json$["Yalnızca hafıza kaybına neden olur","Sinir iletimi yavaşlar ya da kesilir; bu durum hareket, his ve koordinasyon bozukluklarına yol açar","Hastalık yalnızca otonom sinir sistemini etkiler","Miyelin kılıfı hasar görse de sinir iletimi etkilenmez"]$json$::jsonb, 1, $$MS; miyelin hasarı nedeniyle iletim hızının düşmesiyle güçsüzlük, uyuşma ve koordinasyon güçlüğü gibi belirtilerin ortaya çıkmasına neden olur.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Sinir Sistemi ve Nöronlar' LIMIT 1), 'vocabulary', $$Metinde geçen "aksiyon potansiyeli" ne anlama gelir?$$, $json$["Nöronun istirahat durumundaki zar voltajı","Nöronda eşik değeri aşıldığında başlayan, iyon kanallarının açılıp kapanmasıyla oluşan ve akson boyunca yayılan elektrik uyarısı","Nöronlar arası kimyasal iletişim","Sinir sisteminin toplam kapasitesi"]$json$::jsonb, 1, $$Aksiyon potansiyeli; eşik değer aşıldığında Na⁺ kanallarının açılmasıyla oluşan, "hep ya da hiç" yasasına göre yayılan elektriksel nöronal sinyal darbesidir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Cumhuriyet Dönemi Türk Şiiri' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Osmanlı divan şiirinin biçimsel özellikleri","Cumhuriyet döneminde Türk şiirinin toplumsal koşullar, akımlar ve önemli şairlerle birlikte geçirdiği dönüşüm","Halk şiiri geleneğinin modern şiire etkileri","Şiirde ölçü ve uyak sistemleri"]$json$::jsonb, 1, $$Metin; Garip hareketi, İkinci Yeni ve toplumcu gerçekçilik gibi akımlar çerçevesinde Cumhuriyet şiirinin çeşitliliğini ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Cumhuriyet Dönemi Türk Şiiri' LIMIT 1), 'detail', $$1940''lı yıllarda Orhan Veli, Melih Cevdet Anday ve Oktay Rifat öncülüğündeki "Garip hareketi"nin temel ilkesi nedir?$$, $json$["Divan şiirinin klasik biçimlerini canlandırmak","Şiiri sanat kaygısından ve ağdalı dilden arındırarak sıradan insanı ve gündelik yaşamı yalın bir dille şiirin merkezine taşımak","Hece ölçüsünü zorunlu kılmak","Toplumsal gerçekleri sembolist bir dille ele almak"]$json$::jsonb, 1, $$Garip şairleri; kafiye, ölçü ve klişe imgelerden arınmış, sokaktaki insanın dilini kullanan yalın ve serbest bir şiir anlayışı benimsemiştir.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Cumhuriyet Dönemi Türk Şiiri' LIMIT 1), 'detail', $$Nazım Hikmet''in Türk şiirine en önemli katkısı nedir?$$, $json$["Divan geleneğini yeniden canlandırması","Serbest nazımı ve toplumcu gerçekçi temayı birleştirerek Türk şiirinde biçim ve içerik devrimini başlatması","Haiku biçimini Türkçeye uyarlaması","Yalnızca aşk şiiri yazması"]$json$::jsonb, 1, $$Nazım Hikmet; serbest nazımla emek, özgürlük ve toplumsal adalet temalarını işleyerek Türk şiirinin hem biçimsel hem içeriksel sınırlarını genişletmiştir.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Cumhuriyet Dönemi Türk Şiiri' LIMIT 1), 'inference', $$"İkinci Yeni" hareketi neden okuyucuyu zorlayan soyut bir şiir dili benimsemiştir?$$, $json$["Şairlerin Türkçeye yabancı olmasından","Anlamı şiirin yüzeyinde değil derinliğinde bırakan, imgeler arası ilişkilerin yoruma açıldığı kapalı bir dil anlayışını benimseyerek şiiri salt söylevden kurtarmak için","Sansürü aşmak için şifreli bir dil kullanmak amacıyla","Garip hareketini aynen sürdürmek için"]$json$::jsonb, 1, $$İkinci Yeni; şiiri bir anlam bildirme aracı olmaktan çıkarıp bir dil ve imge deneyimine dönüştürmeyi amaçlamış; sürrealizm ve varoluşçuluktan beslenerek kapalı, çok katmanlı bir şiir anlayışını egemen kılmıştır.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Cumhuriyet Dönemi Türk Şiiri' LIMIT 1), 'vocabulary', $$Metinde geçen "serbest nazım" ne anlama gelir?$$, $json$["Hece ölçüsüne uyan ama uyaksız şiir","Belirli bir ölçü ve uyak zorunluluğu olmaksızın yazılmış; dizeyi ve yapıyı şairin biçimsel kısıtlamalar yerine anlam ve ritim kaygısıyla belirlediği şiir biçimi","Yalnızca kafiyeli ve düzenli dize diziliminden oluşan şiir","Nesirle şiir arasında bir tür"]$json$::jsonb, 1, $$Serbest nazım; ölçü ve uyak zorunlulukları olmayan; ancak ritim, imge ve anlam kaygısıyla biçimlenen modern şiir anlayışıdır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Tanzimat Edebiyatı ve Yenilik' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Divan edebiyatının klasik biçimleri","19. yüzyılda Batılılaşma sürecinde Osmanlı edebiyatının geçirdiği köklü dönüşüm ve Tanzimat dönemi yazarlarının rolü","Cumhuriyet döneminde edebiyatın gelişimi","Halk edebiyatının temel özellikleri"]$json$::jsonb, 1, $$Metin; Şinasi, Namık Kemal, Ziya Paşa gibi yazarların roman, gazete ve tiyatroyu edebiyata taşımasını ve Batı etkisinin Osmanlı edebi geleneğini nasıl dönüştürdüğünü ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Tanzimat Edebiyatı ve Yenilik' LIMIT 1), 'detail', $$Tanzimat edebiyatının Divan edebiyatından en köklü ayrımı nedir?$$, $json$["Aynı aruz ölçüsünü kullanmaları","Toplumsal sorunları, bireysel özgürlüğü ve Batılı türleri (roman, tiyatro, gazete makalesi) edebiyata dahil ederek sanatın kapsamını genişletmeleri","Hem Batılı hem Doğulu temalar yerine yalnızca Doğulu temaları işlemeleri","Yalnızca dini içerikli eserler vermeleri"]$json$::jsonb, 1, $$Tanzimat yazarları; sosyal eleştiri, vatan-millet-hürriyet temaları ve Batı''dan alınan roman/tiyatro gibi yeni edebi türlerle divan geleneğinden köklü biçimde ayrışmışlardır.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Tanzimat Edebiyatı ve Yenilik' LIMIT 1), 'detail', $$Namık Kemal''in "Vatan yahut Silistre" oyununun dönemin siyasi ortamındaki önemi nedir?$$, $json$["Yalnızca estetik değeri için sahnelenmiştir","Vatan, özgürlük ve fedakârlık temalarını işleyerek geniş halk kitlelerini derinden etkileyen ve otoriteler tarafından tehlikeli bulunan siyasi bir eser olması","Osmanlı klasik tiyatrosunun özelliklerini taşıması","Tanzimat döneminin ilk Batı tarzı oyunu olması"]$json$::jsonb, 1, $$Oyun; sahnelenmesiyle kalabalıkları sokağa dökmüş, kitlesel milliyetçi duyguyu harekete geçirmiş ve Namık Kemal''in sürgüne gönderilmesine neden olmuştur.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Tanzimat Edebiyatı ve Yenilik' LIMIT 1), 'inference', $$Tanzimat yazarlarının gazeteciliğe ağırlık vermesinin en önemli toplumsal sonucu ne olmuştur?$$, $json$["Edebiyatın yalnızca saray çevresiyle sınırlı kalması","Kamuoyunun oluşması, fikirlerin hızla yayılması ve yeni bir okuyucu kitlesinin doğması","Gazeteler Osmanlı siyasetini hiç etkilememiştir","Yalnızca Fransızca gazete basılmıştır"]$json$::jsonb, 1, $$Gazete; Osmanlı''da kamusal tartışma alanı ve modern fikir yayma aracı olarak hem edebiyatın kitleselleşmesini hem de siyasal bilincin oluşmasını sağlamıştır.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Tanzimat Edebiyatı ve Yenilik' LIMIT 1), 'vocabulary', $$Metinde geçen "Batılılaşma" kavramı Tanzimat edebiyatı bağlamında ne anlama gelir?$$, $json$["Osmanlı kimliğinin tamamen terk edilmesi","Edebi türler, anlatı biçimleri ve düşünce sistemleri açısından Batı Avrupa''nın entelektüel birikiminden beslenerek Osmanlı edebiyatını yenileme çabası","Yalnızca teknik modernleşme","Batı dillerinde eser verme tercih"]$json$::jsonb, 1, $$Tanzimat bağlamında Batılılaşma; salt bir öykünme değil, Batı''nın roman, tiyatro, eleştiri gibi türlerini ve özgürlük, akılcılık gibi değerlerini Osmanlı bağlamına uyarlama çabasıdır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Türk Edebiyatında Modernizm' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Halk edebiyatı geleneğinin özellikleri","Türk edebiyatında modernist akımın öncüleri, teknikleri ve temaları","Osmanlı döneminde roman türünün ilk örnekleri","Cumhuriyet sonrası tarihsel roman türü"]$json$::jsonb, 1, $$Metin; bilinç akışı, iç monolog, parçalanmış anlatı gibi modernist tekniklerin Türk romancılar tarafından nasıl benimsendiğini ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Türk Edebiyatında Modernizm' LIMIT 1), 'detail', $$"Bilinç akışı" anlatı tekniği modernist romanda hangi işlevi yerine getirir?$$, $json$["Olayları kronolojik sırayla aktarır","Karakterin içindeki düşünce, his ve çağrışımların kesiksiz ve denetlenmemiş biçimde aktarılmasını sağlar","Sosyal gerçekliği nesnel bir bakışla betimler","Karakterler arasındaki diyaloğu zenginleştirir"]$json$::jsonb, 1, $$Bilinç akışı (stream of consciousness); psikolojik gerçekliği doğrusal olmayan, özgürce çağrışım yapan bir anlatı akışıyla aktararak karakterin iç dünyasını derinleştiren bir tekniktir.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Türk Edebiyatında Modernizm' LIMIT 1), 'detail', $$Türk modernizminin Batı modernizminden ayırt edici özelliği nedir?$$, $json$["Türk modernizmi Batı modernizmini birebir kopyalamıştır","Türk modernizmi; Batılı biçim ve teknikleri yerel tarih, kimlik ve toplumsal dönüşüm kaygılarıyla harmanlayarak özgün bir sentez oluşturmuştur","Türk modernizmi Batı''dan tamamen bağımsız gelişmiştir","Türk modernizmi yalnızca şiirde kendini göstermiştir"]$json$::jsonb, 1, $$Türk modernist yazarları; Batılı teknik ve anlayışları Cumhuriyet kimliği, geleneksel değerlerle çatışma ve kentleşme gibi özgün yerel sorunlarla buluşturmuştur.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Türk Edebiyatında Modernizm' LIMIT 1), 'inference', $$Modernist Türk edebiyatının "parçalanmış anlatı" ve "güvenilmez anlatıcı" gibi biçimsel tercihleri ne tür bir dünya görüşünü yansıtmaktadır?$$, $json$["Dünyanın düzenli ve anlaşılır olduğuna dair iyimser bir inancı","Gerçekliğin öznel, çoğul ve belirsiz olduğuna; bilgi ve kimliğin istikrarsız yapısına ilişkin modernist bir şüpheciliği","Tarihsel ilerlemeye kayıtsız şartsız inanan pozitivist bir anlayışı","Toplumcu gerçekçiliğe bağlılığı"]$json$::jsonb, 1, $$Modernizm; salt gerçeklik yansıtma yerine öznel deneyimi ve bilincin karmaşıklığını ön plana çıkararak anlatı biçimlerini parçalar; bu, sarsılmış bir dünya görüşünün yansımasıdır.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Türk Edebiyatında Modernizm' LIMIT 1), 'vocabulary', $$Metinde geçen "güvenilmez anlatıcı" kavramı ne anlama gelir?$$, $json$["Yazar gerçek bilgiyi okuyucudan gizler","Okuyucunun aktarılanın doğruluğunu sorgulamasına yol açan; önyargılı, sınırlı ya da yanıltıcı bir bakış açısına sahip olan anlatıcı tipi","Her romanda zorunlu olarak bulunan bir anlatıcı türü","Üçüncü şahıs anlatıcının bir alt türü"]$json$::jsonb, 1, $$Güvenilmez anlatıcı; söylediklerinin gerçeği yansıtıp yansıtmadığı okuyucu tarafından sorgulanabilen, metni aktif yoruma açan bir modernist anlatı tekniğidir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Dalga Hareketi ve Ses Fiziği' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Elektrik akımının özellikleri","Dalga hareketiyle ses enerjisinin iletimi ve ses fiziğinin temel kavramları","Işığın kırılma ve yansıma yasaları","Maddenin katı, sıvı ve gaz hâlleri"]$json$::jsonb, 1, $$Metin; dalga boyu, frekans, genlik, ses hızı ve Doppler etkisi gibi kavramları ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Dalga Hareketi ve Ses Fiziği' LIMIT 1), 'detail', $$Ses dalgasının yayılabilmesi için neye ihtiyacı vardır?$$, $json$["Işığa","Manyetik alana","Maddesel ortama (katı, sıvı veya gaz)","Elektrik alanına"]$json$::jsonb, 2, $$Ses; mekanik titreşim dalgasıdır ve yayılmak için taneciklerin birbirini itip çekebileceği maddesel bir ortam gerektirir; bu nedenle boşlukta iletilmez.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Dalga Hareketi ve Ses Fiziği' LIMIT 1), 'detail', $$Doppler etkisi neyi açıklar?$$, $json$["Sesin boşlukta da iletilmesini","Ses ya da ışık kaynağı ile gözlemci arasındaki göreli hareket nedeniyle algılanan frekansın gerçek frekansdan farklılaşmasını","Sesin yansıma açısını","Ses dalgalarının girişim yapmasını"]$json$::jsonb, 1, $$Kaynak yaklaşırken algılanan frekans artar (tiz), uzaklaşırken azalır (pes); bu Doppler etkisi ambulans sireni örneğinde günlük hayatta gözlemlenebilir.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Dalga Hareketi ve Ses Fiziği' LIMIT 1), 'inference', $$Ses hızının katılarda sıvılardan, sıvılarda ise gazlardan daha yüksek olmasının nedeni nedir?$$, $json$["Katılarda daha fazla hava boşluğu bulunur","Katılardaki yüksek elastiklik modülü, parçacıkların titreşimini ve enerji iletimini çok daha hızlı gerçekleştirir","Katılarda ışık dalgaları sesle birlikte ilerler","Sıcaklık katılarda sesi yavaşlatır"]$json$::jsonb, 1, $$Ses hızı; ortamın yoğunluğu ve elastikliğiyle belirlenir. Katılarda atomlar arası bağlar çok güçlü olduğundan titreşim çok daha hızlı iletilir.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Dalga Hareketi ve Ses Fiziği' LIMIT 1), 'vocabulary', $$Metinde geçen "rezonans (ortak titreşim)" ne anlama gelir?$$, $json$["Dalganın bir engelden yansıması","Bir sistemin dışarıdan uygulanan kuvvetin frekansı doğal frekansıyla örtüştüğünde en yüksek genlikle titreşmesi","Sesin iki ortam arasında kırılması","Dalgaların birbirini güçlendirerek yayılması"]$json$::jsonb, 1, $$Rezonans; dış uyarı frekansı sistemin doğal frekansıyla çakıştığında enerji transferinin maksimuma ulaşmasıdır; köprü çöküşleri ve müzik aletlerinde bu etkiyle karşılaşılır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Evrenin Yapısı ve Kozmoloji' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Güneş Sistemi''ndeki gezegenlerin özellikleri","Evrenin kökeni, yapısı ve genişlemesini inceleyen kozmoloji biliminin temel kavramları","Kara deliklerin oluşumu","Nükleer füzyon süreçleri"]$json$::jsonb, 1, $$Metin; Büyük Patlama, kozmik arka plan radyasyonu, karanlık madde ve karanlık enerji gibi kozmolojinin temel kavramlarını ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Evrenin Yapısı ve Kozmoloji' LIMIT 1), 'detail', $$Evrenin genişlediğini gösteren en önemli gözlemsel kanıt nedir?$$, $json$["Güneş''in konumunun yıllık değişimi","Uzak galaksilerin ışığındaki kırmızıya kayma (redshift), yani galaksilerin bizden uzaklaşmasının göstergesi","Güneş sistemindeki gezegen sayısı","Kozmik arka plan radyasyonunun homojen dağılımı"]$json$::jsonb, 1, $$Hubble''ın bulduğu galaktik kırmızıya kayma; uzak galaksilerin bizden uzaklaştığını ve evrenin genişlediğini gösteren temel gözlemsel kanıttır.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Evrenin Yapısı ve Kozmoloji' LIMIT 1), 'detail', $$"Karanlık madde" hangi kanıtlara dayanarak öne sürülmüştür?$$, $json$["Doğrudan teleskopla gözlemlenmiştir","Galaksilerin beklenen dönme hızından çok daha hızlı dönmesi ve gözlenemeyen ek kütlenin varlığını gerektirmesi","Kozmik arka plan radyasyonundaki sıcaklık dalgalanmaları","Büyük Patlama sırasında üretilen ışık miktarı"]$json$::jsonb, 1, $$Galaksilerin dış bölgeleri, görünür kütleyle açıklanamayacak hızda döndüğünden "görünmez" ama kütleçekim etkisi gösteren karanlık madde modeli önerilmiştir.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Evrenin Yapısı ve Kozmoloji' LIMIT 1), 'inference', $$Büyük Patlama''nın bir "patlama" olmadığının en iyi açıklaması nedir?$$, $json$["Büyük Patlama gerçekten bir patlama olmuştur","Büyük Patlama; var olan boşlukta oluşan bir patlama değil, uzayın-zamanın kendisinin hızla genişlemesi olayıdır; bu nedenle bir merkezi yoktur","Büyük Patlama yalnızca güneş sistemini etkileyen bir olaydır","Büyük Patlama bugün hâlâ devam etmektedir"]$json$::jsonb, 1, $$Büyük Patlama; uzay-zamanın kendisinin genişlemesi olduğundan bir "patlama merkezi" yoktur ve her gözlemciye evrenin kendisinden uzaklaşıyormuş gibi görünür.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Evrenin Yapısı ve Kozmoloji' LIMIT 1), 'vocabulary', $$Metinde geçen "kozmik arka plan radyasyonu" ne anlama gelir?$$, $json$["Yıldızların yaydığı görünür ışık","Büyük Patlama''nın kalıntısı olarak evrenin her yönünden gelen mikrodalga ışıması; evrenin ilk ışık salımının soğumuş biçimi","Kara deliklerin X-ışını emisyonu","Güneş rüzgarının elektromanyetik bileşeni"]$json$::jsonb, 1, $$CMB; Büyük Patlama''dan yaklaşık 380.000 yıl sonra evreni dolduran fotonların soğuyarak mikrodalgaya dönüşmüş hâlidir ve evrenin en erken görüntüsünü sunar.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Termodinamiğin Yasaları' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Kimyasal reaksiyonlarda atom korunumu","Isı, iş ve enerji arasındaki ilişkileri düzenleyen termodinamiğin temel yasaları","Dalga hareketi ve ses fiziği","Newton''un hareket yasaları"]$json$::jsonb, 1, $$Metin; termodinamiğin dört yasasını, enerji korunumunu, entropi kavramını ve mühendislik uygulamalarını ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Termodinamiğin Yasaları' LIMIT 1), 'detail', $$Termodinamiğin birinci yasası hangi ilkeyi ifade eder?$$, $json$["Entropi kapalı sistemlerde daima artar","Enerji yaratılamaz ve yok edilemez; yalnızca bir biçimden diğerine dönüşür","Isı akışı yalnızca sıcak cisimlerde gerçekleşir","Mutlak sıfırda tüm moleküler hareket durur"]$json$::jsonb, 1, $$Birinci yasa (enerji korunumu); ısı, iş ve iç enerji değişimini ΔU = Q - W bağıntısıyla ilişkilendiren temel termodinamik ilkedir.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Termodinamiğin Yasaları' LIMIT 1), 'detail', $$Termodinamiğin ikinci yasasının pratik anlamı nedir?$$, $json$["Her sistemde enerji yüzde yüz verimle dönüştürülebilir","Doğal süreçler düzenden karışıklığa (yüksek entropiye) doğru ilerler; mükemmel verimli bir ısı makinesi yapmak olanaksızdır","Isı her iki yönde eşit biçimde akar","Mutlak sıfır sıcaklığa ulaşmak mümkündür"]$json$::jsonb, 1, $$İkinci yasa; spontan süreçlerin daima entropi artışı yönünde gerçekleştiğini ve ısıl makinelerin Carnot verimine hiçbir zaman ulaşamayacağını öngörür.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Termodinamiğin Yasaları' LIMIT 1), 'inference', $$Entropi kavramının "düzensizlik ölçüsü" olarak tanımlanması neyin ifadesidir?$$, $json$["Enerjinin kaybolduğunu","Mikro hâllerin sayısının artmasıyla sistemin olasılıklı düzensiz hâllere doğru yöneldiğini; düzenin korunmasının enerji gerektirdiğini","Termodinamiğin yalnızca mühendislikte geçerli olduğunu","Her sistemin zamanla düzenleneceğini"]$json$::jsonb, 1, $$İstatistiksel mekanikte entropi; sistemin mümkün olan mikro hâl sayısıyla ilişkilidir. Düzensiz hâller çok daha fazla olasılıklı olduğundan sistemler doğal olarak onlara doğru evrilir.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Termodinamiğin Yasaları' LIMIT 1), 'vocabulary', $$Metinde geçen "Carnot çevrimi" ne anlama gelir?$$, $json$["Gerçek bir buhar makinesi tasarımı","İki ısıl rezervuar arasında çalışan teorik olarak mümkün en verimli (maksimum verimli) ters çevrilebilir ısı makinesi çevrimi","Enerji korunumunun matematiksel ifadesi","Mutlak sıfırın tanımlandığı termodinamik süreç"]$json$::jsonb, 1, $$Carnot çevrimi; iki sıcaklık düzeyi arasında çalışan ve termodinamiğin ikinci yasasına göre ulaşılabilecek teorik maksimum verimi tanımlayan ideal ısı makinesi modelidir.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Atom Modelleri ve Kuantum Teorisi' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Periyodik tablonun tarihsel gelişimi","Dalton''dan kuantum modeline uzanan atom anlayışının evrimi ve modern atom kuramının temelleri","Kimyasal bağ türleri","İyon ve moleküllerin tanımı"]$json$::jsonb, 1, $$Metin; Dalton, Thomson, Rutherford, Bohr ve kuantum mekaniksel atom modellerini karşılaştırarak modern atom anlayışını ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Atom Modelleri ve Kuantum Teorisi' LIMIT 1), 'detail', $$Rutherford''un altın levha deneyi hangi sonucu ortaya koymuştur?$$, $json$["Atomun bölünemeyeceğini","Atomun büyük çoğunluğunun boş alan olduğunu ve pozitif yüklü küçük bir çekirdeğin varlığını","Elektronların çekirdeğe gömülü olduğunu","Atomda yalnızca elektron ve proton bulunduğunu"]$json$::jsonb, 1, $$Rutherford; alfa parçacıklarının büyük kısmının altın levhayı geçtiğini, küçük bir kısmının ise saptığını gözlemleyerek küçük, yoğun, pozitif yüklü bir çekirdeğin varlığını kanıtlamıştır.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Atom Modelleri ve Kuantum Teorisi' LIMIT 1), 'detail', $$Bohr modelinin Rutherford modelini geliştiren en önemli katkısı nedir?$$, $json$["Elektronların çekirdek içinde bulunduğunu göstermek","Elektronların belirli enerji düzeylerinde (yörüngelerde) hareket ettiğini ve ancak bu düzeyler arasında geçişlerde enerji absorpladığını ya da yaydığını tanımlamak","Çekirdeğin bileşimini açıklamak","Nötronun varlığını ilk kez öngörmek"]$json$::jsonb, 1, $$Bohr; elektron yörüngelerini kuantize ederek atomun neden belirli dalga boylarında ışık yaydığını açıklamış ve hidrojenin emisyon spektrumunu başarıyla modellemiştir.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Atom Modelleri ve Kuantum Teorisi' LIMIT 1), 'inference', $$Kuantum mekaniksel atom modelinin "orbital" kavramını kullanmasının nedeni nedir?$$, $json$["Elektronu belirli bir yörüngede konumlandırmak için","Elektronun tam konumunun belirlenemeyeceğini (Heisenberg belirsizlik ilkesi) kabul ederek elektronun bulunma olasılığının yoğun olduğu uzay bölgelerini tanımlamak için","Rutherford modelini aynen sürdürmek için","Elektronun kütlesini hesaplamak için"]$json$::jsonb, 1, $$Orbital; elektronun kesin konumu değil, belirli bir olasılıkla bulunabileceği bölgeyi tanımlar; bu, belirsizlik ilkesinin atomik modele uygulanmasının zorunlu sonucudur.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Atom Modelleri ve Kuantum Teorisi' LIMIT 1), 'vocabulary', $$Metinde geçen "kuantum sayıları" ne anlama gelir?$$, $json$["Atoma ait proton ve nötron sayıları","Bir elektronu üç boyutlu uzaydaki konumu, enerji düzeyi, şekli ve spini bakımından tam olarak tanımlayan dört tam sayı kümesi","Periyodik tablodaki atom numarası","Bir elementin değerlik elektron sayısı"]$json$::jsonb, 1, $$Dört kuantum sayısı (n, l, mₗ, ms); Pauli dışarlama ilkesi gereği her elektronu atomda benzersiz biçimde tanımlar ve orbital yapısını belirler.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Kimyasal Tepkimeler ve Denge' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Asit-baz kavramları","Kimyasal tepkimelerin nasıl gerçekleştiği, denge kavramı ve Le Chatelier ilkesi","Periyodik tablonun düzenlenmesi","Elektrokimyasal pil tasarımı"]$json$::jsonb, 1, $$Metin; tepkime hızını etkileyen faktörleri, denge sabiti kavramını ve Le Chatelier ilkesiyle dengenin nasıl yönlendirilebildiğini ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Kimyasal Tepkimeler ve Denge' LIMIT 1), 'detail', $$Kimyasal denge ne zaman gerçekleşir?$$, $json$["Tepkime tamamen sona erdiğinde","İleri ve geri tepkime hızları eşitlendiğinde, madde konsantrasyonları sabit kaldığında","Tüm reaktifler ürüne dönüştüğünde","Sıcaklık sabit kaldığında"]$json$::jsonb, 1, $$Dinamik kimyasal denge; ileri ve geri tepkimeler devam ederken net değişimin sıfır olduğu; yani konsantrasyonların sabit kaldığı durumdur.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Kimyasal Tepkimeler ve Denge' LIMIT 1), 'detail', $$Le Chatelier ilkesi neyi öngörür?$$, $json$["Denge sabiti her koşulda aynı kalır","Dengedeki sisteme dış bir etki uygulandığında sistem bu etkiyi azaltacak yönde yeni dengeye ulaşır","Sıcaklık artışı her zaman ileri tepkimeyi hızlandırır","Katalizör dengeyi ileri tepkime yönünde kaydırır"]$json$::jsonb, 1, $$Le Chatelier; konsantrasyon, basınç ya da sıcaklık değişimine maruz kalan bir sistemin baskıyı hafifletecek yönde denge konumunu kaydıracağını öngörür.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Kimyasal Tepkimeler ve Denge' LIMIT 1), 'inference', $$Sanayi ölçeğinde amonyak üretiminde (Haber-Bosch süreci) yüksek basınç kullanılmasının nedeni nedir?$$, $json$["Enerji maliyetini artırmak","N₂ + 3H₂ ⇌ 2NH₃ tepkimesinde mol sayısı azaldığından Le Chatelier ilkesi gereği yüksek basınç dengeyi ürün (NH₃) yönüne kaydırır","Katalizörün etkinliğini artırmak","Azot gazını sıvılaştırmak"]$json$::jsonb, 1, $$Yüksek basınç; toplam mol sayısını düşüren taraf (ürünler, 2 mol) lehine dengeyi kaydırır ve NH₃ verimi artırır.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Kimyasal Tepkimeler ve Denge' LIMIT 1), 'vocabulary', $$Metinde geçen "denge sabiti (Keq)" ne anlama gelir?$$, $json$["Tepkimenin tamamlanma süresi","Belirli sıcaklıkta dengedeki ürün ve reaktif konsantrasyonlarının oranını ifade eden ve yalnızca sıcaklığa bağlı olan sabit","Katalizörün derişimini","Tepkimedeki toplam enerji değişimi"]$json$::jsonb, 1, $$Keq; denge durumunda ürün konsantrasyonlarının kuvvetlerle çarpımının reaktif konsantrasyonlarının kuvvetlerine bölümüdür ve sıcaklık dışındaki koşullardan bağımsızdır.$$, 3, 5);
INSERT INTO text_questions (text_id, question_type, question_text, options, correct_index, explanation, difficulty, order_index) VALUES
((SELECT id FROM text_library WHERE title = 'Organik Kimya Temelleri' LIMIT 1), 'main_idea', $$Bu metnin temel konusu nedir?$$, $json$["Asit-baz teorileri","Organik kimyanın temel kavramları: karbon kimyası, fonksiyonel gruplar ve organik bileşik sınıfları","Metal ve alaşımların özellikleri","İyon bağı ve iyonik bileşikler"]$json$::jsonb, 1, $$Metin; karbon atomunun eşsiz bağ kapasitesini, hidrokarbonları, fonksiyonel grupları ve organik reaksiyon türlerini ele almaktadır.$$, 3, 1),
((SELECT id FROM text_library WHERE title = 'Organik Kimya Temelleri' LIMIT 1), 'detail', $$Karbon atomunun organik kimyanın temeli olmasının nedeni nedir?$$, $json$["En hafif element olması","4 değerlikli yapısı sayesinde hem kendi kendine hem de diğer elementlerle güçlü ve çeşitli bağlar kurarak milyonlarca farklı bileşik oluşturabilmesi","En bol bulunan element olması","Yalnızca hidrojenle bağ kurabilmesi"]$json$::jsonb, 1, $$Karbon; kovalent bağ kurma kapasitesi, zincir ve halka yapıları oluşturabilmesi sayesinde organik bileşiklerin sonsuz çeşitliliğinin kaynağıdır.$$, 3, 2),
((SELECT id FROM text_library WHERE title = 'Organik Kimya Temelleri' LIMIT 1), 'detail', $$Alkol ve karboksilli asitler arasındaki yapısal fark nedir?$$, $json$["İkisi de aynı fonksiyonel grubu taşır","Alkoller -OH (hidroksil) grubunu; karboksilli asitler -COOH (karboksil) grubunu taşır","Alkoller zincir, asitler halka yapı kurar","Her ikisi de yalnızca karbon ve hidrojenden oluşur"]$json$::jsonb, 1, $$Alkoller; -OH grubu içerirken karboksilli asitler hem -C=O hem -OH içeren -COOH grubunu taşır; bu fark asidik özellik ve reaksiyon davranışlarını belirler.$$, 3, 3),
((SELECT id FROM text_library WHERE title = 'Organik Kimya Temelleri' LIMIT 1), 'inference', $$İzomer kavramının organik kimyada önemi neden büyüktür?$$, $json$["İzomerler birbirinin aynısı maddelerdir","Aynı moleküler formüle sahip ama farklı yapısal düzenlemelerle tamamen farklı fiziksel ve kimyasal özelliklere sahip bileşikler olmaları, ilaç tasarımından madde özelliklerine kadar kritik pratik sonuçlar doğurur","İzomerlerin birbirinden ayırt edilmesi mümkün değildir","İzomerlerin yalnızca teorik önemi vardır"]$json$::jsonb, 1, $$İzomerlerin farklı özellikleri; bir ilacın bir yapısının tedavi edici diğerinin toksik olabileceği farmakoloji gibi alanlarda organik yapı-özellik ilişkisini kritik kılar.$$, 3, 4),
((SELECT id FROM text_library WHERE title = 'Organik Kimya Temelleri' LIMIT 1), 'vocabulary', $$Metinde geçen "fonksiyonel grup" ne anlama gelir?$$, $json$["Karbonun dört bağından biri","Bir organik molekülde kimyasal reaksiyonların gerçekleştiği ve bileşiğin özelliklerini büyük ölçüde belirleyen özgül atom ya da atom grubu","Aromatik halkayı oluşturan karbon dizisi","Bir bileşiğin formülündeki hidrojen sayısı"]$json$::jsonb, 1, $$Fonksiyonel gruplar (-OH, -COOH, -NH₂, C=O vb.); organik moleküllerin reaktif merkezleridir ve bağlı oldukları bileşiğin kimyasal davranışını, asitliğini ve fiziksel özelliklerini belirler.$$, 3, 5);
